-- Poems batch 80
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b3b5473e-27fc-41c7-a00f-1bb829d859e6','禪人并化主寫真求贊  其三四○','釋正覺','宋','宋诗','song-poetry','','[]','煙蒼蒼兮白鳥飛，水茫茫兮金鱗嬉。',110,'全唐诗/poet.song.102000.json','["煙蒼蒼兮白鳥飛，水茫茫兮金鱗嬉。", "空杳杳兮智不知，覺冥冥兮性所宜。", "包萬像而括二儀，徹三際而周四維。", "影象纍纍，品類差差。", "發揮元自我，點化更由誰。", "方之則矩，圓之則規。", "不須特地，且麽過時。", "兀兀騰騰，憨憨癡癡，跛跛挈挈而萎萎羸羸。"]'),
('e06a96c5-b695-4781-8f52-1e3c31e29d3c','禪人并化主寫真求贊  其三四一','釋正覺','宋','宋诗','song-poetry','','[]','說通齒豁，宗通句活。',48,'全唐诗/poet.song.102000.json','["說通齒豁，宗通句活。", "師座心空，劫壺步闊。", "就位了無機，爛柯曾有著。", "招手相隨恁麽來，百草頭邊活卓卓。"]'),
('7f3ad3bc-d646-447d-8d18-46c002aaa900','禪人并化主寫真求贊  其三四二','釋正覺','宋','宋诗','song-poetry','','[]','性了有餘，體含太虛。',48,'全唐诗/poet.song.102000.json','["性了有餘，體含太虛。", "心空歷歷，道契如如。", "答響神居谷，隨緣井覷驢。", "向道塵塵住三昧，何妨觸處卷而舒。"]'),
('b14fca7d-0bf5-4b33-96e6-543debfa32c2','禪人并化主寫真求贊  其三四三','釋正覺','宋','宋诗','song-poetry','','[]','形容老癯，鬚髮雪敷。',54,'全唐诗/poet.song.102000.json','["形容老癯，鬚髮雪敷。", "體明千劫眼，性靜萬機樞。", "變通自古門門活，伎倆而今恰恰無。", "一指頭禪隨處用，拈來百草俱胝俱。"]'),
('23bf56ec-c856-4697-bdc9-92ef706cc91f','禪人并化主寫真求贊  其三四四','釋正覺','宋','宋诗','song-poetry','','[]','一印印空，三乘莫窮。',48,'全唐诗/poet.song.102000.json','["一印印空，三乘莫窮。", "智了離微句，身分函蓋同。", "彌勒駕來樓閣外，文殊家住覺城東。", "隨身干木，到處家風。"]'),
('3fe42f88-b7cf-4c77-bdce-0254de2b1eb2','禪人并化主寫真求贊  其三四五','釋正覺','宋','宋诗','song-poetry','','[]','拄杖倚床，默而成章。',50,'全唐诗/poet.song.102000.json','["拄杖倚床，默而成章。", "夜月通犀角，秋空沒雁行。", "清寫芭蕉雪，秀盛芙蓉霜。", "青原價問廬陵米，會有知音句廝當。"]'),
('188895f2-5f91-4a39-8cba-1ba234a7a945','禪人并化主寫真求贊  其三四六','釋正覺','宋','宋诗','song-poetry','','[]','默學少林，靜全本心。',46,'全唐诗/poet.song.102000.json','["默學少林，靜全本心。", "幽靈絕待，虛明自任。", "玉線金鍼世家事，鸞膠鳳絃山水音。", "隨方善應，不用相尋。"]'),
('faea79fb-da27-4a64-95b5-d7443f228623','禪人并化主寫真求贊  其三四七','釋正覺','宋','宋诗','song-poetry','','[]','其離而入，其微而出。',26,'全唐诗/poet.song.102000.json','["其離而入，其微而出。", "一彈指響樓閣開，身現門門千百億。"]'),
('4cc78b15-c95d-4ed6-aa60-014a1dae55f9','禪人并化主寫真求贊  其三四八','釋正覺','宋','宋诗','song-poetry','','[]','絕待而靈，無得而名。',48,'全唐诗/poet.song.102000.json','["絕待而靈，無得而名。", "就位難辨，借功證成。", "合伴應時節，隨事放光明。", "神歌社舞閑心適，塊雨條風樂太平。"]'),
('2756357d-d788-4c19-b5f4-39e4d0c7b542','禪人并化主寫真求贊  其三四九','釋正覺','宋','宋诗','song-poetry','','[]','理極非身，智明自神。',46,'全唐诗/poet.song.102000.json','["理極非身，智明自神。", "三緣未作，一默含純。", "回途異類，出歷諸塵。", "彎彎月下漣漪水，剪剪風斜楊柳春。"]'),
('5c946faf-3bbc-4677-b879-74ebfd28884f','禪人并化主寫真求贊  其三五○','釋正覺','宋','宋诗','song-poetry','','[]','野鶴骨癯，澗松皮粗。',70,'全唐诗/poet.song.102000.json','["野鶴骨癯，澗松皮粗。", "一身閑而雲行林壑，兩眼冷而秋入江湖。", "智到無而有，理極有而無。", "齊物蝶翻晝夢，隨機蜂理華鬚。", "開口也著合也著，風鈴發響谷隨呼。"]'),
('43feb487-bf9f-42a9-8c26-8fceff5f157a','禪人并化主寫真求贊  其三五一','釋正覺','宋','宋诗','song-poetry','','[]','爲僧𠜾剞，與世支離。',60,'全唐诗/poet.song.102000.json','["爲僧𠜾剞，與世支離。", "目瞳青炯炯，頭髮白絲絲。", "劫空有句，真得無師。", "借功分照用，借位解提持。", "萬像森羅一音說，何須特地挂唇皮。"]'),
('f9baab27-e2b5-4878-8aa8-d7816c73d0d9','禪人并化主寫真求贊  其三五二','釋正覺','宋','宋诗','song-poetry','','[]','妙存象先，圓成自然。',58,'全唐诗/poet.song.102000.json','["妙存象先，圓成自然。", "佛燈燄續，祖華芳聯。", "野況煙霞老，秋痕天水連。", "生無生性，住無住緣。", "隨分雪分齋一鉢，不嫌雲寄屋三椽。"]'),
('84f73648-8604-47ef-99fd-2adadd03ff1e','禪人并化主寫真求贊  其三五三','釋正覺','宋','宋诗','song-poetry','','[]','明白無根，茫茫月魂。',62,'全唐诗/poet.song.102000.json','["明白無根，茫茫月魂。", "清虛不渾，蒼蒼秋痕。", "青天固可背負，諸佛等閑口吞。", "情空超物物，妙觸應門門。", "了知初不由心念，金色頭陀滅意根。"]'),
('91498a36-d984-480a-98e8-061fa6c0572f','禪人并化主寫真求贊  其三五四','釋正覺','宋','宋诗','song-poetry','','[]','眸子射人，秋澗之津。',72,'全唐诗/poet.song.102000.json','["眸子射人，秋澗之津。", "顛毛衰白，霜松之晨。", "赤湖之林，潮漲而長鯨𩥇浪。", "丹桂之影，月寒而老兔推輪。", "明功借位，起幻入塵。", "百草頭邊有芳信，縱橫指點自家春。"]'),
('e930dbd0-6126-4bda-a895-f7c43a336fea','禪人并化主寫真求贊  其三五五','釋正覺','宋','宋诗','song-poetry','','[]','無心之心，妙超古今。',46,'全唐诗/poet.song.102000.json','["無心之心，妙超古今。", "無相之相，不存情量。", "葉落木而秋開，月度山而潮上。", "柳絮之風隨，葵華之日向。"]'),
('bdaab568-de0c-46d9-8095-2381fd0307f2','禪人并化主寫真求贊  其三五六','釋正覺','宋','宋诗','song-poetry','','[]','默而靜專，體之妙全。',48,'全唐诗/poet.song.102000.json','["默而靜專，體之妙全。", "情盡性傳，心空覺圓。", "閒閒遊幻世，了了應塵緣。", "燈籠露柱渾機用，翠竹黄華總說禪。"]'),
('7dc37994-c1e3-4668-8f6c-3d9ee392d165','禪人并化主寫真求贊  其三五七','釋正覺','宋','宋诗','song-poetry','','[]','塵浄無餘，體明而虛。',48,'全唐诗/poet.song.102000.json','["塵浄無餘，體明而虛。", "秋高夜永，河闊星疏。", "宛轉兼而到，偏圓卷復舒。", "媚川果若珠含蚌，應物何妨井覷驢。"]'),
('a6a2171b-9082-4d5f-8f41-032c1c333756','禪人并化主寫真求贊  其三五八','釋正覺','宋','宋诗','song-poetry','','[]','南臺之靜，中邑之應。',72,'全唐诗/poet.song.102000.json','["南臺之靜，中邑之應。", "圓明之知，平等之性。", "爛柯棋局樵，釣雪華亭艇。", "披叢林明白之襟，握雲水清凉之柄。", "動自風流，閒宜月定。", "心聞況是賞音，相廗何妨打令。"]'),
('9eb202e2-5f1e-4d4c-a0cc-bb3bfe62cd60','禪人并化主寫真求贊  其三五九','釋正覺','宋','宋诗','song-poetry','','[]','雲水孤藤，叢林老僧。',60,'全唐诗/poet.song.102000.json','["雲水孤藤，叢林老僧。", "瀾翻口角，雪點眉棱。", "長春時節相聯蕊，破夜光明自照燈。", "內無絲而繫螘，外無糝而聚蠅。", "不起滅定，能應繁興。"]'),
('8c58736f-e902-4401-8169-cee245aef892','禪人并化主寫真求贊  其三六○','釋正覺','宋','宋诗','song-poetry','','[]','雪髮霜鬚，鯢齒雞膚。',50,'全唐诗/poet.song.102000.json','["雪髮霜鬚，鯢齒雞膚。", "年侵蒲柳，日在桑榆。", "用持智之大柄，靜守道之元樞。", "而今百草頭邊用，妙得雲門一字俱。"]'),
('dca5af14-f0b6-4853-9333-bf746d8b1fb4','禪人并化主寫真求贊  其三六一','釋正覺','宋','宋诗','song-poetry','','[]','曹洞宗乘，老難發興。',74,'全唐诗/poet.song.102000.json','["曹洞宗乘，老難發興。", "秋波摇眼角，春雪點眉稜。", "一步跨空劫，孤心相續燈。", "西母之桃兮秀結三千年實，北冥之鯤兮蛻翔九萬里鵬。", "珊瑚枝枝撐著月，出格雲門跛脚僧。"]'),
('b41a1bbd-1cf8-4dc6-8fb3-da9ca3e22060','禪人并化主寫真求贊  其三六二','釋正覺','宋','宋诗','song-poetry','','[]','心心絕緣，了了亡年。',50,'全唐诗/poet.song.102000.json','["心心絕緣，了了亡年。", "吞佛空三世，披經等大千。", "妙觀智出礙，韶晝春無邊。", "齊物竹床蝴蝶夢，雙飛栩栩華風顛。"]'),
('fd06e03c-af50-47d3-a741-b26a11812212','禪人并化主寫真求贊  其三六三','釋正覺','宋','宋诗','song-poetry','','[]','妙而不有，空而不無。',50,'全唐诗/poet.song.102000.json','["妙而不有，空而不無。", "坐寒床下板，步轉劫前壺。", "返色光初發，知音德不孤。", "流長信是盈科水，盤走端如受影珠。"]'),
('b17fe58c-87be-4c92-845b-6e3e6e2fa66f','禪人并化主寫真求贊  其三六四','釋正覺','宋','宋诗','song-poetry','','[]','疏齒如鯢，皴皮若雞。',48,'全唐诗/poet.song.102000.json','["疏齒如鯢，皴皮若雞。", "萬機頓削，一句全提。", "湛存性海闊，圓明心月低。", "有信風雷還破蟄，無言桃李自成蹊。"]'),
('161149b2-49bc-4992-a3bf-d4efdaaf2799','禪人并化主寫真求贊  其三六五','釋正覺','宋','宋诗','song-poetry','','[]','有應之身，無位之人。',52,'全唐诗/poet.song.102000.json','["有應之身，無位之人。", "隨方而見，妙觸而神。", "山林森森春在木，江湖澹澹秋生津。", "語不投機不展事，雲門一路從來親。"]'),
('da0fe671-3cb1-4618-bd77-a49605831918','禪人并化主寫真求贊  其三六六','釋正覺','宋','宋诗','song-poetry','','[]','一切相空，其後之心。',56,'全唐诗/poet.song.102000.json','["一切相空，其後之心。", "一切心空，其後之相。", "幽谷雲生，寒潭月上。", "應因緣平定二儀，了幻化森羅萬像。", "恰恰不疑，如指諸掌。"]'),
('e80df946-98b8-449b-83ad-be56ed292b3f','禪人并化主寫真求贊  其三六七','釋正覺','宋','宋诗','song-poetry','','[]','清浄本然，和合因緣。',60,'全唐诗/poet.song.102000.json','["清浄本然，和合因緣。", "涅不緇而磨不磷，仰彌高而鉆彌堅。", "隨之無後，迎之無前，空空空處亡中邊。", "而今信手拈來用，頭尾相應正復偏。"]'),
('8e8e50d4-2c42-461a-bd84-6c6807b918af','禪人并化主寫真求贊  其三六八','釋正覺','宋','宋诗','song-poetry','','[]','身老而衰，根鈍且遲。',52,'全唐诗/poet.song.102000.json','["身老而衰，根鈍且遲。", "霽冷河闊，天空斗垂。", "圓明三隻目，受用兩莖眉。", "塵剎大千縱橫而妙觸，三尺丈六笑語而相隨。"]'),
('d8052165-8286-4bbd-9e9d-bde72ad159c5','禪人并化主寫真求贊  其三六九','釋正覺','宋','宋诗','song-poetry','','[]','坐忘是非，默見離微。',60,'全唐诗/poet.song.102000.json','["坐忘是非，默見離微。", "佛祖之陶冶，天地之範圍。", "髑髏眉底眼，空劫句中機。", "青原赭色麒麟步，藥嶠金毛師子威。", "相逢捉手，大道同歸。"]'),
('702f0298-264d-4bb4-a3f0-b99292003b19','禪人并化主寫真求贊  其三七○','釋正覺','宋','宋诗','song-poetry','','[]','空劫默遊，靈然破幽。',52,'全唐诗/poet.song.102000.json','["空劫默遊，靈然破幽。", "潮揚光燄珊瑚月，海縮波瀾翡翠秋。", "於世無求，隨緣自由。", "百千三昧門門事，潦倒俱胝一指頭。"]'),
('77e12b31-8031-4b2d-868a-0886e96c3187','禪人并化主寫真求贊  其三七一','釋正覺','宋','宋诗','song-poetry','','[]','說真不真，說似不似，拈轉舌頭提得鼻。',54,'全唐诗/poet.song.102000.json','["說真不真，說似不似，拈轉舌頭提得鼻。", "空劫家風，衲僧田地。", "心心與祖相傳，佛佛見他出世。", "一塵入正受，諸塵三昧起。"]'),
('162b58e5-c513-47ee-ac86-2178bf808171','禪人并化主寫真求贊  其三七二','釋正覺','宋','宋诗','song-poetry','','[]','形貌春寒，顛毛雪殘。',66,'全唐诗/poet.song.102000.json','["形貌春寒，顛毛雪殘。", "坐空生滅影，靜見離微端。", "珊瑚樹生玳瑁海，明月珠走琉璃盤。", "藏天下於天下兮一性自然平等，出世間於世間兮萬像誰敢相謾。"]'),
('6489e04f-5553-4f7b-ae04-439a1929c70b','禪人并化主寫真求贊  其三七三','釋正覺','宋','宋诗','song-poetry','','[]','天地含光，陰陽化章。',60,'全唐诗/poet.song.102000.json','["天地含光，陰陽化章。", "蔬腸清白，棗齒淡黄。", "叢林閒去就，雲水老行藏。", "百鍊之金柔兮繞指，九試之玉溫兮截肪。", "隨身干木，作戲逢場。"]'),
('23eee831-673d-4e48-938d-9795f0e09816','禪人并化主寫真求贊  其三七四','釋正覺','宋','宋诗','song-poetry','','[]','默默靈光，堆堆坐忘。',58,'全唐诗/poet.song.102000.json','["默默靈光，堆堆坐忘。", "衲僧事業，宗印文章。", "應物空三世，隨緣遍十方。", "分身不用相回互，到處誰能作覆藏。", "巍巍堂堂，煒煒煌煌。"]'),
('db81c128-12c3-45fe-852a-01fc8acdfcd4','禪人并化主寫真求贊  其三七五','釋正覺','宋','宋诗','song-poetry','','[]','雲水老身，叢林陳人。',50,'全唐诗/poet.song.102000.json','["雲水老身，叢林陳人。", "髮毛已雪，鼻氣猶春。", "平等應緣也心心佛佛，自然說法也剎剎塵塵。", "回途復妙，弄假像真。"]'),
('b72dcb38-f409-4de8-9012-c8013468f96e','禪人并化主寫真求贊  其三七六','釋正覺','宋','宋诗','song-poetry','','[]','山带雪而歲寒，水含月而夜闌。',52,'全唐诗/poet.song.102000.json','["山带雪而歲寒，水含月而夜闌。", "對機轉物，影草探竿。", "遊刃之牛解，爛柯之局殘。", "西風雨歛煙雲浄，北斗脚垂河漢乾。"]'),
('b7736586-525f-46e5-88aa-c3edd5410052','禪人并化主寫真求贊  其三七七','釋正覺','宋','宋诗','song-poetry','','[]','形雖老蒼，事不窮忙。',48,'全唐诗/poet.song.102000.json','["形雖老蒼，事不窮忙。", "味真嚼蠟，面冷刮霜。", "撒手行空劫，全身入帝鄉。", "回頭遊戲成三昧，春上百華蜂采香。"]'),
('ab33e11a-81e6-4319-a8f0-01d29ca2702b','禪人并化主寫真求贊  其三七八','釋正覺','宋','宋诗','song-poetry','','[]','曲木坐床，烏藤倚旁。',46,'全唐诗/poet.song.102000.json','["曲木坐床，烏藤倚旁。", "孤禪一句，三世十方。", "青燈含華夜耿耿，白鳥欲沒天蒼蒼。", "却來有應，出礙無當。"]'),
('9a508dc4-d74f-414b-91b8-b6a8c0423191','禪人并化主寫真求贊  其三七九','釋正覺','宋','宋诗','song-poetry','','[]','丘壑精神，雲水陳人。',64,'全唐诗/poet.song.102000.json','["丘壑精神，雲水陳人。", "心燈不夜，道樹長春。", "珠胎養乎老蚌，龍雷躍於脩鱗。", "爛爛光輝兮明白之窟，稜稜浪級兮桃華之津。", "莊嚴三昧，遊戲諸塵。"]'),
('bb5f2fbc-e593-412f-a4d7-79b519d9aac2','禪人并化主寫真求贊  其三八○','釋正覺','宋','宋诗','song-poetry','','[]','默默有句兮祖祖相傳，心心無住兮靈靈自然。',60,'全唐诗/poet.song.102000.json','["默默有句兮祖祖相傳，心心無住兮靈靈自然。", "石藴玉而輝山，淵含珠而媚川。", "千億門開彌勒彈，三十年用俱胝禪。", "一乘底事，百草頭邊。"]'),
('1ee5db7a-39f4-4761-a1cd-0d57d772f5d3','禪人并化主寫真求贊  其三八一','釋正覺','宋','宋诗','song-poetry','','[]','二儀之門，萬象之根。',58,'全唐诗/poet.song.102000.json','["二儀之門，萬象之根。", "有無難議，青白不痕。", "借功承祖禰，了事付兒孫。", "採華香負蜜蜂股，齊物夢翻蝴蝶槐。", "即相離相，知恩報恩。"]'),
('06bfc378-a67a-4ba5-b338-457df92f36ab','禪人并化主寫真求贊  其三八二','釋正覺','宋','宋诗','song-poetry','','[]','太行之雪春不消，黄河之月夜更饒。',54,'全唐诗/poet.song.102000.json','["太行之雪春不消，黄河之月夜更饒。", "家風許清白，身世自超摇。", "離微器重，出沒機調。", "光燄波瀾俱滿浄，珊瑚林樹漲高潮。"]'),
('70cdd2a1-2797-45a6-8710-a497e41bfaaf','禪人并化主寫真求贊  其三八三','釋正覺','宋','宋诗','song-poetry','','[]','雪拭晚晴，水受秋清。',64,'全唐诗/poet.song.102000.json','["雪拭晚晴，水受秋清。", "天空四壁，月冷三更。", "湛存而獨立，定應而周行。", "二儀之道成且平，萬像之印虛不盈。", "鷗鳥情閒機事外，夕陽沙上未寒盟。"]'),
('457321a5-3306-4009-b881-eb5ad0723a56','禪人并化主寫真求贊  其三八四','釋正覺','宋','宋诗','song-poetry','','[]','老身且懶，居然從簡。',64,'全唐诗/poet.song.102000.json','["老身且懶，居然從簡。", "白雪覆顛，烏華亂眼。", "心光傳祖燈，手段破家產。", "到不到趙州喫茶，回不回睦州擔板。", "借問諸人識也無，青山骨秀閑雲散。"]'),
('dc4a9c93-db08-42ab-a294-5e2683e6436e','禪人并化主寫真求贊  其三八五','釋正覺','宋','宋诗','song-poetry','','[]','枯槁形骸，虛明性懷。',46,'全唐诗/poet.song.102000.json','["枯槁形骸，虛明性懷。", "秋河夜月，老樹蒼崖。", "一機色前自宛轉，萬像頭上誰安排。", "雲門拄杖，趙州草鞋。"]'),
('04e4241a-89d3-4e70-9290-e8cc874408d3','禪人并化主寫真求贊  其三八六','釋正覺','宋','宋诗','song-poetry','','[]','性成而不立玄微，智詣而難分是非。',52,'全唐诗/poet.song.102000.json','["性成而不立玄微，智詣而難分是非。", "天空雲澹泞，夜冷月依稀。", "蝴蝶夢魂兮春晝飛而齊物，白鷗盟事兮夕陽卧而亡機。"]'),
('6f379b69-afaa-456b-9f0b-ea63ee2ed7df','禪人并化主寫真求贊  其三八七','釋正覺','宋','宋诗','song-poetry','','[]','皴皮似雞，疏齒如鯢。',40,'全唐诗/poet.song.102000.json','["皴皮似雞，疏齒如鯢。", "諸緣坐斷，一句全提。", "夜月圓明兮珊瑚海闊，晚雲破碎兮玳瑁天低。"]'),
('5c5abb40-4631-4459-9f24-aedf9d6ad174','禪人并化主寫真求贊  其三八八','釋正覺','宋','宋诗','song-poetry','','[]','肌骨瘦寒，氣貌衰殘。',40,'全唐诗/poet.song.102000.json','["肌骨瘦寒，氣貌衰殘。", "坐冷秋生河闊，心空月墮潮乾。", "善財遊歷百城了，樓閣門開指一彈。"]'),
('b27aa883-c7e9-4de2-bb97-cab70453df48','禪人并化主寫真求贊  其三八九','釋正覺','宋','宋诗','song-poetry','','[]','古岩老僧，百事不能。',62,'全唐诗/poet.song.102000.json','["古岩老僧，百事不能。", "飽雪筠林野之姿，癯猶高節。", "抱松石歲寒之骨，老更蒼稜。", "去就且拙，唱酬可憎。", "慎嚴逆流洞水道，孝滿顛酒曹山曾。"]'),
('73cbeb5f-5204-462f-9363-52cece34ee02','禪人并化主寫真求贊  其三九○','釋正覺','宋','宋诗','song-poetry','','[]','靈靈而空，了了而融。',48,'全唐诗/poet.song.102000.json','["靈靈而空，了了而融。", "正偏之機轉，佛祖之道同。", "玉井有月，冰壺無風。", "兒孫得力成家事，影現諸塵三昧中。"]'),
('8a4ece45-2fb3-4bd6-8e80-795d725cbba5','禪人并化主寫真求贊  其三九一','釋正覺','宋','宋诗','song-poetry','','[]','精神自然，秋早春先。',62,'全唐诗/poet.song.102000.json','["精神自然，秋早春先。", "蟠胸丘壑，繞齒風煙。", "理無生而心傳阿祖，神不死而道出諸仙。", "蒼黄酢酬兮將軍齒鏃之日，黑白勝負兮樵子爛柯之年。"]'),
('f2dca370-f62b-4f88-9e54-50d0025fd5c2','禪人并化主寫真求贊  其三九二','釋正覺','宋','宋诗','song-poetry','','[]','默默亡言，靈靈見根。',36,'全唐诗/poet.song.102000.json','["默默亡言，靈靈見根。", "鼓撾塗毒，香燒返魂。", "物物無心影受鏡，塵塵出礙聲踰垣。"]'),
('0b203f5f-490b-4f9e-ab17-e02afa3b9bc8','禪人并化主寫真求贊  其三九三','釋正覺','宋','宋诗','song-poetry','','[]','萎萎羸羸，病起風姿。',48,'全唐诗/poet.song.102000.json','["萎萎羸羸，病起風姿。", "跛跛挈挈，老來事業。", "坐穩三際平，心空百念絕。", "森羅萬象信崝嶸，門門三昧從施設。"]'),
('a7ce1ae4-58c9-4c7a-a2b8-588150b97996','禪人并化主寫真求贊  其三九四','釋正覺','宋','宋诗','song-poetry','','[]','髮白齒豁，鼻垂口闊。',52,'全唐诗/poet.song.102000.json','["髮白齒豁，鼻垂口闊。", "坐冷月依依，氣清秋漠漠。", "離微出入門開，正偏往來機活。", "雙碧耆婆眼有神，分明百草頭邊藥。"]'),
('990bf735-7f87-4659-95d0-ab47c8e4adf7','禪人并化主寫真求贊  其三九五','釋正覺','宋','宋诗','song-poetry','','[]','慧而能定，定而能應。',48,'全唐诗/poet.song.102000.json','["慧而能定，定而能應。", "空有短長，初無欠剩。", "定慧力莊嚴，性相心齊證。", "妙觀察智照非功，成所作智同圓鏡。"]'),
('a754a0dc-5e93-44c8-beb1-46df70daee4b','禪人并化主寫真求贊  其三九六','釋正覺','宋','宋诗','song-poetry','','[]','默默而遊，月冷天秋。',48,'全唐诗/poet.song.102000.json','["默默而遊，月冷天秋。", "靡靡而周，雲行水流。", "身心無畔岸，機用有錐鈎。", "諸塵三昧縱橫句，分付之人拄杖頭。"]'),
('555deb00-142e-400a-9c0c-d69621e485e2','禪人并化主寫真求贊  其三九七','釋正覺','宋','宋诗','song-poetry','','[]','妙了常存，幽靈不昏。',58,'全唐诗/poet.song.102000.json','["妙了常存，幽靈不昏。", "偏正旋樞臼，離微見道根。", "微塵破處大經出，冷口開時諸佛吞。", "隨緣歷歷，得用門門。", "成褫家事，分付兒孫。"]'),
('c56f03c6-ce5f-403f-b9ee-4a134133c795','禪人并化主寫真求贊  其三九八','釋正覺','宋','宋诗','song-poetry','','[]','影之神，物之春。',50,'全唐诗/poet.song.102000.json','["影之神，物之春。", "鶯喉頰之滑滑，柳眉目之津津。", "蜂股華須粉，蠟脾蜜釀醇。", "等閑諦了遊戲事，端的還如幻化人。"]'),
('e54d9ecd-7963-4111-bfdd-bfd77a66f628','禪人并化主寫真求贊  其三九九','釋正覺','宋','宋诗','song-poetry','','[]','湛存不渾，靈明不昏。',76,'全唐诗/poet.song.102000.json','["湛存不渾，靈明不昏。", "派分河漢底，流决崑崙源。", "見聞了成一相，影響應空六根。", "體本真如，能來生滅之界。", "用隨生滅，却入真如之門。", "叢林參飽三條篾，雲夢等閑八九吞。"]'),
('b526a871-b4b7-4459-b138-0fd1f938bbdc','禪人并化主寫真求贊  其四○○','釋正覺','宋','宋诗','song-poetry','','[]','淵默元成，至虛不盈。',50,'全唐诗/poet.song.102000.json','["淵默元成，至虛不盈。", "體天地之含光，十方昭徹。", "用陰陽之變態，萬像崝嶸。", "百戰瘢知風雨信，垂頭兀兀老昇平。"]'),
('e5dbf4d2-dbd9-48f2-9cb1-c2e644a74f11','禪人并化主寫真求贊  其四○一','釋正覺','宋','宋诗','song-poetry','','[]','龜兮蓍兮，祛執决疑。',40,'全唐诗/poet.song.102000.json','["龜兮蓍兮，祛執决疑。", "師兮範兮，扶斜理差。", "定徹其底，慧窮其涯。", "箭撞筈破，珠旋影隨。"]'),
('70bfe5c9-32b1-44a1-abb5-5f36351c6acc','禪人并化主寫真求贊  其四○二','釋正覺','宋','宋诗','song-poetry','','[]','默成其性，慧潤其定。',40,'全唐诗/poet.song.102000.json','["默成其性，慧潤其定。", "虛應六窗，觀通三徑。", "善巧開權，觸機墮穽。", "怪殺者僧，藥多成病。"]'),
('0b49044e-6335-4e30-b632-b644fa7a5585','禪人并化主寫真求贊  其四○三','釋正覺','宋','宋诗','song-poetry','','[]','祖祖家傳，心心印全。',60,'全唐诗/poet.song.102000.json','["祖祖家傳，心心印全。", "混沌未受鑿，威音不得專。", "蕉雷文象齒之所以，桂月暈犀角之能然。", "水自竹來兮綠非假借，風從華過兮香有因緣。"]'),
('fecdfbe2-d49e-4537-a39e-f7ef63c769e6','禪人并化主寫真求贊  其四○四','釋正覺','宋','宋诗','song-poetry','','[]','像取模畫，人成幻化。',90,'全唐诗/poet.song.102000.json','["像取模畫，人成幻化。", "得失一鬮，是非一馬。", "建立摐摐，權行且且。", "平貼而安，放蕩而野。", "科臼弗存，軌儀何暇。", "饑則餐，飽則罷。", "硬而枕，軟而藉。", "出世間於世間，藏天下於天下。", "更問如何，之乎者也。"]'),
('dbd7fb79-5336-4fbd-ba47-13ebade40daa','禪人并化主寫真求贊  其四○五','釋正覺','宋','宋诗','song-poetry','','[]','本來無物，當處出生。',74,'全唐诗/poet.song.102000.json','["本來無物，當處出生。", "白毿毿之頭髮，烏律律之眼睛。", "誰敢居尊宿，僧相奉老成。", "現威儀，住滅定。", "隨影響，放光明。", "玳瑁海深難尋含月之蚌，珊瑚林沒誰見𩥇潮之鯨。"]'),
('965f2bdb-46d8-4dd6-943d-c39b1c16527d','禪人并化主寫真求贊  其四○六','釋正覺','宋','宋诗','song-poetry','','[]','兀兀默耕，天成地平。',74,'全唐诗/poet.song.102000.json','["兀兀默耕，天成地平。", "一心無住住，萬像不生生。", "起家空劫壺中句，借伴今時路上行。", "攪叢林人七八處，令行而據。", "握拄杖子四十年，師坐而橫。", "用之不敝，虛而不盈。"]'),
('c25d1a2b-3983-40d0-83aa-a0dfe791a01f','禪人并化主寫真求贊  其四○七','釋正覺','宋','宋诗','song-poetry','','[]','湛乎性源，遊乎度門。',76,'全唐诗/poet.song.102000.json','["湛乎性源，遊乎度門。", "動靜出礙，方圓不痕。", "寒木得春晚，雪窗亡夜昏。", "通塞也虛離實坎，變化也連乾斷坤。", "六和合而無功兮脫略三千之界，萬差別而有據兮齊承一點之恩。"]'),
('617f5354-cb99-4832-b24d-0ad690efc41d','禪人并化主寫真求贊  其四○八','釋正覺','宋','宋诗','song-poetry','','[]','這箇形容，緣報遭逢。',62,'全唐诗/poet.song.102000.json','["這箇形容，緣報遭逢。", "藏萬德於未兆，戢六用於無蹤。", "雪陣血戰，玉田歷農。", "影響若空谷，隨扣如霜鐘。", "竿頭不是風幡動，知有此事還盧舂。"]'),
('89762ace-45b1-444c-9154-e176efe60c8c','禪人并化主寫真求贊  其四○九','釋正覺','宋','宋诗','song-poetry','','[]','碧澗之松，煙巢之鶴。',44,'全唐诗/poet.song.102000.json','["碧澗之松，煙巢之鶴。", "野性閑閑，癯身卓卓。", "江含月而練長，水連天而秋闊。", "一點分明兮十方虛豁。"]'),
('5052148a-424a-4989-ac9a-cff027503522','禪人并化主寫真求贊  其四一○','釋正覺','宋','宋诗','song-poetry','','[]','跡像而無，純全而有。',56,'全唐诗/poet.song.102000.json','["跡像而無，純全而有。", "陰陽不測之神，生滅不到而壽。", "十方界聊現半身，三世佛不消一口。", "只箇山形拄杖子，與君觸處相隨走。"]'),
('851a0e58-f16f-4b77-b01f-1619035f7589','禪人并化主寫真求贊  其四一一','釋正覺','宋','宋诗','song-poetry','','[]','目深額聳，口方鼻端。',41,'全唐诗/poet.song.102000.json','["目深額聳，口方鼻端。", "秋雲消兮天青而闊，夜月上兮水白而寒。", "看看，影像隨應兮明珠走盤。"]'),
('4f12f8b7-9560-4faa-b044-22d6addf4622','禪人并化主寫真求贊  其四一二','釋正覺','宋','宋诗','song-poetry','','[]','用得乎眉，體全乎鼻。',50,'全唐诗/poet.song.102000.json','["用得乎眉，體全乎鼻。", "香象不羣，金毛無畏。", "明妙吉之初心，入普賢之幻智。", "回途放曠知不知，般若光中熟遊戲。"]'),
('501ab595-eef3-41dd-94be-8b57356047cc','禪人并化主寫真求贊  其四一三','釋正覺','宋','宋诗','song-poetry','','[]','雲水之身，山林之氣。',62,'全唐诗/poet.song.102000.json','["雲水之身，山林之氣。", "不專乎學，不遊乎藝。", "默坐而心空，妙傳而道貴。", "西風凄清秋有痕，長天碧浄雲無蒂。", "從來佛祖真宗，只麽克承家世。"]'),
('ba83ff00-0c22-4a91-8002-bef2c4585817','禪人并化主寫真求贊  其四一四','釋正覺','宋','宋诗','song-poetry','','[]','山光寒點雪，水色冷磨秋。',56,'全唐诗/poet.song.102000.json','["山光寒點雪，水色冷磨秋。", "肝膽古鑑浄，身世浮萍流。", "罔象而珠得，亡牛而刃遊。", "瑞鳳入網兮連鼇上鈎，箇般手段兮老不傳休。"]'),
('3557fe6a-fa0e-4ad9-b399-90f4a9cf9df8','禪人并化主寫真求贊  其四一五','釋正覺','宋','宋诗','song-poetry','','[]','淵默而明，湛存而妙。',46,'全唐诗/poet.song.102000.json','["淵默而明，湛存而妙。", "三世齊平，十方圓照。", "月隨水而流，風入松而嘯。", "相逢會有知音，向道自然同調。"]'),
('f41b861d-6d9e-4181-b5d1-3e277035a6d8','禪人并化主寫真求贊  其四一六','釋正覺','宋','宋诗','song-poetry','','[]','鼻直口四方，眉低眼三角。',60,'全唐诗/poet.song.102000.json','["鼻直口四方，眉低眼三角。", "默默句難傳，深深誰轉脚。", "入掛樹之壺，天地能闊。", "得爛柯之棋，黑白未錯。", "如今更不囊藏，到處隨宜著落。"]'),
('3bf59f4d-9379-4d6d-843b-68afeb2295cb','禪人并化主寫真求贊  其四一七','釋正覺','宋','宋诗','song-poetry','','[]','了了常知，靈靈匪思。',59,'全唐诗/poet.song.102000.json','["了了常知，靈靈匪思。", "妙空三世，圓包二儀。", "針鼻長通線，梭臍細吐絲。", "出谷白雲風斷送，盈科流水月相隨。", "普應羣機兮，自然合宜。"]'),
('74f64d21-0af1-4924-bfa7-e6687466f295','禪人并化主寫真求贊  其四一八','釋正覺','宋','宋诗','song-poetry','','[]','衆流吞海，大澤藏山。',28,'全唐诗/poet.song.102000.json','["衆流吞海，大澤藏山。", "磨雲月兮蟾蜍膽冷，卧風波兮鷗鳥情閒。"]'),
('e16ae38e-6295-45d1-9c75-b97dd145933f','禪人并化主寫真求贊  其四一九','釋正覺','宋','宋诗','song-poetry','','[]','眉目精神，畫工裝點。',54,'全唐诗/poet.song.102000.json','["眉目精神，畫工裝點。", "功轉玄微，了無絲糝。", "秋天清而河氣澄明，夜水白而月魂瀲灧。", "物物頭頭應化身，超出機前有刑典。"]'),
('c0bc66bb-8c31-485c-b0e6-3863fd935809','禪人并化主寫真求贊  其四二○','釋正覺','宋','宋诗','song-poetry','','[]','廓然而瑩，了無餘影。',48,'全唐诗/poet.song.102000.json','["廓然而瑩，了無餘影。", "卓爾而存，豈有他痕。", "靜非像也，徹見其源。", "動順緣也，萌發其根。", "用綿綿兮攪不渾。"]'),
('6cd2d7c9-be20-4730-afa1-661c08603b58','禪人并化主寫真求贊  其四二一','釋正覺','宋','宋诗','song-poetry','','[]','鑑之現像，谷之藏神。',50,'全唐诗/poet.song.102000.json','["鑑之現像，谷之藏神。", "六門隨萬彙，三昧入諸塵。", "月通犀角暈，華到蜜房春。", "歷歷之機果明了，更嫌何處不相親。"]'),
('6c2774bf-3653-475d-a586-e3b89979b984','禪人并化主寫真求贊  其四二二','釋正覺','宋','宋诗','song-poetry','','[]','顰而嗔，伸而悅。',52,'全唐诗/poet.song.102000.json','["顰而嗔，伸而悅。", "默傳鼻孔家風，用付眉毛時節。", "放下機投，展開漏洩。", "十方三世兮同得同參，二儀萬像兮同聽同說。"]'),
('0815d13f-023f-47e6-b2b6-def6721381dd','禪人并化主寫真求贊  其四二三','釋正覺','宋','宋诗','song-poetry','','[]','止水懷月，空山吐雲。',40,'全唐诗/poet.song.102000.json','["止水懷月，空山吐雲。", "清白自若，高閒不羣。", "丘壑性靈兮猿鶴得伴，江湖情味兮鷗鷺相分。"]'),
('4d17a250-363e-4db9-93d1-e5f0148bead6','禪人并化主寫真求贊  其四二四','釋正覺','宋','宋诗','song-poetry','','[]','霜洗斗魁，秋生河漢。',28,'全唐诗/poet.song.102000.json','["霜洗斗魁，秋生河漢。", "形夭矯而長松參雲，氣澄明而餘潦退岸。"]'),
('1a0246d4-c5e3-47dc-8686-7db6c60d66e3','禪人并化主寫真求贊  其四二五','釋正覺','宋','宋诗','song-poetry','','[]','髮皚皚而雪山，目湛湛而秋潭。',66,'全唐诗/poet.song.102000.json','["髮皚皚而雪山，目湛湛而秋潭。", "杖拂老伴，叢林飽參。", "萬全非一有，二破却成三。", "門門虛而正受，物物各自禪談。", "春亭不要閒狼藉，華烏而今罷了銜。"]'),
('42cc1871-e88e-450a-8303-f23a789fe8e0','禪人并化主寫真求贊  其四二六','釋正覺','宋','宋诗','song-poetry','','[]','白髮蒼顔，三篾住山。',50,'全唐诗/poet.song.102000.json','["白髮蒼顔，三篾住山。", "開眼不覺曉，靜坐不知閒。", "善應全機用，靈明入道環。", "而今相伴塵中去，榆葉青錢莫我慳。"]'),
('93ce9edb-0c54-4278-8d32-921063d0f828','禪人并化主寫真求贊  其四二七','釋正覺','宋','宋诗','song-poetry','','[]','行起解絕，宗全說缺。',58,'全唐诗/poet.song.102000.json','["行起解絕，宗全說缺。", "根根塵塵兮元自現成，佛佛祖祖兮何勞施設。", "本色當行家，賞音箇時節。", "遲日風流轉柳腰，遷林語軟調鶯舌。"]'),
('009dcf41-e0e0-41ac-b546-4566e1484bdc','禪人并化主寫真求贊  其四二八','釋正覺','宋','宋诗','song-poetry','','[]','亡牛刃游，罔象珠得。',24,'全唐诗/poet.song.102000.json','["亡牛刃游，罔象珠得。", "沙漠漠而鷗寒，天蒼蒼而雁沒。"]'),
('f3197b16-7922-460a-ad56-dfa33a513380','禪人并化主寫真求贊  其四二九','釋正覺','宋','宋诗','song-poetry','','[]','石上足蟠，人間念乾。',192,'全唐诗/poet.song.102000.json','["石上足蟠，人間念乾。", "秋生眼角，喜入眉端。", "丘壑之身心磈磊，叢林之肝膽衰殘。", "澗月依稀，夜霜濯磨而氣韻清白。", "岩松偃蹇，朔雪湔洗而精神翠寒。", "行脚屨敗，住山篾寬。", "點著破竈墮，呼回倒剎竿。", "光陰催促三眠繭，風雨捫摩百戰瘢。", "影像受鑑，音聲度垣。", "寂默髑髏眼，光明赤肉團。", "雲錦舒春兮華容光燄，潮雷卷雪兮海口波瀾。", "掛拂之喝，拄杖之竄。", "胡餅饅頭有變通而紹祖供職，蓮華荷葉沒科臼而說禪判宦。", "相隨學步，莫似邯鄲。"]'),
('cf029327-165a-4bf2-b072-e6fdfad1d80e','烏巨光長老寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','骨寒氣羸，頂雪頷絲。',104,'全唐诗/poet.song.102000.json','["骨寒氣羸，頂雪頷絲。", "牛首之懶，虎頭之癡。", "兀兀逃禪處，空空選佛時。", "九萬鵬風扶羊角，千年兔月卧蛾眉。", "門門幻起，塵塵智隨。", "蝴蝶夢遊兮莊生齊物，桃華眼冷兮靈雲不疑。", "初無稜縫，渾莫鍼錐。", "巴陵曾對吹毛劍，珊瑚撐月夜枝枝。"]'),
('2772add3-d285-4ee5-8e2c-747fea9f75bc','真首座寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','覺海元澄，性天廓平。',100,'全唐诗/poet.song.102000.json','["覺海元澄，性天廓平。", "耳眼空更遠，息氣細而清。", "露寒斗濕，秋淡河橫。", "叢林底去就，百草頭光明。", "蛾眉之月兮三千剎海，羊角之風兮九萬霄程。", "肚皮參飽，肝膽老成。", "揮斤容易甚，器受太難生。", "爲你一斲鼻堊，從教四望人驚。"]'),
('d2fbc86b-bddb-44a3-8e2c-646c381bd336','教監寺寫真救贊','釋正覺','宋','宋诗','song-poetry','','[]','胡床一默，智遊理窟。',106,'全唐诗/poet.song.102000.json','["胡床一默，智遊理窟。", "偏正往來，離微出沒。", "上下混成也二儀之根，去來平等也三世之則。", "有時隨應諸塵，不可說似一物。", "修證不無，污染不得。", "震之東，兌之西，離之南，坎之北。", "青州布衫，鎮州蘿蔔。", "當家行眼裏有筋，本色漢舌頭無骨。"]'),
('16e663b5-8f64-46cb-b160-9138458f9a5c','小師智臨禪客寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','雲石雪松，歲寒之友從。',120,'全唐诗/poet.song.102000.json','["雲石雪松，歲寒之友從。", "曉月霜鐘，清白之音容。", "自樂也村歌社舞，平懷也牧笛歸農。", "暴雨卒風，潛神堂而避陣。", "吼雷掣電，戰禪席而交鋒。", "十分閑暇，一等疏慵。", "青山白雲之去就，浮萍流水之行蹤。", "披霧變文豹，吟雲蛻骨龍。", "身老藝孤兮難其授子，智齊德半兮未可傳宗。"]'),
('f25d0ef4-0c80-462a-8864-58c548cb402d','鄭成忠寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','智不能知，識不能識。',100,'全唐诗/poet.song.102000.json','["智不能知，識不能識。", "一氣輕清，雙瞳冷碧。", "蓮開夢覺，十方虛殞於一時。", "鯤蛻鵬摶，九萬里成乎一息。", "物我普融，自他平出。", "珠受色而不痕，劍揮空而何跡。", "須更指響，彌勒閣開也許是重深。", "塵剎分身，普賢毛孔也初非迫窄。"]'),
('44a2f64c-d971-4cd0-9a67-69421bf7eec2','王承事寫真求贊','釋正覺','宋','宋诗','song-poetry','','[]','蒼棱羼顔，璠璵藴石而輝山。',88,'全唐诗/poet.song.102000.json','["蒼棱羼顔，璠璵藴石而輝山。", "老節歲寒，琥珀抱松而永年。", "威音未興之際，混沌欲鑿之前。", "叢林大義兮道尊百丈，剎海平潮兮月現三千。", "我爲你說法，你爲我開田。", "據坐松根石頭上，知音人信默心傳。"]'),
('18c5562d-6bc5-4d9b-b352-89d294f08aa4','頌古二十一首  其一','釋正覺','宋','宋诗','song-poetry','','[]','如今推也，是子是賊。',20,'全唐诗/poet.song.102000.json','["如今推也，是子是賊。", "買帽相頭，食魚去骨。"]'),
('99b5ffbd-48d8-4f79-a9f2-4a26c2068fdb','頌古二十一首  其二','釋正覺','宋','宋诗','song-poetry','','[]','千鄉萬里尋知己，一語臨禨不契梁。',32,'全唐诗/poet.song.102000.json','["千鄉萬里尋知己，一語臨禨不契梁。", "面壁九年居少室，覓心千古累神光。"]'),
('9898c0cc-a5a2-47a9-9bd6-29555611ad4d','頌古二十一首  其三','釋正覺','宋','宋诗','song-poetry','','[]','我這鎌子用得快，當時三十文錢買。',32,'全唐诗/poet.song.102000.json','["我這鎌子用得快，當時三十文錢買。", "南泉門下路歧通，寄語行人著精彩。"]'),
('e18e6c14-8761-4676-9666-a971feba06c1','頌古二十一首  其四','釋正覺','宋','宋诗','song-poetry','','[]','溈山水牯牛，禪人聚頭咬。',24,'全唐诗/poet.song.102000.json','["溈山水牯牛，禪人聚頭咬。", "可憐負舂人，喚作嶺南獠。"]'),
('943f82b0-2d42-4374-a959-ee86158145bb','頌古二十一首  其五','釋正覺','宋','宋诗','song-poetry','','[]','露地白牛起問端，隨緣叱叱齒牙寒。',32,'全唐诗/poet.song.102000.json','["露地白牛起問端，隨緣叱叱齒牙寒。", "不知飲啄是何物，喫喫直教滄海乾。"]'),
('f57cff7b-3ca4-403e-8245-884b58939b5b','頌古二十一首  其六','釋正覺','宋','宋诗','song-poetry','','[]','容顔甚奇妙，光明照十方。',56,'全唐诗/poet.song.102000.json','["容顔甚奇妙，光明照十方。", "我適曾供養，今復還親覲。", "黄鶴樓前共語時，白蘋紅蓼對江湄。", "衷腸已訴無人會，惟有清風明月知。"]'),
('d7efdc47-65c1-4237-93a6-b355e5149e9a','頌古二十一首  其七','釋正覺','宋','宋诗','song-poetry','','[]','青山不異，白玉無瑕。',52,'全唐诗/poet.song.102000.json','["青山不異，白玉無瑕。", "茫茫流水，擾擾黄花。", "有佛處纖毫不立，無佛處萬別千差。", "長安路上未歸客，尋溪由自摘楊花。"]'),
('9246ba81-47fc-4f07-b51a-8f7e85ffbb52','頌古二十一首  其八','釋正覺','宋','宋诗','song-poetry','','[]','侍者來言報大王，趙州曾揖下禪床。',32,'全唐诗/poet.song.102000.json','["侍者來言報大王，趙州曾揖下禪床。", "憐兒不覺傍觀醜，爭奈全身在帝鄉。"]'),
('458b2524-2d08-4d44-be84-cacc4892fbb9','頌古二十一首  其九','釋正覺','宋','宋诗','song-poetry','','[]','出羣須是英靈漢，敵勝還他師子兒。',32,'全唐诗/poet.song.102000.json','["出羣須是英靈漢，敵勝還他師子兒。", "選佛若無如是眼，假饒千載亦奚爲。"]'),
('3e89b717-f89b-494e-84c0-60af4d89236d','頌古二十一首  其一○','釋正覺','宋','宋诗','song-poetry','','[]','殺人不眨眼，救人須出手。',24,'全唐诗/poet.song.102000.json','["殺人不眨眼，救人須出手。", "論實不論虛，合升始爲斗。"]'),
('6122ed9d-a003-4bb2-8513-806444518d37','頌古二十一首  其一一','釋正覺','宋','宋诗','song-poetry','','[]','學道須教正眼開，莫將狂解意中猜。',32,'全唐诗/poet.song.102000.json','["學道須教正眼開，莫將狂解意中猜。", "脫鞋龜上人難會，遂使携囊特地來。"]'),
('656fed68-9d3f-43cd-ab1c-c8a73a239965','頌古二十一首  其一二','釋正覺','宋','宋诗','song-poetry','','[]','識法者懼，欺敵者亡。',20,'全唐诗/poet.song.102000.json','["識法者懼，欺敵者亡。", "水中辨乳，須是鵞王。"]'),
('9c502b37-028a-4e3d-b716-334f4f26c3b7','頌古二十一首  其一三','釋正覺','宋','宋诗','song-poetry','','[]','雙盲入暗路崎嶇，日落棲蘆暫得甦。',64,'全唐诗/poet.song.102000.json','["雙盲入暗路崎嶇，日落棲蘆暫得甦。", "爭似石人眠半夜，免教舜讓守林居。", "須知花綻非干木，無脚行時早觸途。", "昨朝風起長安道，元是崑崙進國圖。"]'),
('de226e95-ff50-4784-8966-b63afee7a6d4','頌古二十一首  其一四','釋正覺','宋','宋诗','song-poetry','','[]','渠非老朽，不禮不受。',50,'全唐诗/poet.song.102000.json','["渠非老朽，不禮不受。", "威音世前，毗盧頂後。", "把定壺中白日長，觸著匣內青蛇吼。", "良醫叮囑病人，服藥不如忌口。"]'),
('6321255f-f1c6-4bd4-a313-0f5974134090','頌古二十一首  其一五','釋正覺','宋','宋诗','song-poetry','','[]','即日貴人，舊家貧漢。',52,'全唐诗/poet.song.102000.json','["即日貴人，舊家貧漢。", "兄弟相承，尊卑互換。", "向晚途中眼不開，夜明簾外機旋轉。", "騎牛戴帽異中來，百鍊真金色不變。"]'),
('33cdbd90-97c9-4bb3-978a-51180b058146','頌古二十一首  其一六','釋正覺','宋','宋诗','song-poetry','','[]','大地火發，間不容髮。',30,'全唐诗/poet.song.102000.json','["大地火發，間不容髮。", "南海崑崙，天寒不襪。", "祖祖相傳，一頭搕𣜂。"]'),
('74defcc9-f850-42ba-80cf-e27d864bb32b','頌古二十一首  其一七','釋正覺','宋','宋诗','song-poetry','','[]','無人接得渠，遺逼馬相如。',24,'全唐诗/poet.song.102000.json','["無人接得渠，遺逼馬相如。", "果來橋上也，記得柱頭書。"]'),
('4ce1286a-a79c-4b00-b60c-9152e81cca25','頌古二十一首  其一八','釋正覺','宋','宋诗','song-poetry','','[]','無人識得渠，棋局醉樵夫。',24,'全唐诗/poet.song.102000.json','["無人識得渠，棋局醉樵夫。", "回頭斧柯爛，大海亦成枯。"]'),
('4c26911c-b588-4582-8175-bc33f34c546c','頌古二十一首  其一九','釋正覺','宋','宋诗','song-poetry','','[]','雪老大開方便路，低頭却入菴中去。',64,'全唐诗/poet.song.102000.json','["雪老大開方便路，低頭却入菴中去。", "者僧有眼恰如盲，却被巖頭行一步。", "者僧好休不肯休，依然依路去悠悠。", "元來不會雪峯意，却被巖頭甕贛頭。"]'),
('8516a4de-6877-4acf-9b1f-c23ef5b9d3c3','頌古二十一首  其二○','釋正覺','宋','宋诗','song-poetry','','[]','翡翠簾垂，絲綸未濟。',56,'全唐诗/poet.song.102000.json','["翡翠簾垂，絲綸未濟。", "紫羅帳合，視聽難通。", "犯動毛頭，月昇夜扃。", "密移一步，鶴出銀籠。", "脫身一色無遺影，不坐同風落大功。"]'),
('1037f5ec-7188-4671-98e1-bd1a8b7502a2','頌古二十一首  其二一','釋正覺','宋','宋诗','song-poetry','','[]','大衆退後，衲僧去就。',36,'全唐诗/poet.song.102000.json','["大衆退後，衲僧去就。", "豈用機關，那容體究。", "蓑翁老熟慣風波，橈棹不施船放溜。"]'),
('efc21c99-23cb-494e-994f-fcedccdb08a9','頌古二十一首  其二二','釋正覺','宋','宋诗','song-poetry','','[]','智門真得祖家風，放出雲門廣長舌。',50,'全唐诗/poet.song.102000.json','["智門真得祖家風，放出雲門廣長舌。", "大智如愚，大巧若拙，用盡工夫參不徹。", "莫於平地上增堆，休向虛空裏釘橛。"]'),
('6fd110dc-091c-4526-83dc-8b0666c1ee22','偈','釋正覺','宋','宋诗','song-poetry','','[]','句裏明宗則易，宗中辨白則難。',30,'全唐诗/poet.song.102000.json','["句裏明宗則易，宗中辨白則難。", "凍雞未報家林曉，隱隱行人過雪山。"]'),
('e3cf7d6e-3e2f-4665-bc09-874825dfb6df','雪竇中巖夜坐','釋正覺','宋','宋诗','song-poetry','','[]','哀猿叫落中巖月，野客吟殘夜半燈。',32,'全唐诗/poet.song.102000.json','["哀猿叫落中巖月，野客吟殘夜半燈。", "此景此時誰會得，白雲深處坐禪僧。"]'),
('db85cb04-d8f7-4f8d-9fdc-285d556b9863','題奉化西峰圓覺禪院','釋正覺','宋','宋诗','song-poetry','','[]','水流百折山蒼蒼，古寺秋容橫野航。',64,'全唐诗/poet.song.102000.json','["水流百折山蒼蒼，古寺秋容橫野航。", "明月初濡寒露白，籬花似趁重陽黄。", "道人心已老松石，學子膽須磨雪霜。", "默默澄源坐兀兀，游魚沙鳥靜相忘。"]'),
('f0eb589e-48d9-49e2-a827-77b91ac53fb2','治塗田','釋正覺','宋','宋诗','song-poetry','','[]','棋局未散芭蕉仙，樵夫柯爛海成田。',64,'全唐诗/poet.song.102000.json','["棋局未散芭蕉仙，樵夫柯爛海成田。", "長隄抗潮人得路，淡水沒脛牛加鞭。", "天雲晚晴深似綺，禾稻日茂濃如煙。", "白米軟炊供衆飽，心空選佛石頭禪。"]'),
('824a5a78-970c-4e4e-b486-d9896aa975cc','紫巖九章章八句上壽張丞相  其一','張元幹','宋','宋诗','song-poetry','','[]','赫赫紫巖，白虹貫淵。',40,'全唐诗/poet.song.102000.json','["赫赫紫巖，白虹貫淵。", "玉生其中，匪雕匪鎸。", "登於廊廟，圭璋渾全。", "溫如之質，所寶象賢。"]'),
('f84af379-e2a5-40f9-b37e-2f143ec784b3','紫巖九章章八句上壽張丞相  其二','張元幹','宋','宋诗','song-poetry','','[]','紫巖赫赫，衆山維則。',40,'全唐诗/poet.song.102000.json','["紫巖赫赫，衆山維則。", "秉國之鈞，百僚是式。", "志殄仇方，力復明辟。", "時方中興，勳冠今昔。"]'),
('2b6f056b-0e8a-4bb0-aadf-aaea04086829','紫巖九章章八句上壽張丞相  其三','張元幹','宋','宋诗','song-poetry','','[]','紫巖高兮，上摩穹窿。',40,'全唐诗/poet.song.102000.json','["紫巖高兮，上摩穹窿。", "雨露潤澤，風雲會同。", "表宋宗臣，禮泰智崇。", "皇以昭之，簡在帝衷。"]'),
('d818ec9b-2225-4bde-bcce-af5416350d90','紫巖九章章八句上壽張丞相  其四','張元幹','宋','宋诗','song-poetry','','[]','紫巖廣兮，作鎮坤位。',40,'全唐诗/poet.song.102000.json','["紫巖廣兮，作鎮坤位。", "盡臣之道，厚德以載。", "開國南陽，厥緒光大。", "是似是續，福祿未艾。"]'),
('04ab8757-7e4b-4883-82be-8103000971e8','紫巖九章章八句上壽張丞相  其五','張元幹','宋','宋诗','song-poetry','','[]','瞻彼紫巖，降神所儲。',40,'全唐诗/poet.song.102000.json','["瞻彼紫巖，降神所儲。", "進退有度，威儀甚都。", "粵自己未，帥於無諸。", "以忠以孝，奉承安輿。"]'),
('acad736d-541a-46e8-a04b-37e72b855750','紫巖九章章八句上壽張丞相  其六','張元幹','宋','宋诗','song-poetry','','[]','北堂之尊，命婦稱首。',40,'全唐诗/poet.song.102000.json','["北堂之尊，命婦稱首。", "逢是穀旦，酌以大斗。", "公如老萊，衣衮裳繡。", "式歌且舞，以介眉壽。"]'),
('05c6fd50-d91c-4982-8ce3-21883a83e9fe','紫巖九章章八句上壽張丞相  其七','張元幹','宋','宋诗','song-poetry','','[]','土宇未復，繄公闢之。',40,'全唐诗/poet.song.102000.json','["土宇未復，繄公闢之。", "士風未變，繄公革之。", "軍律未振，繄公鼓之。", "國論未定，繄公斷之。"]'),
('37ebaa79-c8d2-4e39-9374-2a2c6a06d1a3','紫巖九章章八句上壽張丞相  其八','張元幹','宋','宋诗','song-poetry','','[]','來朝伊何，築隄於沙。',40,'全唐诗/poet.song.102000.json','["來朝伊何，築隄於沙。", "對揚伊何，言宣其麻。", "明明天子，坐於正衙。", "徯公來歸，相我邦家。"]'),
('eea8024f-77f0-4e30-8ea8-98e230e0e568','紫巖九章章八句上壽張丞相  其九','張元幹','宋','宋诗','song-poetry','','[]','紫巖之松，在澗之沚。',40,'全唐诗/poet.song.102000.json','["紫巖之松，在澗之沚。", "下有茯苓，兔絲蔓只。", "結爲琥珀，深根固柢。", "願公難老，受茲燕喜。"]'),
('a8a6c11d-6a48-4ea1-89e2-869ff9fb79b6','雒陽陳去非自符寶郎謫陳留酒官予時作丞澶淵舊僚友也有詩次韻','張元幹','宋','宋诗','song-poetry','','[]','寒水遶近郭，棲鴉蔽高原。',72,'全唐诗/poet.song.102000.json','["寒水遶近郭，棲鴉蔽高原。", "映带幽人居，暝色起草根。", "衡門東南開，濁河日夜奔。", "所喜古堤月，初出煙江村。", "不入城市久，懶訪亡與存。", "羨子了萬事，坐以一氣春。"]'),
('cba63559-28b3-47a6-9d7e-0d9ccd98a7be','丁未歲春過西湖寶藏寺作','張元幹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖垠取微徑，窈窕松門深。',72,'全唐诗/poet.song.102000.json','["湖垠取微徑，窈窕松門深。", "中有古佛屋，閴無人足音。", "春雲带飛雨，冷色來蒼岑。", "孰知戎馬盛，但見藤蘿陰。", "平生雲卧想，正欲幽夢尋。", "不減避世士，契此太古心。"]'),
('018ab369-03f6-42a1-8e6d-380b71a2a6e6','乙卯秋奉送王周士龍閣自貶所歸鼎州太夫人侍下','張元幹','宋','宋诗','song-poetry','','[]','語離三秋風，念子萬里客。',168,'全唐诗/poet.song.102000.json','["語離三秋風，念子萬里客。", "我獨憂患餘，幾爲死生隔。", "相逢忽眼明，照影俱頭白。", "蘭若清夜長，連床話疇昔。", "如何功名心，一旦乃冰釋。", "賣藥真徉狂，穿雲忘遷謫。", "不然蔬笋腸，寧無瘴烟色。", "良由火棗成，內景充尺宅。", "下視陋九州，槐安等稱國。", "絕憐蠻觸爭，亦復弄兵革。", "亂來更多事，老去覺世窄。", "歸歟桃花源，斑衣作兒劇。", "此樂人所稀，今我那能得。", "他時南山南，寄書北山北。"]'),
('29ceea11-3eb4-4bcb-b778-90ef21c68f76','奉和希道新句兼簡祖穎漕使','張元幹','宋','宋诗','song-poetry','','[]','秋來乏隣酤，近事采塗說。',144,'全唐诗/poet.song.102000.json','["秋來乏隣酤，近事采塗說。", "愁多費陶寫，戶小輒敗闕。", "誰能空隱憂，判飲最良策。", "兩公俱世豪，風味奪佳節。", "手釀甕中春，香浮玉丹色。", "相餉走鴟夷，芳辛真妙絕。", "共賦醉鄉詩，銷磨閑日月。", "頗聞鎖娉婷，迴風舞流雪。", "何妨出房櫳，滿引快關膈。", "此念想當然，清尊可虛設。", "我老留甌閩，感時夢淮浙。", "公其招故人，亦記未歸客。"]'),
('5166fe7f-2133-4404-a2e8-37e9d532fe7d','送舒希古','張元幹','宋','宋诗','song-poetry','','[]','老舒古君子，送客皆善類。',60,'全唐诗/poet.song.102000.json','["老舒古君子，送客皆善類。", "觴行頗軒渠，一斗輒徑醉。", "凉颸生白蘋，落日照紫翠。", "驪駒雖在門，不下兒女淚。", "儻復逢湘纍，更與問憔悴。"]'),
('de95e8c3-e1a7-42ce-bb1e-48d1f92b45fb','過白彪訪沈次律有感十六韻','張元幹','宋','宋诗','song-poetry','','[]','天驕毒中原，國勢苦日削。',192,'全唐诗/poet.song.102000.json','["天驕毒中原，國勢苦日削。", "一爲虛聲摇，顛沛幾失脚。", "翠華棲海隅，此戯亦太虐。", "忽聞哀痛詔，迸淚向寥寞。", "何當速悔禍，四海安耕鑿。", "乃者浙西帥，望風先即却。", "坐令臨安城，開關猶白著。", "只今鋒鏑餘，寃鬼號冥漠。", "賞罰二大柄，倒持示微弱。", "豈無英雄人，戴宋心未薄。", "有如沈使君，忠義等籌略。", "始終誓復仇，志願久已確。", "浮家來水村，避亂畏矰繳。", "行矣收功名，遠過麒麟閣。", "氣投平生歡，事付今夕噱。", "吾衰世無用，鼓勇徒矍鑠。"]'),
('ffff2c06-fe88-4542-a513-56e9406059fe','七月三日雨不止後一日作','張元幹','宋','宋诗','song-poetry','','[]','暝色復已夕，雨聲全未疏。',120,'全唐诗/poet.song.102000.json','["暝色復已夕，雨聲全未疏。", "掩關頗嗜卧，篝燈空照書。", "點滴聞瓦溝，决溜鳴階渠。", "試作華屋想，未減嚴城居。", "大江洶波浪，曠野風號呼。", "那知三家村，有此一腐儒。", "是身在宇宙，何適非蘧廬。", "陵谷儻遷變，樓觀皆空虛。", "安心無秘法，絕念忘畏途。", "生死尚可處，此境固有餘。"]'),
('1c0cad1e-5c5f-4c8d-a9c8-f83783848a94','題王巖起樂齋','張元幹','宋','宋诗','song-poetry','','[]','宦遊適樂土，宴坐名樂齋。',96,'全唐诗/poet.song.102000.json','["宦遊適樂土，宴坐名樂齋。", "問君何獨樂，胸中高崔嵬。", "軒裳儻來物，世途吁可哀。", "紛然雞鶩爭，陷穽成禍胎。", "不如尋蠹魚，簡編閱興衰。", "萬事付杯酒，百年俱劫灰。", "搘頤忽長嘯，妙想從天回。", "人生行樂耳，勿爲華髮催。"]'),
('2f1bde30-50ad-4023-bf26-333baeadfa64','陪李仲輔昆仲宿惠山寺','張元幹','宋','宋诗','song-poetry','','[]','蒼山崷崒中，殿古起野色。',120,'全唐诗/poet.song.102000.json','["蒼山崷崒中，殿古起野色。", "仰空象緯高，撫事戎馬隔。", "三子俱人豪，語默有典則。", "安知今夕遊，值此老賓客。", "危言驚鬼神，懷舊痛京國。", "寄書白帝城，問道屈原宅。", "三春聞竹枝，萬里共悽惻。", "風來松柏悲，月落世界黑。", "相看炯不寐，袖手了無策。", "去去更酌泉，吾生易南北。"]'),
('dd7fb31b-ce5c-4cc3-b92e-1bff6b706de2','和韻奉酬王原父集福山之什','張元幹','宋','宋诗','song-poetry','','[]','平生契所崇，晚得故人語。',192,'全唐诗/poet.song.102000.json','["平生契所崇，晚得故人語。", "驚呼追曩遊，世道今如許。", "中原鞠茂草，萬里盡豺虎。", "天王巡江濆，對壘眺淮楚。", "未聞誅叛亡，快憤斷腰膂。", "上復九廟讐，下寬四民苦。", "胸中有成奏，無路不容吐。", "天高雲霧深，灑泣逃罪罟。", "朅來陪勝集，人物良可數。", "高氏父子賢，王甥兄弟窶。", "相過茶酒間，窮年簡編處。", "喪亂共傷時，興衰更懷古。", "假日聊銷憂，信美非吾土。", "夜闌然薪歸，被酒踏寒雨。", "買山結茅茨，我老竟何所。", "要當喬松根，白石仍同煮。"]'),
('f7851b31-1504-421a-ae45-1259783d985b','奉送真歇禪師往住阿育山兼簡黄檗雲峰諸老','張元幹','宋','宋诗','song-poetry','','[]','時流罕識真，特立取衆忌。',264,'全唐诗/poet.song.102000.json','["時流罕識真，特立取衆忌。", "不有明眼人，誰止萬口沸。", "古今冠蓋場，毀譽固一致。", "胡爲空門中，生滅亦滋熾。", "更憐晚學徒，遍參反諛媚。", "妄將宗派分，未必盡師志。", "要是鷹犬姿，乃出蛇鼠計。", "堂堂真歇師，的的示大意。", "所向古道場，衲子悉傾至。", "往年入吳閩，宴坐走檀施。", "繼踵幾尊宿，建立各超詣。", "南方祖令行，山川久增氣。", "乃知羣魔怖，不樂佛住世。", "休歇雲卧菴，謗焰息氛翳。", "欻然天門開，黄紙書廣利。", "萬態復現前，頗似厭權勢。", "去來初何心，緣感本自契。", "憫茲象衆衰，願力救深弊。", "維師法梁棟，世道貴相濟。", "露風吹海雲，瘴嶺發巖桂。", "欲挽衣裓留，意已萬里外。", "我老卜後期，夜話炯不寐。"]'),
('fd3bf8a6-7ef6-4088-8dcc-56af23d9a82a','送言上人往見徑山老十四韻','張元幹','宋','宋诗','song-poetry','','[]','忽辭鼓山行，便作徑山去。',168,'全唐诗/poet.song.102000.json','["忽辭鼓山行，便作徑山去。", "道人孤飛雲，腰包咄嗟具。", "兩邊兄弟間，楊岐一條路。", "禪許衆人參，院要大家住。", "無是亦無非，何喜復何怒。", "同粥鼓齋鐘，等燈籠露柱。", "佛眼接竹庵，雲門透圓悟。", "爾則有師承，心共成佛祖。", "可笑世上兒，妄念分毀譽。", "石火電光中，畢竟什麽處。", "所得能幾多，造業不知數。", "生死到頭來，請問末後句。", "窮漢未必窮，富漢豈真富。", "入門相見時，此話莫錯舉。"]'),
('3e12a552-35db-48fe-baaa-224704b4bc0b','建炎感事','張元幹','宋','宋诗','song-poetry','','[]','乾坤忽震蕩，土宇遂分裂。',288,'全唐诗/poet.song.102000.json','["乾坤忽震蕩，土宇遂分裂。", "殺氣西北來，遺毒成僭竊。", "議和其禍胎，割地亦覆轍。", "儻從种將軍，用武寨再劫。", "不放匹馬回，安得兩宮說。", "巍巍開國初，真宰創鴻業。", "一統包八荒，受降臨觀闕。", "并州稍稽命，駢頭亟膏鉞。", "於今何勢殊，天王狩明越。", "諸鎮本藩翰，楚破闔城血。", "翠輿欲東巡，蹈海計愈切。", "詔下散百司，恩許保妻妾。", "瞻彼廉陛尊，孰與壯班列。", "肉食知謀身，未省肯死節。", "檢校輿地圖，寧復見施設。", "三吳素輕浮，傷弓更心折。", "四顧皆驚波，蒼黄共嗚咽。", "維茲艱危秋，貧士轉疏拙。", "明年穀增貴，賢愚罔分別。", "何處置我家，患在建午月。", "故山盍早歸，豈憂踐霜雪。", "作意海邊來，初非事干謁。", "責我賣屋金，流言尚爲孽。", "汪公德甚大，遊說情激烈。"]'),
('afe71293-dc3e-40e4-8467-ff461fedb75c','奉同黄檗慧公秀峰昌公丁巳上元日訪鼓山珪公遊臨滄亭爲賦十四韻','張元幹','宋','宋诗','song-poetry','','[]','孤雲乘天風，飛入海上山。',168,'全唐诗/poet.song.102000.json','["孤雲乘天風，飛入海上山。", "松聲發鼓吹，導我登層巒。", "平生烟霞想，政在巖壑間。", "及茲百事懶，作意三日閑。", "聊將燒燈夜，付與兒輩看。", "來陪老禪伯，杖履同躋攀。", "曲折幾蘚磴，竹引春斕斑。", "竇口咽細泉，崖腹鳴飛瀾。", "足疲眼界遠，語樂心地安。", "倒景射西崦，晃蕩雲海寬。", "十年戎馬後，集此蘭若難。", "未必支許遊，能盡賓主歡。", "暝色到峰頂，月光散林端。", "摩挲忘歸石，告以幽遐觀。"]'),
('905ef63e-2d6a-4d09-8def-b86019418c00','九月一日與王季夷酌別爲賦十六韻','張元幹','宋','宋诗','song-poetry','','[]','黄鵠摶秋風，一舉輒萬里。',192,'全唐诗/poet.song.102000.json','["黄鵠摶秋風，一舉輒萬里。", "飛鳴蓬蒿間，燕雀徒爲爾。", "王郎志凌雲，英妙良可喜。", "片言隻字奇，採掇殊未已。", "樂從長者遊，論事亦亹亹。", "知我中原時，早與大門齒。", "流落天南端，相過不相鄙。", "乃翁四男兒，君蓋處其季。", "家世賢弟兄，自立要如是。", "古學儻有成，終身保無愧。", "陋哉斗筲人，惟見目前利。", "茲焉入三吳，索詩餞行李。", "何補僕馬饑，聊復慰深意。", "可同洪喬書，盡付浙江水。", "今夕燈燭凉，便當茱菊醉。", "畏途重語離，瓶卧莫遽起。"]'),
('38bc8992-b3b4-469a-83b5-6b269ba24e77','訪周元舉菁山隱居','張元幹','宋','宋诗','song-poetry','','[]','胸次飽丘壑，乃覺軒裳輕。',144,'全唐诗/poet.song.102000.json','["胸次飽丘壑，乃覺軒裳輕。", "舉世沈湎時，勇退公早醒。", "十年烟雨簑，手種松杉成。", "蒼根鬰寒霧，老色入戶庭。", "棲心不爭地，似欲畢此生。", "那知戎馬際，亦使山房驚。", "四海方蕩潏，積骸盈破城。", "公豈失策者，獨留枯槁形。", "賊舟會稍遠，請復安柴荆。", "暗泉雜夜雨，稚笋肥晨烹。", "起予歸去來，故山今可行。", "胡爲困羈旅，浩歎常吞聲。"]'),
('d85c9a04-8450-41fe-8a67-d20467687002','次仲彌性所知陳丈大卿韻','張元幹','宋','宋诗','song-poetry','','[]','伏波晚歲思少遊，萬事過眼如雲浮。',160,'全唐诗/poet.song.102000.json','["伏波晚歲思少遊，萬事過眼如雲浮。", "我生不樂城市隘，受性但愜林泉幽。", "稍同臭味自投合，肯與流俗相對酬。", "旅懷久已乏佳趣，白日政覺多閑愁。", "舂容大篇忽旁及，氣象楚澤涵新秋。", "律嚴雖許强續尾，韻險豈復能畫籌。", "逍遥一舸白太傅，蹴踏五字韋蘇州。", "主人頻誇小鬟舞，勸客且聽吳娃謳。", "從來誰數折巾郭，重到似是栽桃劉。", "夢入江湖渺春水，何如此念隨輕鷗。"]'),
('743e8369-8209-4cd8-b939-d8fef5e44a1f','東平劉左車坎止春歌','張元幹','宋','宋诗','song-poetry','','[]','先朝相國今幾家，我嗟夫子鬢已華。',128,'全唐诗/poet.song.102000.json','["先朝相國今幾家，我嗟夫子鬢已華。", "瓊艘頗慣倒膏乳，老來手釀尊仍窪。", "百年彈指法界觀，萬事過眼天女花。", "聊學兒曹作春甕，喚客取醉無等差。", "夜眠不覺體平粟，卯頰共眩朝蒸霞。", "養生妙處本無說，我輩豈解燒丹砂。", "糟床正可珠的皪，石鼎莫放聲咿啞。", "東風遮幕雪埋屋，坎止齋中酒初熟。"]'),
('3a221c28-6d68-44bf-ad7f-fe73ac7da967','送高集中赴漳浦宰','張元幹','宋','宋诗','song-poetry','','[]','三年烏石僧房居，忍饑待次真臞儒。',144,'全唐诗/poet.song.102000.json','["三年烏石僧房居，忍饑待次真臞儒。", "有意載酒問奇字，無事閉門抄異書。", "一行作吏去漳水，斂版趨廊參刺史。", "胸中豪氣半銷磨，稍覺風波生眼底。", "高郎高郎君莫嗔，舉世未有如君貧。", "毀官不復謁時宰，老大甘爲行路人。", "君今業已臨民社，辦取催科時下下。", "不然彭澤歸去來，簿領笞榜何爲哉。", "男兒策勳有時節，家世況自圖雲臺。"]'),
('bde08e88-cde3-44f9-a5d5-6abec0aec5e6','信中居仁叔正皆有詩訪梅於城西而獨未暇載酒分付老拙其敢不承','張元幹','宋','宋诗','song-poetry','','[]','關山往歲曾冰裂，跋馬平坡千樹雪。',160,'全唐诗/poet.song.102000.json','["關山往歲曾冰裂，跋馬平坡千樹雪。", "疏枝冷蕊最撩人，雪後生香微带月。", "醉中不數長短亭，狐裘擁鼻風前醒。", "十年喪亂豈記憶，一見新詩心目驚。", "平生公輩真豪友，意氣相投共杯酒。", "祇今流落天南端，悵望中原莫回首。", "及身强健頻看梅，此花到眼春光催。", "玉人風味正清絕，但欠雪月相徘徊。", "欲訪城西尋醉語，竹籬茅舍知何許。", "携壺藉草儻不嗔，便與此花長作主。"]'),
('2f762a0e-6105-4ec7-914f-c77e82d31e80','希道使君見遺古風謹次嚴韻','張元幹','宋','宋诗','song-poetry','','[]','君侯氣挾飛仙骨，插腦伏犀高崒屼。',128,'全唐诗/poet.song.102000.json','["君侯氣挾飛仙骨，插腦伏犀高崒屼。", "榮枯過眼海一漚，出處何心兔三窟。", "養生得趣喜按摩，子夜不眠頻叱咄。", "枕中玉函妙以微，肘後金精恍兮惚。", "我真蒲柳欲師承，刻畫無鹽恐唐突。", "似聞有意贈刀圭，倒卷逆流翻澥渤。", "世間萬態古今同，政可忘言佯吃訥。", "杖藜未辦飲菊潭，且看冥鴻秋滅沒。"]'),
('b2c87c6b-a0b3-408b-92ab-a541c36f73f9','葉少藴生朝','張元幹','宋','宋诗','song-poetry','','[]','先生早貴當天升，文章爾雅傳六經。',384,'全唐诗/poet.song.102000.json','["先生早貴當天升，文章爾雅傳六經。", "腹包萬卷書縱橫，玉堂草制羣公驚。", "繡韉綠髮趨承明，意氣已向沙堤行。", "出入四紀更寵榮，聲華摩空鬰崢嶸。", "坐嘯十郡歷九卿，視公進退爲重輕。", "聖神天子開延英，丞轄政地思儀型。", "中開香火祠殊庭，石林高卧憂蒼生。", "五載筦鑰司陪京，貔貅百萬環屯營。", "大江千里依長城，控制勍敵堅其盟。", "詔書移鎮來旆旌，山川草木知威名。", "潢池桴鼓令不鳴，盡歸戲下息鬬爭。", "維師鷹揚宇宙清，指顧號令驅風霆。", "小試擒縱孰敢攖，部曲愛戴如父兄。", "太阿龍泉發新硎，逆順之勢如建瓴。", "綸巾羽扇寬作程，韜略堂堂時俗評。", "乞師未用牛酒迎，胸次自有堂上兵。", "姦宄革面輸忠誠，碧海不復鱷鯢腥。", "細數前輩存典刑，爛爛伴月唯長庚。", "歲時建巳嶽降靈，三奇天運乙丙丁。", "良辰樂事非難并，香凝燕寢合鼓笙。", "舞翻流雪歌囀鶯，兒孫遶膝奉兕觥。", "安輿綵服壽且寧，五福共應南極星。", "龐眉鶴骨超籛鏗，清都絳闕吞蓬瀛。", "明年正拜居阿衡，爐錘造化推至誠。"]'),
('503a9b1e-acb5-4611-9a15-e436b934b9d1','賦漳南李幾仲安齋詩','張元幹','宋','宋诗','song-poetry','','[]','羔豚蒸乳活臠牛，口腹造業誇炰羞。',160,'全唐诗/poet.song.102000.json','["羔豚蒸乳活臠牛，口腹造業誇炰羞。", "儻知晚食足當肉，一飽何苦多營求。", "先生睡美黑甜處，那聞鐘鼓朝鳴樓。", "布衾竹枕自穩暖，此念灰冷百不憂。", "世間寢食乃日用，衆生擾擾如蚍蜉。", "昔年我亦走南北，往反萬里無停輈。", "胸中不作異鄉縣，有似坐閱十數州。", "雲山渾如舊過眼，歲月不覺春已秋。", "宿君齋屋亦偶爾，更僕笑語久未休。", "夜闌各困且打睡，明日饑飽臨時謀。"]'),
('737e5461-4f94-474f-b102-9d18309ac119','次韻奉酬楞伽室老人歌寄懷雲門佛日兼簡乾元老珪公并敘鍾山二十年事可謂趁韻也','張元幹','宋','宋诗','song-poetry','','[]','雲門道價傾緇白，一去如何經書尺。',128,'全唐诗/poet.song.102000.json','["雲門道價傾緇白，一去如何經書尺。", "乾竺宗旨超隱峰，客至不鳴齋後鐘。", "楊岐兒孫真鐵脊，二子等是僧中龍。", "平生我如拆韈線，老來要認本來面。", "憶昨二老初相知，竹爐擁衲清夜圍。", "佛眼霜顱象懶瓚，圜悟辨口吞韓非。", "鍾山往事無人識，我識二子因師得。", "楞伽一句作麽生，請問同參俱本色。"]'),
('ded7fd3d-5d81-4510-9ed2-2c1a5b804582','贈慶紹上人','張元幹','宋','宋诗','song-poetry','','[]','上人久住湖外遊，辛亥春陷孔彥舟。',288,'全唐诗/poet.song.102000.json','["上人久住湖外遊，辛亥春陷孔彥舟。", "長沙城中就驅掠，七十七日遭拘留。", "眼看殺人等螻蟻，劍血洗盡湘川流。", "張帆方離道林岸，鼓枻已過巴陵樓。", "兵纏妖氣草木暗，火熾凶焰雲烟愁。", "衣冠子女半同載，俛首悲泣猶驚羞。", "蒙衝頗諳大風浪，舴艋或掛長戈矛。", "兩舷矢集鬧如雨，勢欲欹側爭先投。", "相牽浮湛狀菱荇，乍墜出沒真鳧鷗。", "衆生流浪幾生死，愛河苦海何時休。", "曹成馬友互屠滅，偶爾不殺老比丘。", "枯顱茁髮蟣蝨滿，得脫性命非人謀。", "孰知賊黨亦方便，日供齋鉢仍茶甌。", "南歸數年閉戶卧，故山精舍松颼颼。", "灰心一切本夢幻，返照逆照無人牛。", "細聽此語重歎息，羣盜掃迹夫何憂。", "吾閩目前豈不樂，禾稻未穫先麥秋。", "師來訪我問居士，我若訪師尋浄頭。"]'),
('9341994c-62d5-435a-9f04-5993a51c966b','西峽行','張元幹','宋','宋诗','song-poetry','','[]','西峽門東晚潮上，濤頭駕風高數丈。',160,'全唐诗/poet.song.102000.json','["西峽門東晚潮上，濤頭駕風高數丈。", "絕江艇子更揚帆，風水相吞兩岸壯。", "中流蕩潏思慮深，欲濟未竟愁夕陰。", "賈客胡商數航海，忍死射利誠何心。", "不如遵陸困輿皂，九折羊腸復相惱。", "下臨湍瀨千仞淵，胥靡輕生履危道。", "我曹過計常私憂，垂堂之戒寧自尤。", "經營一飽亦細事，世亂畏塗歸罷休。", "少年新進真兒劇，浪喜功名不量力。", "殺身無補誤朝廷，天下英雄古難得。"]'),
('ae3dbc0b-56c1-45a2-bbc9-3409c68c9c77','奉送李叔易博士被召赴行在所','張元幹','宋','宋诗','song-poetry','','[]','君嘗手校輿地圖，上下千載鉛黄朱。',354,'全唐诗/poet.song.102000.json','["君嘗手校輿地圖，上下千載鉛黄朱。", "斯人魁磊豈假此，願見尅復東西都。", "胸中遠略指諸掌，表裏拄腹撐腸書。", "深知禍起取幽薊，頗覺氣王吞青徐。", "眼看僭僞忽亡滅，逆黨未足勞誅鋤。", "萬方助順事可卜，火運要是穹蒼扶。", "興衰撥亂戴真主，會掃氛祲開雲衢。", "於今荆淮付諸將，控带川陜襟江湖。", "儻能倒用進築法，更許世襲宏規模。", "兩河境土不難辦，狡寇膽落遊魂孤。", "古今徒聞作戎首，中國禮義終如初。", "公家自有中興相，雅意泰階光六符。", "難兄難弟實間出，直欲並駕仍齊驅。", "承明入謁一見决，三遷故事登元樞。", "整頓乾坤賴公等，我病只合山林居。", "殘年正爾甚易與，不過二頃鄰一區。", "平生故人半廊廟，老僧何患無門徒。", "與君痛飲遽成別，努力强飯供時須。", "男兒富貴亦細事，否泰相反分賢愚。", "酒酣起舞莫作惡，行矣自愛千金軀。", "本朝再造舊基業，速拯塗炭疲氓蘇。", "勿令毫髮有遺恨，文章爾雅華國猶其餘。"]'),
('692a6421-8fca-44e3-9d94-34591615778a','拜顔魯公像','張元幹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吳興祠堂祀百世，凜凜英姿有生意。',176,'全唐诗/poet.song.102000.json','["吳興祠堂祀百世，凜凜英姿有生意。", "坐令異代乾沒兒，莫敢徜徉來仰視。", "唐家綱紀日陵遲，僭竊相連益昌熾。", "我公人物第一流，皇天后土明忠義。", "屹然砥柱立頹波，未覺羊腸隳坦履。", "欲回希烈叛逆心，老夫但知朝覲禮。", "年垂八十位太師，平生所欠惟死耳。", "死重泰山古所難，杞鬼竊柄猶偷安。", "安知我公本不死，汝曹有知當骨寒。", "豐碑法書屋漏雨，政與丹青照千古。", "天遣神物常守護，要使亂臣賊子懼。"]'),
('8489c158-03a8-411f-b44a-55cce4678dbb','祥符陵老許作先馳歸閩因成伽陀贈別紹興甲戌秋七月書於鶴林山','張元幹','宋','宋诗','song-poetry','','[]','無量劫來幾相見，莫話南州與北縣。',64,'全唐诗/poet.song.102000.json','["無量劫來幾相見，莫話南州與北縣。", "居士向來業風吹，自合失却本來面。", "今年坐夏在鶴林，許我先馳海舟便。", "三山到日已秋深，且看山門騎佛殿。"]'),
('69aabadb-71bd-4174-aee8-7e47b1ce18f8','次韻唐彥猷所題顧野王祠與霍子孟廟對','張元幹','宋','宋诗','song-poetry','','[]','蘭若黄門像，相望博陸居。',48,'全唐诗/poet.song.102000.json','["蘭若黄門像，相望博陸居。", "衣冠塵亦暗，簫鼓祭全疏。", "草色侵荒逕，潮聲過夕墟。", "遺風猶可想，弔古一觴餘。"]'),
('72e321b2-5e43-44c9-a3f6-81c204aa4062','過宿趙次張郊居二首  其一','張元幹','宋','宋诗','song-poetry','','[]','北客多流落，東村更寂寥。',48,'全唐诗/poet.song.102000.json','["北客多流落，東村更寂寥。", "肯同清夜夢，不待故人招。", "月挂荒園竹，霜飛獨木橋。", "聽雞休起舞，且共論天驕。"]'),
('5d34ad71-5137-4aab-8e67-fd82e29c4066','過宿趙次張郊居二首  其二','張元幹','宋','宋诗','song-poetry','','[]','莫歎交遊晚，相期歲月深。',48,'全唐诗/poet.song.102000.json','["莫歎交遊晚，相期歲月深。", "秋來初識面，老去要知心。", "燈火須更僕，杯盤取自斟。", "平生王霸術，袖手有微吟。"]'),
('fff7941d-3665-462a-9ac5-efc925afdcf7','次韻奉和平叔亭林至日之什','張元幹','宋','宋诗','song-poetry','','[]','雲物果何好，客愁今更新。',48,'全唐诗/poet.song.102000.json','["雲物果何好，客愁今更新。", "坐來江月白，興在雪籬春。", "我輩且同酌，公詩殊出塵。", "莫思淮海上，黑幟雜黄巾。"]'),
('a647f089-f5e5-4be1-8431-ad82434787eb','花飛','張元幹','宋','宋诗','song-poetry','','[]','雨暗連兵氣，花飛點客愁。',48,'全唐诗/poet.song.102000.json','["雨暗連兵氣，花飛點客愁。", "寓居皆野寺，相過只扁舟。", "不作新塘去，還爲後泖遊。", "盤飧雖杞菊，得飽勝椎牛。"]'),
('60bdc95b-4ae4-4f81-8a15-d2247e8dc312','送江子我歸嚴陵','張元幹','宋','宋诗','song-poetry','','[]','久客驚秋晚，懷歸更送君。',48,'全唐诗/poet.song.102000.json','["久客驚秋晚，懷歸更送君。", "亂來俱避地，老去惜離羣。", "山閣杯浮菊，江城雁度雲。", "行行經釣瀨，時事不須聞。"]'),
('1d9bd532-08ce-436e-bdb6-768dff0d3d43','亂後','張元幹','宋','宋诗','song-poetry','','[]','亂後今誰在，年來事可傷。',48,'全唐诗/poet.song.102000.json','["亂後今誰在，年來事可傷。", "雲深懷故里，春老尚他鄉。", "寧復論秦過，終當作楚狂。", "維舟短籬下，聊學捕魚郎。"]'),
('59368f9c-7520-4143-83ca-b97634c09da5','返正','張元幹','宋','宋诗','song-poetry','','[]','諸將爭傳檄，羣凶尚阻兵。',48,'全唐诗/poet.song.102000.json','["諸將爭傳檄，羣凶尚阻兵。", "天旋黄屋正，日轉赤墀明。", "喪亂多妖孽，經綸貴老成。", "鯨鯢終必戮，草木已知生。"]'),
('c56d870c-2d6d-47db-903b-bbea2e9321f3','冬夜有懷柯田山人四首  其一','張元幹','宋','宋诗','song-poetry','','[]','聞說新居好，山樊卜築深。',48,'全唐诗/poet.song.102000.json','["聞說新居好，山樊卜築深。", "藥囊能濟物，龜策少知音。", "四海憂黔首，中原盡綠林。", "直須期雪屋，夜棹去相尋。"]'),
('339844ba-225e-40da-87cb-d59384470d87','冬夜有懷柯田山人四首  其二','張元幹','宋','宋诗','song-poetry','','[]','坐閱干戈擾，輸公已定居。',48,'全唐诗/poet.song.102000.json','["坐閱干戈擾，輸公已定居。", "生涯今易足，世態莫嗔渠。", "晷短全疏客，窗晴好對書。", "故山常入夢，何日到吾廬。"]'),
('57776aa9-7b43-4c77-82ff-9c03ab8a04b9','冬夜有懷柯田山人四首  其三','張元幹','宋','宋诗','song-poetry','','[]','客裏了無况，亂來何止貧。',48,'全唐诗/poet.song.102000.json','["客裏了無况，亂來何止貧。", "淹留頻換歲，老大更思親。", "泥飲思田父，供糧乏故人。", "自憐歸未得，不是白頭新。"]'),
('3f41a8ec-725a-49fb-bbf8-0026689c8230','冬夜有懷柯田山人四首  其四','張元幹','宋','宋诗','song-poetry','','[]','雅欲賦招隱，何堪弔戰場。',48,'全唐诗/poet.song.102000.json','["雅欲賦招隱，何堪弔戰場。", "獨看星錯落，久立夜蒼茫。", "羽檄來東越，風煙隔下塘。", "安閑隨處有，冠蓋莫相望。"]'),
('23c0567f-ca87-4cb8-87bc-42cc145a0ca7','登垂虹亭二首  其一','張元幹','宋','宋诗','song-poetry','','[]','一別三吳地，重來二十年。',48,'全唐诗/poet.song.102000.json','["一別三吳地，重來二十年。", "瘡痍兵火後，花石稻粱先。", "山暗松江雨，波吞震澤天。", "扁舟莫浪發，蛟鰐正垂涎。"]'),
('abfc1578-f6cc-44b3-a513-4c4f45d8a60e','登垂虹亭二首  其二','張元幹','宋','宋诗','song-poetry','','[]','熠熠流螢火，垂垂倒飲虹。',48,'全唐诗/poet.song.102000.json','["熠熠流螢火，垂垂倒飲虹。", "行雲吞皎月，飛電掃長空。", "壯觀江邊雨，醒人水上風。", "須臾風雨過，萬事笑談中。"]'),
('a0a0520e-f82d-4879-86e1-779aaaabdb3a','送趙公遠往建康','張元幹','宋','宋诗','song-poetry','','[]','王孫朝謁去，功業歎流年。',48,'全唐诗/poet.song.102000.json','["王孫朝謁去，功業歎流年。", "强項今三已，棲遲未九遷。", "笑談曾擊賊，謀畧合臨邊。", "秋雨長干路，歸時且著鞭。"]'),
('82c08dd2-ba20-4097-b50f-8498fbe61a80','偶成寄友人','張元幹','宋','宋诗','song-poetry','','[]','萬里天南客，三年日至歸。',48,'全唐诗/poet.song.102000.json','["萬里天南客，三年日至歸。", "羣陰雖久否，吾道豈終微。", "顧我民稱逸，如君遁正肥。", "鯨魚波浪穩，雲翼有時飛。"]'),
('388aa528-0016-4ed8-9996-193a6e8a43c8','感事四首丙午冬淮上作  其一','張元幹','宋','宋诗','song-poetry','','[]','國步何多難，天驕據孟津。',48,'全唐诗/poet.song.102000.json','["國步何多難，天驕據孟津。", "焦勞唯聖主，遊說盡姦臣。", "再造今誰力，重圍忌太頻。", "風吹遷客淚，爲灑屬車塵。"]'),
('10b99029-038f-4a4e-bd79-287fe6e416fc','感事四首丙午冬淮上作  其二','張元幹','宋','宋诗','song-poetry','','[]','血灑三城渡，心寒粘罕兵。',48,'全唐诗/poet.song.102000.json','["血灑三城渡，心寒粘罕兵。", "洛師聞已破，陵邑得無驚。", "憤切吞妖孽，悲凉托聖明。", "本朝仁澤厚，會復見承平。"]'),
('11d873bb-a796-4bf2-9469-365a60e7b51a','感事四首丙午冬淮上作  其三','張元幹','宋','宋诗','song-poetry','','[]','賊馬環京洛，朝廷尚議和。',48,'全唐诗/poet.song.102000.json','["賊馬環京洛，朝廷尚議和。", "傷心聞徇地，痛恨競投戈。", "始望全三鎮，誰謀棄兩河。", "羣凶未葅醢，吾合老江波。"]'),
('800182f3-8626-4b1f-9859-5e6b77c6dccf','感事四首丙午冬淮上作  其四','張元幹','宋','宋诗','song-poetry','','[]','肉食貪謀己，幾成國與人。',48,'全唐诗/poet.song.102000.json','["肉食貪謀己，幾成國與人。", "珠旒輕遺賊，玉冊忍稱臣。", "四海皆流涕，三軍盍奮身。", "不堪宗社辱，一戰靖邊塵。"]'),
('d0ae4798-5c29-437a-a9ff-ede1e107d364','丙午春京城圍解口號','張元幹','宋','宋诗','song-poetry','','[]','戎馬來何速，春壕綠自深。',48,'全唐诗/poet.song.102000.json','["戎馬來何速，春壕綠自深。", "要知龍虎踞，不受犬羊侵。", "九廟安全日，三軍死守心。", "儻爲襄漢幸，按堵見於今。"]'),
('24f13975-4341-4186-88ac-193085f05dfe','漫興','張元幹','宋','宋诗','song-poetry','','[]','老答書題懶，貧營口腹忙。',48,'全唐诗/poet.song.102000.json','["老答書題懶，貧營口腹忙。", "未能忘壯志，詎肯變剛腸。", "晷短催寒急，燈明伴漏長。", "床頭褚衾在，不怕滿檐霜。"]'),
('1c64682c-a293-4e9e-891a-9bac46dc6b42','奉送富修仲赴南昌尉','張元幹','宋','宋诗','song-poetry','','[]','吏道雖餘事，人情要飽諳。',48,'全唐诗/poet.song.102000.json','["吏道雖餘事，人情要飽諳。", "家風端自守，句法有同參。", "南浦翻雲浪，西山滴翠嵐。", "折腰與趨走，政恐未能堪。"]'),
('8fba625c-5e92-4034-a4fe-86bba25bda65','夜宿宗公丈室求詩甚勤爲賦五字','張元幹','宋','宋诗','song-poetry','','[]','林表登層閣，秋聲隱暮鐘。',48,'全唐诗/poet.song.102000.json','["林表登層閣，秋聲隱暮鐘。", "鴉歸苦竹寺，雨闇亂雲峯。", "屢乞留新句，重來訪舊蹤。", "松門罕車馬，似喜老夫逢。"]'),
('9fd8bd47-5cfb-4a6a-af1a-8f6a72f010e1','范才元參議求酒於延平使君邀予同賦謹次其韻','張元幹','宋','宋诗','song-poetry','','[]','桑落冷篘玉，菊籬霜著天。',48,'全唐诗/poet.song.102000.json','["桑落冷篘玉，菊籬霜著天。", "飄零河朔飲，悵望竹林賢。", "烏有防前轍，青州貴下田。", "使君能遣騎，端爲喚魚船。"]'),
('325dc57b-f9fa-41f7-941c-96baac0cf98b','次韻晁伯南飲董彥達官舍心遠堂','張元幹','宋','宋诗','song-poetry','','[]','今夕知何夕，真成累十觴。',48,'全唐诗/poet.song.102000.json','["今夕知何夕，真成累十觴。", "爐薰飄月影，蜜炬剪花香。", "政懶還詩債，無從發酒狂。", "故人憐久客，舞袖要須長。"]'),
('98fbe348-51ac-4ee7-a771-5450bd195149','喜錢申伯病起二首  其一','張元幹','宋','宋诗','song-poetry','','[]','一室維摩老，長年法喜遊。',48,'全唐诗/poet.song.102000.json','["一室維摩老，長年法喜遊。", "苦心翻貝葉，癡坐寫蠅頭。", "可是文園病，何堪杞國憂。", "我知公健在，骨相合封侯。"]'),
('9d911974-c4b9-422e-995e-5074201d9bfc','喜錢申伯病起二首  其二','張元幹','宋','宋诗','song-poetry','','[]','花飛傷宿雨，山潤照清晨。',48,'全唐诗/poet.song.102000.json','["花飛傷宿雨，山潤照清晨。", "念子經時卧，嗟予一味貧。", "稍聞疏藥餌，遐想整衣巾。", "何日扶藜出，相陪醉晚春。"]'),
('50c263e4-2915-4275-a847-c988e51e6143','叔易自三歸吳同赴竹菴荔子之集二首  其一','張元幹','宋','宋诗','song-poetry','','[]','惜別梅花雨，來歸荔子秋。',48,'全唐诗/poet.song.102000.json','["惜別梅花雨，來歸荔子秋。", "江帆成昨夢，雲嶠忽重遊。", "共喜身長健，寧論客久愁。", "殷勤老居士，更爲寶峯留。"]'),
('eb5996ea-9fb2-4114-8c45-531e5c2f80bc','叔易自三歸吳同赴竹菴荔子之集二首  其二','張元幹','宋','宋诗','song-poetry','','[]','客去雲俱散，山空月正圓。',48,'全唐诗/poet.song.102000.json','["客去雲俱散，山空月正圓。", "不參藤樹句，自透竹菴禪。", "骨法凌煙像，家聲鼓瑟篇。", "直須陪叔季，急佐中興年。"]'),
('dec60a2d-6fbb-42fd-a5df-991ac8d0d28b','寄錢申伯二首  其一','張元幹','宋','宋诗','song-poetry','','[]','子去客昭武，今儂懷舊遊。',48,'全唐诗/poet.song.102000.json','["子去客昭武，今儂懷舊遊。", "青山渾在眼，白髮暗添頭。", "旅食今安好，歸程儻滯留。", "溪邊因野步，試覓水明樓。"]'),
('7bc3ac36-e553-4550-9aa8-439ff813e65e','寄錢申伯二首  其二','張元幹','宋','宋诗','song-poetry','','[]','一點照今古，胸中殊了然。',48,'全唐诗/poet.song.102000.json','["一點照今古，胸中殊了然。", "不妨爲漫吏，可但號臞仙。", "丹荔盟猶在，凝香句未傳。", "秋風稍凉冷，速辦下灘船。"]'),
('a33e59ae-c490-4a7f-84fd-e8a317866430','真歇老人退居東庵予過雪峰特訪之爲留再宿仍賦兩詩  其一','張元幹','宋','宋诗','song-poetry','','[]','雲卧孤峯頂，齋餘閉戶眠。',48,'全唐诗/poet.song.102000.json','["雲卧孤峯頂，齋餘閉戶眠。", "時容龍象衆，來說葛藤禪。", "此日輸真歇，平生最信緣。", "從渠魔起謗，把火漫燒天。"]'),
('ed816c6d-cb3c-44d1-b261-3f9c13540e56','真歇老人退居東庵予過雪峰特訪之爲留再宿仍賦兩詩  其二','張元幹','宋','宋诗','song-poetry','','[]','山月轉松影，澗泉鳴夜窗。',48,'全唐诗/poet.song.102000.json','["山月轉松影，澗泉鳴夜窗。", "清談虎溪遠，癡坐鹿門龐。", "敵國終亡滅，邊城合受降。", "晨鐘發秋思，同夢繞三江。"]'),
('fadcbefa-9a1e-415d-83c3-b5e020b725d3','解嘲示真歇老人二首  其一','張元幹','宋','宋诗','song-poetry','','[]','不作市朝夢，生憎城郭居。',48,'全唐诗/poet.song.102000.json','["不作市朝夢，生憎城郭居。", "前身真衲子，妄念入儒書。", "丘壑無疑老，軒裳久已疏。", "世人多大屋，爭笑賣吾廬。"]'),
('8e4833dc-b93c-40ff-9839-d460f781e84b','解嘲示真歇老人二首  其二','張元幹','宋','宋诗','song-poetry','','[]','毀譽何時了，雞蟲事可知。',48,'全唐诗/poet.song.102000.json','["毀譽何時了，雞蟲事可知。", "不妨遭點檢，好在莫相疑。", "高爵非吾性，奇勳任爾爲。", "道人元具眼，批判亦慈悲。"]'),
('6556942a-f901-467a-b4ee-c0d99f9fba6d','申伯有行色會宿東禪次元韻','張元幹','宋','宋诗','song-poetry','','[]','真成風雨夜，精舍對床眠。',48,'全唐诗/poet.song.102000.json','["真成風雨夜，精舍對床眠。", "去住非無數，行藏莫問天。", "十年瀕瘴海，一棹破春煙。", "君自足歸興，不妨啼杜鵑。"]'),
('649b3f1a-c96a-4f83-b630-10b5f5e1090c','次折樞留題雪峰韻','張元幹','宋','宋诗','song-poetry','','[]','軒冕本無意，煙霞如有期。',48,'全唐诗/poet.song.102000.json','["軒冕本無意，煙霞如有期。", "故人容野老，勝踐見新詩。", "誰辦兼忘世，公當急濟時。", "春歸仍送別，好在出山遲。"]'),
('4d0a59ad-1f55-49da-8d5a-80eef35bf3bc','次韻范才元中秋不見月','張元幹','宋','宋诗','song-poetry','','[]','不見中秋月，長吟五字城。',48,'全唐诗/poet.song.102000.json','["不見中秋月，長吟五字城。", "浮雲有底急，清影可憐生。", "殘夜四更句，故人千里情。", "與君同悵望，天上自分明。"]'),
('8d80ab7d-26b6-4dfe-90c8-4d69d60c1508','次呂居仁見寄韻','張元幹','宋','宋诗','song-poetry','','[]','老去猶爲客，誰人念退居。',48,'全唐诗/poet.song.102000.json','["老去猶爲客，誰人念退居。", "相望千里路，賴有數行書。", "白曬猶堪寄，烏牛政憶渠。", "何時聞枉駕，竹裏喚行厨。"]'),
('5ce86963-8b80-4de6-a7ad-d9e0f237f3ea','次韻劉希顔感懷二首  其一','張元幹','宋','宋诗','song-poetry','','[]','春光垂老日，北騎欲歸時。',48,'全唐诗/poet.song.102000.json','["春光垂老日，北騎欲歸時。", "王氣如三捷，懽聲定四馳。", "山河還舊貫，草木有餘悲。", "擬頌中興業，孤忠只自知。"]'),
('cf5a474b-19a3-4797-a6d8-8b10c5befb9b','次韻劉希顔感懷二首  其二','張元幹','宋','宋诗','song-poetry','','[]','避謗疏毛穎，推愁賴索郎。',48,'全唐诗/poet.song.102000.json','["避謗疏毛穎，推愁賴索郎。", "坐來春漏促，夢去畏途長。", "故國書題冷，新詩齒頰香。", "湖山雖好在，歲月已相忘。"]'),
('2987c8a5-bf22-4071-a26d-9515ac364018','郭從範示及張安國諸公酬唱輒次嚴韻','張元幹','宋','宋诗','song-poetry','','[]','登樓乘暇日，喚客共澆愁。',48,'全唐诗/poet.song.102000.json','["登樓乘暇日，喚客共澆愁。", "春去花猶發，陰濃雨未休。", "和詩真冷澹，得句總風流。", "能遣西鄰老，殊無陋巷憂。"]'),
('17492980-d3d5-4307-957d-587c0571d27f','上張丞相十首  其一','張元幹','宋','宋诗','song-poetry','','[]','閩粵諸侯地，春風盡去思。',48,'全唐诗/poet.song.102000.json','["閩粵諸侯地，春風盡去思。", "三年歌德政，萬戶繪生祠。", "位極聊方伯，謀深必帝師。", "待公安社稷，四海被恩私。"]'),
('eeed93c9-1993-433a-92e9-9b4f355f97b4','上張丞相十首  其二','張元幹','宋','宋诗','song-poetry','','[]','廣漢家山遠，臨川道路旁。',48,'全唐诗/poet.song.102000.json','["廣漢家山遠，臨川道路旁。", "安輿懷故壘，同氣聽甘棠。", "雪後風煙潤，春歸草木香。", "丹心馳魏闕，夢想萬年觴。"]'),
('90dc0014-3363-4a05-aa07-72d61056ac2c','上張丞相十首  其三','張元幹','宋','宋诗','song-poetry','','[]','活國勳奇甚，平戎志未衰。',48,'全唐诗/poet.song.102000.json','["活國勳奇甚，平戎志未衰。", "肯從時論屈，自許世人知。", "豹尾遥臨鎮，蟬冠暫祝釐。", "天將擒頡利，露布捨公誰。"]'),
('dce7f3a7-dd0f-4670-9237-1f08bf956a50','上張丞相十首  其四','張元幹','宋','宋诗','song-poetry','','[]','百六古今有，兩宮開闢無。',48,'全唐诗/poet.song.102000.json','["百六古今有，兩宮開闢無。", "興師誠刷耻，奮袂競捐軀。", "必挾三靈助，能令萬國孚。", "九宮驅六甲，何患五單于。"]'),
('09aa8d00-cb90-43da-bc66-417c80c98a48','上張丞相十首  其五','張元幹','宋','宋诗','song-poetry','','[]','蠢爾天驕子，中原禍太深。',48,'全唐诗/poet.song.102000.json','["蠢爾天驕子，中原禍太深。", "野心殊叵測，內地任頻侵。", "日昃那常晦，陽生自剝陰。", "德光非不僭，終識殺狐林。"]'),
('73ebf568-6c54-4716-981e-9eb58b74be73','上張丞相十首  其六','張元幹','宋','宋诗','song-poetry','','[]','國士多孤憤，君侯特長雄。',48,'全唐诗/poet.song.102000.json','["國士多孤憤，君侯特長雄。", "玉墀曾復辟，鐵券會論功。", "宇宙尊文物，華夷界土風。", "力扶炎運正，此意合蒼穹。"]'),
('b33f1e08-2344-4254-a9e2-7b895cd95b94','上張丞相十首  其七','張元幹','宋','宋诗','song-poetry','','[]','衮繡春秋富，旂常事業新。',48,'全唐诗/poet.song.102000.json','["衮繡春秋富，旂常事業新。", "三遷推孟母，一德表商臣。", "任重能知止，功成合保身。", "儻容陪几杖，同訪赤松人。"]'),
('08f7661f-dba6-4162-aa91-7112f5e9f8df','上張丞相十首  其八','張元幹','宋','宋诗','song-poetry','','[]','賤子居閭里，明公總帥權。',48,'全唐诗/poet.song.102000.json','["賤子居閭里，明公總帥權。", "姓名誰比數，禮遇每周旋。", "老去無三窟，閑中有二天。", "知音何日報，願見中興年。"]'),
('fa489d62-b7ab-42a9-af33-3197536b5f88','上張丞相十首  其九','張元幹','宋','宋诗','song-poetry','','[]','罪放丙午末，歸來辛亥初。',48,'全唐诗/poet.song.102000.json','["罪放丙午末，歸來辛亥初。", "不談天下事，猶誦古人書。", "利病明諸掌，危疑儆後車。", "他時果無悔，載籍定欺予。"]'),
('d1124225-ea38-472c-9d01-967ae8fd45eb','上張丞相十首  其一○','張元幹','宋','宋诗','song-poetry','','[]','簪紱久已棄，行裝今甚疲。',48,'全唐诗/poet.song.102000.json','["簪紱久已棄，行裝今甚疲。", "買山如畧辦，畢娶更奚爲。", "小築開三徑，躬耕趁一犁。", "賴公霖雨手，忍賦語離詩。"]'),
('2fb1751e-c157-4c67-8321-aeadff716c89','送李文中主簿受代歸庭闈','張元幹','宋','宋诗','song-poetry','','[]','豹隱猶遮霧，鸞棲遂及瓜。',48,'全唐诗/poet.song.102000.json','["豹隱猶遮霧，鸞棲遂及瓜。", "綠林方在境，綵服徑還家。", "世路久來險，人情何用嗟。", "胸中自丘壑，樂處是生涯。"]'),
('b8b433a9-2040-4c34-80bd-203bc4470e13','戊辰春二月晦日同棲鸞子送所親過寶積題壁間','張元幹','宋','宋诗','song-poetry','','[]','春江因送客，雲嶠更登臨。',48,'全唐诗/poet.song.102000.json','["春江因送客，雲嶠更登臨。", "精舍經行地，征人去住心。", "猿啼清夢斷，花落曉窗陰。", "勝踐成三宿，俱來此意深。"]'),
('5be5550d-d24f-4d6c-a5af-6fe3eb2b7e34','代上張丞相生朝四首  其一','張元幹','宋','宋诗','song-poetry','','[]','上相生坤位，中興運泰開。',48,'全唐诗/poet.song.102000.json','["上相生坤位，中興運泰開。", "德威加異域，文武屬全才。", "南極星躔煥，東方騎氣來。", "下車逢誕日，喜色照樽罍。"]'),
('d99ad9eb-f7e6-473d-963a-073d4e9cbc86','代上張丞相生朝四首  其二','張元幹','宋','宋诗','song-poetry','','[]','奇勳施社稷，萬世許忠嘉。',48,'全唐诗/poet.song.102000.json','["奇勳施社稷，萬世許忠嘉。", "賓日扶神器，回天坐正衙。", "貂蟬峨上衮，鞀鼓擁高牙。", "暫屈臨閩粵，重聞降白麻。"]'),
('e57045eb-9fcf-4da9-9a6f-384fde7cca1a','代上張丞相生朝四首  其三','張元幹','宋','宋诗','song-poetry','','[]','坤維標厚載，任重出宗臣。',48,'全唐诗/poet.song.102000.json','["坤維標厚載，任重出宗臣。", "眉宇如虹氣，儀形似玉人。", "中興真有相，命世必逢辰。", "霖雨聊均逸，餘波潤七閩。"]'),
('d70cbd3e-af9b-418b-8d4b-a7575d7e80cd','代上張丞相生朝四首  其四','張元幹','宋','宋诗','song-poetry','','[]','將相兼文武，謙光接下僚。',48,'全唐诗/poet.song.102000.json','["將相兼文武，謙光接下僚。", "輿情爭快覩，善頌適生朝。", "勳業當興宋，謀猷永佐堯。", "千秋迎壽母，忠孝稱金貂。"]'),
('68b6689e-a2f1-4a38-b055-d812ac33cddc','李丞相綱生朝三首  其一','張元幹','宋','宋诗','song-poetry','','[]','炎景生賢佐，三朝火王時。',48,'全唐诗/poet.song.102000.json','["炎景生賢佐，三朝火王時。", "德威雖敵畏，忠藎只天知。", "安國驚何久，收功會有期。", "他年調鼎地，黄髮屬公師。"]'),
('be61bfda-ae38-4010-baa4-bad635a77eb8','李丞相綱生朝三首  其二','張元幹','宋','宋诗','song-poetry','','[]','戡亂登廊廟，羣公數靖康。',48,'全唐诗/poet.song.102000.json','["戡亂登廊廟，羣公數靖康。", "一身輕去就，百口恃安强。", "天意非難見，人情漫自凉。", "殷勤酌周斗，矍鑠更鷹揚。"]'),
('352bfb44-6fa6-4f67-b1d7-f2cc2c51e467','李丞相綱生朝三首  其三','張元幹','宋','宋诗','song-poetry','','[]','希世推英偉，行藏孰是非。',48,'全唐诗/poet.song.102000.json','["希世推英偉，行藏孰是非。", "橫流曾砥柱，袖手且深衣。", "槐影摇黄閤，星躔煥紫微。", "山林愚已老，衮繡看公歸。"]'),
('b9512725-b3c0-4e82-874b-880d0644a16d','輓少師相國李公  其一','張元幹','宋','宋诗','song-poetry','','[]','望表公師位，身兼將相權。',48,'全唐诗/poet.song.102000.json','["望表公師位，身兼將相權。", "三朝更出入，一德奉周旋。", "盍爲蒼生起，曾扶大厦顛。", "何知老賓客，擁篲掃新阡。"]'),
('4f57de7d-9ec1-4e83-8185-1c1277174e60','輓少師相國李公  其二','張元幹','宋','宋诗','song-poetry','','[]','往在東都日，傷心丙午年。',48,'全唐诗/poet.song.102000.json','["往在東都日，傷心丙午年。", "不從三鎮割，安得兩宮遷。", "抗議行營上，排姦御榻前。", "英風成昨夢，遺恨落窮邊。"]'),
('bf51f323-5858-41fe-8312-9229ae5ff861','輓少師相國李公  其三','張元幹','宋','宋诗','song-poetry','','[]','城守麾强弩，諸班果翕然。',48,'全唐诗/poet.song.102000.json','["城守麾强弩，諸班果翕然。", "雲梯攻正急，雨箭勇爭先。", "中夜飛雷砲，平明破火船。", "如公真徇國，繪像冠凌煙。"]'),
('b8b9356e-7a92-46eb-806f-c8d7edb9f496','輓少師相國李公  其四','張元幹','宋','宋诗','song-poetry','','[]','壯志深憂國，丹心篤愛君。',48,'全唐诗/poet.song.102000.json','["壯志深憂國，丹心篤愛君。", "謗書興衆枉，諫疏在奇勳。", "風咽梁谿水，山悲湛峴雲。", "空餘雙舞鶴，鼓吹不堪聞。"]'),
('52a6ce55-c133-4b3d-926c-b7c749a108fe','輓少師相國李公  其五','張元幹','宋','宋诗','song-poetry','','[]','淚盡西州路，碑留峴首名。',48,'全唐诗/poet.song.102000.json','["淚盡西州路，碑留峴首名。", "買山緣荔子，爲圃養黄精。", "所至登臨地，猶疑步履聲。", "堂堂真漢相，天忍閟佳城。"]'),
('0d182dc9-4fa9-4086-a8c2-a35a289529de','輓寺丞許子如','張元幹','宋','宋诗','song-poetry','','[]','盛世黄門嗣，輕裘綠髮時。',48,'全唐诗/poet.song.102000.json','["盛世黄門嗣，輕裘綠髮時。", "傷心來故里，刮膜訪良醫。", "春雨銘旌暗，東郊薤露悲。", "人生得意早，遺恨在孤嫠。"]'),
('d413656d-e0a2-458d-b02a-4752cfaaadf9','輓夢錫機宜寺簿  其一','張元幹','宋','宋诗','song-poetry','','[]','零落梁溪客，何堪鄭子悲。',48,'全唐诗/poet.song.102000.json','["零落梁溪客，何堪鄭子悲。", "閉門專學易，擁鼻愛哦詩。", "臭味方投合，行藏罕遇知。", "他年鄉飲酒，揚觶相威儀。"]'),
('d8c0af1f-efee-460b-b344-aa3afc7de423','輓夢錫機宜寺簿  其二','張元幹','宋','宋诗','song-poetry','','[]','太府堅辭掾，平陽頃著功。',48,'全唐诗/poet.song.102000.json','["太府堅辭掾，平陽頃著功。", "清貧名教樂，靜退昔賢風。", "俛首稠人裏，甘心正論中。", "胡然成鬼錄，骨相本三公。"]'),
('0a0c720e-21f9-4dc6-b3ea-77bb53748b34','輓夢錫機宜寺簿  其三','張元幹','宋','宋诗','song-poetry','','[]','問疾方旬浹，殊驚不起傳。',48,'全唐诗/poet.song.102000.json','["問疾方旬浹，殊驚不起傳。", "所欽期異日，何意遽終天。", "圖籍嗟空富，生涯衆漫憐。", "保家宜有後，一角儻稱賢。"]'),
('bb881d8a-dad5-4159-acca-ee0d53ec3c7f','輓林天和  其一','張元幹','宋','宋诗','song-poetry','','[]','歎息宜春守，抽簪未亂歸。',48,'全唐诗/poet.song.102000.json','["歎息宜春守，抽簪未亂歸。", "不應徒告老，要是久知幾。", "築室聊遮雨，耘田止療饑。", "杜門何悔吝，牖下斂朝衣。"]'),
('be6f481c-5f27-4360-8478-95981b2eaf5f','輓林天和  其二','張元幹','宋','宋诗','song-poetry','','[]','行配古君子，齒尊鄉丈人。',48,'全唐诗/poet.song.102000.json','["行配古君子，齒尊鄉丈人。", "儻來名位晚，長往誄文新。", "薤露空悲臘，芻靈不見春。", "諸郎無過毀，壽考沒元身。"]'),
('46e37f98-0191-4e1a-888b-0ac06c496218','輓李仲輔三首  其一','張元幹','宋','宋诗','song-poetry','','[]','畫省何心入，軺車隨分行。',48,'全唐诗/poet.song.102000.json','["畫省何心入，軺車隨分行。", "急難頻太息，交友舊馳聲。", "素月墮江影，白雞悲夜鳴。", "繡衣無復出，部曲把銘旌。"]'),
('c3f7bf84-797f-4e20-b6f0-11e5ce2bcec0','輓李仲輔三首  其二','張元幹','宋','宋诗','song-poetry','','[]','貌古期驚世，心夷合享年。',48,'全唐诗/poet.song.102000.json','["貌古期驚世，心夷合享年。", "交遊稱長者，風味配先賢。", "雁序飄零地，龍門寂寞邊。", "不知誰作誄，著意翠珉鎸。"]'),
('6f680627-5191-4783-a956-41a99e0ab1d4','輓李仲輔三首  其三','張元幹','宋','宋诗','song-poetry','','[]','人生真寄爾，天問竟悠哉。',48,'全唐诗/poet.song.102000.json','["人生真寄爾，天問竟悠哉。", "三載重凶釁，一門皆異材。", "尚疑書未報，遽有訃先來。", "淚盡餘青血，秋風萬壑哀。"]'),
('f71622e8-2c8d-4760-b996-6d8fa5c6f218','彭德器北堂太夫人輓詩','張元幹','宋','宋诗','song-poetry','','[]','早歲嫠居久，儒家守志貧。',48,'全唐诗/poet.song.102000.json','["早歲嫠居久，儒家守志貧。", "白頭躬祭祀，老眼喜縫紉。", "哭婦無遺恨，憐孫不忍嗔。", "一朝違孝養，力疾叫蒼旻。"]'),
('f7254db5-19d3-4c50-a4ac-42bed28b1075','劉建州母夫人難氏輓章','張元幹','宋','宋诗','song-poetry','','[]','慈顔推壽相，懿範在吾鄉。',48,'全唐诗/poet.song.102000.json','["慈顔推壽相，懿範在吾鄉。", "不待黄堂養，空遺紫誥藏。", "板輿悲騎省，鶴客弔龍驤。", "風卷銘旌去，松岡閟夜長。"]'),
('0a040ed1-35a7-4b96-8fb7-4fb1ede7e80a','李丞相生朝','張元幹','宋','宋诗','song-poetry','','[]','柱史生周室，仙源譜系崇。',240,'全唐诗/poet.song.102000.json','["柱史生周室，仙源譜系崇。", "儲星昭昴宿，降嶽表神嵩。", "間氣憑家世，宗臣挺祖風。", "夢求終作楫，獵卜果非熊。", "感遇雲龍會，恩深雨露豐。", "折衝淵聖日，輝赫靖康功。", "社稷欹傾際，乾坤震蕩中。", "力扶神器正，堅守帝都雄。", "割地爭三鎮，回天定兩宮。", "壯圖期敉難，大節耻和戎。", "去國孤舟遠，憂時百雉空。", "建炎欣翊戴，鴻慶襲光融。", "相印機衡重，兵權號令通。", "安危繄禮貌，進退肯雷同。", "巨屏頻循撫，真祠示眷蒙。", "歡聲逢穀旦，善頌達蒼穹。", "弼亮需元老，平章合上公。", "五行推有本，六甲混無窮。", "再造邦基固，中興大運隆。", "保民躋壽域，千載簡宸衷。"]'),
('44ab1463-15e7-4a2e-a3b9-73123d13b6df','張丞相生朝二十韻','張元幹','宋','宋诗','song-poetry','','[]','鳳歷推炎德，宗臣繫重輕。',240,'全唐诗/poet.song.102000.json','["鳳歷推炎德，宗臣繫重輕。", "神開丹扆夢，人向紫巖生。", "昴宿秋旻迥，坤維玉露清。", "風雲符感遇，草木畏威名。", "不有三靈助，寧無四海驚。", "大江元帝渡，細柳亞夫營。", "勁氣吞妖孽，深謀厲甲兵。", "天旋黄屋正，日轉赤墀明。", "茅土宜班數，山河舊著盟。", "濟時登衮職，命世屬阿衡。", "社稷扶持了，乾坤整頓成。", "勳庸多部曲，陶冶遍公卿。", "牙帳羅旌棨，萱堂合鼓笙。", "誕辰尊壽母，善頌及難兄。", "慶積基墉固，源長福祿并。", "欲知貂珥貴，倍覺綵衣榮。", "象闕鋒車召，沙堤相印迎。", "指麾烽燧靜，翊戴泰階平。", "老鶴三千歲，飛鵬九萬程。", "百川浮巨斝，快飲吸長鯨。"]'),
('0034725b-c4cf-4274-930e-68cd0b4f23e2','次韻送友人過山陰郡時夜別於舟中','張元幹','宋','宋诗','song-poetry','','[]','草草杯盤燦燭光，故人相對水雲鄉。',64,'全唐诗/poet.song.102000.json','["草草杯盤燦燭光，故人相對水雲鄉。", "濤江君去訪秦望，丘壑我歸爲楚狂。", "活國未逢三折臂，憂時空轉九回腸。", "絕憐明發成南北，夢寐全無夜太長。"]'),
('a020a030-f2f9-451a-84c6-9415810687ff','喜王性之見過千金村','張元幹','宋','宋诗','song-poetry','','[]','春來書劄已西東，喜復相逢亂世中。',64,'全唐诗/poet.song.102000.json','["春來書劄已西東，喜復相逢亂世中。", "萬事變更唯舌在，三年流落轉塗窮。", "雲收野寺侵廊水，月挂孤帆送客風。", "剩欲留君明日住，夜闌難得一樽同。"]'),
('e24f3267-998f-4969-8b69-f6eb1b85b918','次江子我遷居韵','張元幹','宋','宋诗','song-poetry','','[]','平生自省宜三黜，老去何心望九遷。',64,'全唐诗/poet.song.102000.json','["平生自省宜三黜，老去何心望九遷。", "避地湖山聊復爾，脫身兵火想當然。", "浮家泛宅非無計，坎止流行本信緣。", "猶恐驚濤翻四海，直須化鶴作飛仙。"]'),
('2dad40c5-62cc-4b2c-b8b3-a86a113a812f','次趙次張見遺之什韻','張元幹','宋','宋诗','song-poetry','','[]','海邊遊子日思歸，新句勞君更置規。',64,'全唐诗/poet.song.102000.json','["海邊遊子日思歸，新句勞君更置規。", "莫問人間多貝錦，正如天上有參旗。", "寄書只欲憑黄耳，去路誰能畏赤眉。", "定與故巢猿鶴老，此生無愧北山移。"]'),
('5d6acf91-49ef-4221-aa96-f871668c74ad','過雲間黄用和新圃','張元幹','宋','宋诗','song-poetry','','[]','繚池剩欲開花徑，傍舍先須作草堂。',64,'全唐诗/poet.song.102000.json','["繚池剩欲開花徑，傍舍先須作草堂。", "雨後不妨頻檢校，客來留得共徜徉。", "故園怪我歸何晚，避地輸君樂未央。", "待得功成方卜築，豈如强健享風光。"]'),
('8a50464a-957d-46b3-a62e-200211ae68cd','蘭溪舟中寄蘇粹中','張元幹','宋','宋诗','song-poetry','','[]','氣吞萬里境中事，心老經年江上行。',64,'全唐诗/poet.song.102000.json','["氣吞萬里境中事，心老經年江上行。", "三徑已荒無蟻夢，一錢不直有鷗盟。", "雲收遠嶂晚風熟，浪打寒灘春水生。", "鴻雁北飛知我意，爲傳詩句濮陽城。"]'),
('c1b460dd-9621-4fce-9507-0e0b628b6216','別綬老','張元幹','宋','宋诗','song-poetry','','[]','無端流落迫殘年，三十南山訪老禪。',64,'全唐诗/poet.song.102000.json','["無端流落迫殘年，三十南山訪老禪。", "未契安心了難覓，不如同世且隨緣。", "頻移竹几負寒日，旋拾松梢炊晚煙。", "珍重孤雲出山去，東西南北一青天。"]'),
('99fabf8a-aee5-4da0-9252-87e284feb491','次江子我聞角韻','張元幹','宋','宋诗','song-poetry','','[]','夫差故國縈寒水，鐵馬南來忽振纓。',64,'全唐诗/poet.song.102000.json','["夫差故國縈寒水，鐵馬南來忽振纓。", "城上昏鴉爭接翅，舟中逐客謹逃名。", "胡笳怨處風微起，濁酒醒時夢易驚。", "飄泊似聞山寺近，真成夜半聽鐘聲。"]'),
('a80c7f5d-88e8-445b-b824-7e03cbc0fc68','次韻奉呈公澤處士','張元幹','宋','宋诗','song-poetry','','[]','屏迹苕溪少往還，時危尤覺故人歡。',64,'全唐诗/poet.song.102000.json','["屏迹苕溪少往還，時危尤覺故人歡。", "相期臘盡屠蘇酒，速享春來苜蓿盤。", "雪夜劇談金賊入，風江絕歎鐵衣寒。", "何年天上旄頭落，併滅穹廬舊契丹。"]'),
('853f6ea5-fae6-4d01-a86c-bb5949f0b9ec','次友人寒食書懷韻二首  其一','張元幹','宋','宋诗','song-poetry','','[]','往昔昇平客大梁，新煙然燭九衢香。',64,'全唐诗/poet.song.102000.json','["往昔昇平客大梁，新煙然燭九衢香。", "車聲馳道內家出，春色禁溝宮柳黄。", "陵邑祇今稱虜地，衣冠誰復問唐裝。", "傷心寒食當時事，夢想流鶯下苑牆。"]'),
('f9882f49-629e-4edd-b739-7d42dbff5e1b','次友人寒食書懷韻二首  其二','張元幹','宋','宋诗','song-poetry','','[]','孤生投老急菟裘，萬里雲山已倦遊。',64,'全唐诗/poet.song.102000.json','["孤生投老急菟裘，萬里雲山已倦遊。", "共喜石交逢異縣，更陪綵筆賦春愁。", "無心俯仰猶多事，與世浮沉己拙謀。", "冷雨吹花作寒食，三杯軟飽且眠休。"]'),
('f79fb42b-e4c1-4989-bf04-4979db1664bf','訪親於連江因過筠溪叩門循行歎其荒翳不治有懷普現居士口占此章','張元幹','宋','宋诗','song-poetry','','[]','筠莊主人何未歸，溪畔長林穿翠微。',64,'全唐诗/poet.song.102000.json','["筠莊主人何未歸，溪畔長林穿翠微。", "此去功名時欲至，箇中車馬蹟全稀。", "茅茨漏久蝸涎篆，籬落欹多蛛網圍。", "公肯借庵容我老，爲公朝夕掃柴扉。"]'),
('ffcadac6-b5bc-4e14-aa67-55ec8f2b3ced','奉同公直圮老過應夫石友齋','張元幹','宋','宋诗','song-poetry','','[]','王郎胸次鬰崢嶸，鑿牖開軒不浪名。',64,'全唐诗/poet.song.102000.json','["王郎胸次鬰崢嶸，鑿牖開軒不浪名。", "疾世政須論石友，絕交今已見方兄。", "我曹自笑真同病，吾道誰當爲主盟。", "但得此心如此老，故人寧復負平生。"]'),
('37784fe7-4bfd-4050-ab43-e1fff48dd7d3','宮使樞密富丈和篇高妙所謂壓倒元白末句許予尤非所敢承謹用前韻敘謝','張元幹','宋','宋诗','song-poetry','','[]','脩門一出十經春，相業時來自奮身。',64,'全唐诗/poet.song.102000.json','["脩門一出十經春，相業時來自奮身。", "袖手深謀終活國，揮毫佳句且驚人。", "話言每許聞前輩，賓客何堪接後塵。", "待掃欃槍洗兵馬，兩翁玄語記天津。"]'),
('c863621f-c014-4494-983c-5afb7b02b103','子立昆仲垂和遊天宮詩既工且敏義不虛辱再此見意','張元幹','宋','宋诗','song-poetry','','[]','華裾綠髮等青春，詩似機雲定後身。',64,'全唐诗/poet.song.102000.json','["華裾綠髮等青春，詩似機雲定後身。", "家學乃翁真具眼，祖風當代豈凡人。", "字中仙爪便搔癢，句裏靈犀解辟塵。", "萬壑爭流君看取，西興從此是通津。"]'),
('f3d124fa-cd88-4814-a878-173a2dd12ebb','端常觀察被旨入蜀迎母夫人所得贈行詩文成巨軸矣臨別亦辱見索匆遽中愧乏好語掇拾諸公餘意勉成四韻','張元幹','宋','宋诗','song-poetry','','[]','髫齔分携幾見春，它時有恃獨常顰。',64,'全唐诗/poet.song.102000.json','["髫齔分携幾見春，它時有恃獨常顰。", "何期萬里漂零後，忽報三巴信息真。", "素髮輕安膺晚福，遠懷悲喜望征人。", "王孫盛事今雙美，及早歸來奉紫宸。"]'),
('c5ce62ec-039a-4c4c-9fd1-715f1408f8af','次韻文老使君宗兄見贈近體佳什兩篇僕與公別四十餘年一旦邂逅情著於辭  其一','張元幹','宋','宋诗','song-poetry','','[]','使君元自錦官來，百丈重尋灧澦回。',64,'全唐诗/poet.song.102000.json','["使君元自錦官來，百丈重尋灧澦回。", "化閱行年如伯玉，心成全德過王駘。", "把麾政爾人生貴，持橐終期間世才。", "莫問桃花今老矣，劉郎去後任渠栽。"]'),
('ce3e538e-6b82-43b2-80f2-062202168cac','次韻文老使君宗兄見贈近體佳什兩篇僕與公別四十餘年一旦邂逅情著於辭  其二','張元幹','宋','宋诗','song-poetry','','[]','舊遊蘭若盡英才，坐上高談亦壯哉。',64,'全唐诗/poet.song.102000.json','["舊遊蘭若盡英才，坐上高談亦壯哉。", "老去語音雖記憶，衆中容貌各驚猜。", "津亭夜雨故人少，樽酒燈花鄉信來。", "茂苑相逢話京洛，柂樓猶喜待春回。"]'),
('610b4d77-5f90-43af-a15a-caaca37a8920','冬夜書懷呈富樞密','張元幹','宋','宋诗','song-poetry','','[]','耳聾無用問新聞，矯首何妨目作昏。',64,'全唐诗/poet.song.102000.json','["耳聾無用問新聞，矯首何妨目作昏。", "癡絕已甘投老境，背馳寧受乞憐恩。", "難陪年少從渠薄，賴得春回爲我溫。", "京洛交遊頻檢校，渡江今有幾人存。"]'),
('33f49c87-ac1b-4a52-8d7e-6f45966b4f5a','次韻趙元功贈李季言之什','張元幹','宋','宋诗','song-poetry','','[]','赤縣飄零未易逢，那知今夕一樽同。',64,'全唐诗/poet.song.102000.json','["赤縣飄零未易逢，那知今夕一樽同。", "好招明月共清影，託與白雲行太空。", "戃恍舊遊如隔世，蹉跎壯志莫論功。", "兩公秉燭還相對，情話從渠半醉中。"]'),
('32398988-bfa4-4781-be38-ebe980691bcf','次韻元功才友道中見貺因以解嘲','張元幹','宋','宋诗','song-poetry','','[]','當時勇决徑歸休，更有人愚似我不。',64,'全唐诗/poet.song.102000.json','["當時勇决徑歸休，更有人愚似我不。", "何許置錐寧免累，直須畢娶始無憂。", "頻遭白眼傷流俗，誰向青門念故侯。", "客裏題詩相慰藉，羨君椽筆合螭頭。"]'),
('82044614-5db7-47e8-95fe-a3186fb34877','奉送晁伯南歸金谿','張元幹','宋','宋诗','song-poetry','','[]','君家諸父多人傑，半是平生親舊間。',64,'全唐诗/poet.song.102000.json','["君家諸父多人傑，半是平生親舊間。", "莫話故園空矯首，相從逆旅足開顔。", "文元勳業金甌字，昭德風流玉筍班。", "此去騰驤吐虹氣，何由來伴老夫閑。"]'),
('3209b163-2bc9-42e8-b3fd-a11e8cd94bbb','奉簡才元探梅有作兼懷舊遊','張元幹','宋','宋诗','song-poetry','','[]','遮莫胡僧問劫灰，且陪東閣賦官梅。',64,'全唐诗/poet.song.102000.json','["遮莫胡僧問劫灰，且陪東閣賦官梅。", "春梢慣識宮粧樣，花信偏隨驛使回。", "痛飲我曹身總健，浩歌誰怕老相催。", "疏枝氣壓羣芳盡，羞殺牆陰錦被堆。"]'),
('daa6999f-c18e-435c-9fee-8dc081fa0ecf','才元思如湧泉愈和愈好晨興遣騎扣門披衣疾讀走筆再酬嚴韻','張元幹','宋','宋诗','song-poetry','','[]','陽和生發驗葭灰，但見江梅欠蠟梅。',64,'全唐诗/poet.song.102000.json','["陽和生發驗葭灰，但見江梅欠蠟梅。", "風味向人忘冷落，歲寒乘月重徘徊。", "從來對酒遭花惱，何獨題詩被雨催。", "公子唾珠無限思，更看鐵畫寫離堆。"]'),
('9722e401-a32a-476f-8a2a-dd45f9007641','奉酬才元席上所賦前韻','張元幹','宋','宋诗','song-poetry','','[]','夜飲華堂燭屢灰，暗香浮處數枝梅。',64,'全唐诗/poet.song.102000.json','["夜飲華堂燭屢灰，暗香浮處數枝梅。", "坐中一笑對三粲，客裏此歡能幾回。", "醉後不知歌扇去，歸時還是曉鐘催。", "露濃月白溪橋路，但記羣山翠作堆。"]'),
('2a79a53a-107c-4041-b17c-a0e459164099','冬夜癡坐似聞才元作集有日矣因和前韻奉呈','張元幹','宋','宋诗','song-poetry','','[]','擁爐書帙易塵灰，覽古臨窗獨對梅。',64,'全唐诗/poet.song.102000.json','["擁爐書帙易塵灰，覽古臨窗獨對梅。", "未寤徑須呼子慎，常奴何得比方回。", "虛名到底將安用，能事從來不受催。", "似許相過陪客醉，胸中那復有愁堆。"]'),
('6f6ec0bc-8c8a-4413-b4f3-d207bcc4630d','遊東山二詠次李丞相韻 鱣溪','張元幹','宋','宋诗','song-poetry','','[]','寒木高蘿幾曲溪，斷碑零落卧荒祠。',64,'全唐诗/poet.song.102000.json','["寒木高蘿幾曲溪，斷碑零落卧荒祠。", "澄潭想像雲頭湧，懸瀑依稀雨脚垂。", "地軸漫煩龍虎戰，天符那得鬼神私。", "茫茫造物殊難曉，要是爲霖自有時。"]'),
('664f7088-2f33-4b83-99d7-7ae9439db639','遊東山二詠次李丞相韻 榴花谷','張元幹','宋','宋诗','song-poetry','','[]','公如謝傅暫閑身，我亦歸來效季真。',64,'全唐诗/poet.song.102000.json','["公如謝傅暫閑身，我亦歸來效季真。", "山屐數陪銷暇日，詩篇常許和陽春。", "虛懷寄傲三休外，洗眼旁觀萬態新。", "谷口榴花解迎客，騎鯨端爲謫仙人。"]'),
('dde5f67d-f137-42a1-b323-ae61ab1345c3','留寄黄檗山妙湛禪師','張元幹','宋','宋诗','song-poetry','','[]','晨發薌城越數峯，我來師出失從容。',64,'全唐诗/poet.song.102000.json','["晨發薌城越數峯，我來師出失從容。", "白雲遮日蔽秋寺，青嶂聞猿驚暮鐘。", "世亂可無閑地隱，山深偏覺老僧慵。", "他年芋火談空夜，雪屋松窗約過冬。"]'),
('6752af0d-7577-4bdc-bd16-0516a29a2dac','用折樞韻呈李丞相二首  其一','張元幹','宋','宋诗','song-poetry','','[]','參陪仍許瘦筇支，長者登臨敢後期。',64,'全唐诗/poet.song.102000.json','["參陪仍許瘦筇支，長者登臨敢後期。", "鐘斷白雲飛雨過，月生青嶂夜凉時。", "心知勝地都忘睡，喜聽連床共和詩。", "蓮社風流增荔子，餘生長健更何爲。"]'),
('d0f1cff9-5f11-4ab3-8ef4-1d0cd2f6efdf','用折樞韻呈李丞相二首  其二','張元幹','宋','宋诗','song-poetry','','[]','莫問蒲萄出月支，不緣瓜棗訪安期。',64,'全唐诗/poet.song.102000.json','["莫問蒲萄出月支，不緣瓜棗訪安期。", "輕紅滿地人慵掃，空翠霑衣雨足時。", "松蔭晴泉聽落澗，蟬嘶晚吹助裁詩。", "公乎此去歸廊廟，無用山中怨鶴爲。"]'),
('733c0fee-2f08-4cbd-b422-a31ea320cda2','再和李丞相遊山','張元幹','宋','宋诗','song-poetry','','[]','海山幻出化人宮，樓觀新崇萬指容。',64,'全唐诗/poet.song.102000.json','["海山幻出化人宮，樓觀新崇萬指容。", "雲霧入檐銀色界，藤蘿昏雨妙高峯。", "放懷久已參黄檗，雅志無疑伴赤松。", "欲去更聞獅子吼，忘歸橋下興猶濃。"]'),
('89f05f6f-7790-4cd3-9c5d-e645b1c1a875','次錢申伯遊東山韻二首  其一','張元幹','宋','宋诗','song-poetry','','[]','東麓坡陀盡梵宮，我來泉上照衰容。',64,'全唐诗/poet.song.102000.json','["東麓坡陀盡梵宮，我來泉上照衰容。", "解衣又作茶瓜客，倚檻同看煙雨峯。", "何用苦吟凌鮑謝，要須高節配喬松。", "海冰永閟錐沙畫，絕歎故人遺墨濃。"]'),
('c36a51ff-1305-4678-85a8-23e845047c23','次錢申伯遊東山韻二首  其二','張元幹','宋','宋诗','song-poetry','','[]','掃榻開軒走寺宮，吾曹終日得從容。',64,'全唐诗/poet.song.102000.json','["掃榻開軒走寺宮，吾曹終日得從容。", "夕陽初落鱣溪路，雲氣半遮獅子峯。", "試問丹砂回白髮，何如瀑布煮枯松。", "暮年縱有壯心在，歸意已勝山色濃。"]'),
('00cf410f-2771-42ba-b998-673ac810186c','次韻錢申伯遊東山既歸述懷之章','張元幹','宋','宋诗','song-poetry','','[]','山人不省大明宮，懷昔幽尋自改容。',64,'全唐诗/poet.song.102000.json','["山人不省大明宮，懷昔幽尋自改容。", "廬阜東西二林寺，錢塘南北兩高峯。", "百年有盡雲歸壑，萬事無邊月掛松。", "滿院蒼苔重到日，秋光欲滴向人濃。"]'),
('40cd0796-02c9-45e8-951f-adb405bde635','哭鄒德久二首用前韻  其一','張元幹','宋','宋诗','song-poetry','','[]','出守真成夢蟻宮，天台雲色亦愁容。',64,'全唐诗/poet.song.102000.json','["出守真成夢蟻宮，天台雲色亦愁容。", "時來盍錫萬釘带，仙去俄歸羣玉峯。", "川上可驚如逝水，歲寒徒有後凋松。", "煩將老眼銀河淚，共灑西風絮酒濃。"]'),
('c0c9330d-651b-4d89-8eaf-6adb490e877c','哭鄒德久二首用前韻  其二','張元幹','宋','宋诗','song-poetry','','[]','窮達那知十二宮，由來與世不相容。',64,'全唐诗/poet.song.102000.json','["窮達那知十二宮，由來與世不相容。", "乃翁極諫牽龍衮，百謫同愁割劍峯。", "前輩品題推玉樹，平生憂患挺蒼松。", "傷心身後夸君賜，泉路恩光底事濃。"]'),
('130986c5-4ac7-45bd-95c7-5b612bec45c2','再用前韻哭德久','張元幹','宋','宋诗','song-poetry','','[]','女無美惡妬深宮，盛德如公果不容。',64,'全唐诗/poet.song.102000.json','["女無美惡妬深宮，盛德如公果不容。", "何遽蓋棺臨禹穴，未應藏骨在秦峯。", "論文平日樽中酒，挂劍它年冢上松。", "點檢交親祇解少，存亡悲感老情濃。"]'),
('e49f166b-d07a-4e83-9857-b8527d917b74','再用前韻重哭德久賢使君','張元幹','宋','宋诗','song-poetry','','[]','風撼棠梨對殯宮，中郎談笑孰形容。',64,'全唐诗/poet.song.102000.json','["風撼棠梨對殯宮，中郎談笑孰形容。", "不居上界神仙府，當在補陀孤絕峯。", "至論每符磁石鐵，長生空問茯苓松。", "九原可作還知否，底處返魂香最濃。"]'),
('8445bf84-19cc-43f2-ad27-fffe16d2488f','與富樞密','張元幹','宋','宋诗','song-poetry','','[]','和氣從容一笑春，如公今是暫閑身。',64,'全唐诗/poet.song.102000.json','["和氣從容一笑春，如公今是暫閑身。", "伊蒲饌設無多客，薝蔔花繁正惱人。", "已遣爐熏通鼻觀，更分茗碗瀹心塵。", "僧房長夏宜幽僻，杖屨頻來願問津。"]'),
('27608b29-761a-4839-be2a-0dd1074e7d54','止戈堂  其一','張元幹','宋','宋诗','song-poetry','','[]','譙門直北望燕山，乙巳年來例破殘。',64,'全唐诗/poet.song.102000.json','["譙門直北望燕山，乙巳年來例破殘。", "可但中原仍禍結，誰令東粵獨偷安。", "西師有請君侯力，南顧無憂聖慮寬。", "惡少至今猶膽落，雲臺須入畫圖看。"]'),
('3caf17f4-ec63-40af-86b0-e6d88daaf4de','止戈堂  其二','張元幹','宋','宋诗','song-poetry','','[]','八州賢牧喜休兵，千騎重來竹馬迎。',64,'全唐诗/poet.song.102000.json','["八州賢牧喜休兵，千騎重來竹馬迎。", "萬瓦連甍存比屋，十年回首賴長城。", "舉觴談笑精明甚，緩带登臨步武輕。", "多是門牆舊賓客，願公黄髮佐昇平。"]'),
('d642fe92-7e93-4256-b7e3-1af09c85ad1f','次友人書懷  其一','張元幹','宋','宋诗','song-poetry','','[]','此生無意入修門，粗飽雞豚短褐溫。',64,'全唐诗/poet.song.102000.json','["此生無意入修門，粗飽雞豚短褐溫。", "卜築幾椽臨水屋，經營數畝傍山園。", "酒杯剩喜故人飲，書帙能遮老眼昏。", "身世頗同猿擇木，功名誰問鶴乘軒。"]'),
('19700078-e2be-40cf-b0da-af791c6bbf17','次友人書懷  其二','張元幹','宋','宋诗','song-poetry','','[]','腸斷春風楊柳花，中原何日再京華。',64,'全唐诗/poet.song.102000.json','["腸斷春風楊柳花，中原何日再京華。", "將軍未報歌三箭，樂府徒傳舞兩娃。", "會見敵營如竹破，不應淮甸又兵加。", "頻年寒食常爲客，强索芳樽樂有涯。"]'),
('b6c2b15a-aa62-4d82-b23b-678271b07250','次友人書懷  其三','張元幹','宋','宋诗','song-poetry','','[]','布穀催春惜雨乾，白鷗江上未盟寒。',64,'全唐诗/poet.song.102000.json','["布穀催春惜雨乾，白鷗江上未盟寒。", "且傾客子酴醾酒，共享先生苜蓿盤。", "我已懸車羞碌碌，公當鳴珮稱珊珊。", "休文才思雖多病，可是空吟紅藥闌。"]'),
('38a5beec-a10a-4ef9-a85c-2dde2b9768a8','和楊聰父聞雨書懷','張元幹','宋','宋诗','song-poetry','','[]','坎壈如公莫怨天，謫居端是坐無氈。',64,'全唐诗/poet.song.102000.json','["坎壈如公莫怨天，謫居端是坐無氈。", "時來要自有歸路，客散不妨頻醉眠。", "雲氣久能浮蜃屋，雨聲殊未透龜田。", "回思風雪圍爐夜，何處聯裘擁木綿。"]'),
('006f8b9b-8247-4e55-bb9a-de4463f4ea84','筠溪居士跳出隨順境界把住放行自在神通縱橫妙用已是摸索不著妙現老子猶眨句中眼可謂善知識用心謹次嚴韻上呈','張元幹','宋','宋诗','song-poetry','','[]','珍重筠溪舊主人，我知明水是前身。',64,'全唐诗/poet.song.102000.json','["珍重筠溪舊主人，我知明水是前身。", "如何一念初無過，便有多生未了因。", "止酒裙襦成厭雜，逃禪槌拂要比鄰。", "雲居嫡子重拈出，流布諸方此話新。"]'),
('ab6eab13-e0bc-4749-8f00-3643e0d9b62f','次韻聰父見遺二首  其一','張元幹','宋','宋诗','song-poetry','','[]','十年遷客北歸時，旁海相逢歎渺瀰。',64,'全唐诗/poet.song.102000.json','["十年遷客北歸時，旁海相逢歎渺瀰。", "枝上煙光忙蛺蝶，尊中風味奪酴醾。", "老來詩思真枯井，別後心情似亂絲。", "喜故將軍殊矍鑠，家山小築未爲遲。"]'),
('d4845df4-0230-42eb-a72d-104ed6e7d818','次韻聰父見遺二首  其二','張元幹','宋','宋诗','song-poetry','','[]','雞嶼洋邊桃李穠，岸沙遮海暮雲重。',64,'全唐诗/poet.song.102000.json','["雞嶼洋邊桃李穠，岸沙遮海暮雲重。", "乘槎我自犯牛斗，掘獄誰何藏劍鋒。", "世路肯遵前覆轍，交遊誰識後凋松。", "此生但得長相見，一笑能輕祿萬鍾。"]'),
('eceb2317-6ee0-40e0-b322-a112116ab3aa','次聰父見遺韻','張元幹','宋','宋诗','song-poetry','','[]','拙速還知勝巧遲，男兒功業要逢時。',64,'全唐诗/poet.song.102000.json','["拙速還知勝巧遲，男兒功業要逢時。", "不妨唾面辱高馬，似有泥坑規病鴟。", "老去尚堪蘇子印，興來須到習家池。", "此心畢娶無餘事，且向春江理釣絲。"]'),
('5f16c1c0-d93f-4859-9e24-544c0c3825c8','李丞相綱生朝三首  其一','張元幹','宋','宋诗','song-poetry','','[]','梁溪萬折必流東，間氣英姿叶夢熊。',64,'全唐诗/poet.song.102000.json','["梁溪萬折必流東，間氣英姿叶夢熊。", "出入三朝推大老，險夷一節合蒼穹。", "守關虎豹徒窺闖，得雨蛟龍定長雄。", "衮繡未歸聊袖手，不妨閑作黑頭公。"]'),
('267f3a1a-98b6-42c7-b248-a5835881a5e5','李丞相綱生朝三首  其二','張元幹','宋','宋诗','song-poetry','','[]','將壇丙午贊親征，相印元年佐聖明。',64,'全唐诗/poet.song.102000.json','["將壇丙午贊親征，相印元年佐聖明。", "賊子亂臣俱破膽，皇天后土實同盟。", "扶持更係民休戚，進退元知勢重輕。", "捨我其誰公健在，乞身贏得見昇平。"]'),
('312ff5a1-1266-454f-9641-76b257d92ffe','李丞相綱生朝三首  其三','張元幹','宋','宋诗','song-poetry','','[]','濟世功名肯力爲，風雲遇合貴逢時。',64,'全唐诗/poet.song.102000.json','["濟世功名肯力爲，風雲遇合貴逢時。", "欲知辟穀師黄石，便是扁舟號子皮。", "後進忌能踰日月，敵人用間果蓍龜。", "福城東際笙歌地，且祝千齡醉荔支。"]'),
('0a261281-14b0-4b21-b6f2-b91dbc5a3d86','代上折樞彥質生朝二首  其一','張元幹','宋','宋诗','song-poetry','','[]','天扶王室挺生申，瑞啟中興社稷臣。',64,'全唐诗/poet.song.102000.json','["天扶王室挺生申，瑞啟中興社稷臣。", "樽俎折衝常自任，廟堂康濟更何人。", "秋風玉帳軍容肅，冷月鈴齋夜宴新。", "願掃妖氛開壽域，衮衣端爲轉洪鈞。"]'),
('f1867291-8934-4cc4-ada2-c99f68cd94b5','代上折樞彥質生朝二首  其二','張元幹','宋','宋诗','song-poetry','','[]','秋水爲神吉夢隨，上公冠佩儼朝儀。',64,'全唐诗/poet.song.102000.json','["秋水爲神吉夢隨，上公冠佩儼朝儀。", "風雲感遇千齡會，日月依光四海知。", "筆陣詞鋒明藻色，龍韜豹略繫安危。", "頑金從此歸爐錘，歲歲門闌獻壽詩。"]'),
('d5f6b02a-1bbe-4633-8d3d-dbc2b04e252e','福帥生朝二首  其一','張元幹','宋','宋诗','song-poetry','','[]','玉帳生朝香霧飛，秋風欲到碧梧枝。',64,'全唐诗/poet.song.102000.json','["玉帳生朝香霧飛，秋風欲到碧梧枝。", "回思十載折衝地，還鎮八州安靜時。", "淇澳會須歌綠竹，渭濱猶待獵非羆。", "止戈堂上多珠履，爭獻龐眉春酒詩。"]'),
('37049452-cf1a-43bf-b17b-66ffa848c3de','福帥生朝二首  其二','張元幹','宋','宋诗','song-poetry','','[]','金貂赫奕照來仍，雅意諸郎以壽稱。',64,'全唐诗/poet.song.102000.json','["金貂赫奕照來仍，雅意諸郎以壽稱。", "矍鑠儀形千歲鶴，扶摇風力九霄鵬。", "黄雲䆉䅉人皆醉，丹荔芳敷俎正登。", "請看君侯高閣宴，層梯無用一枝藤。"]'),
('2998ce3a-d5d0-4311-851b-d706c5553ef4','葉少藴生朝三首  其一','張元幹','宋','宋诗','song-poetry','','[]','絳節霓旌下九天，括蒼初識地行仙。',64,'全唐诗/poet.song.102000.json','["絳節霓旌下九天，括蒼初識地行仙。", "桃華海上三千歲，鳳歷人間五百年。", "可但彤弓尋節制，要知黔首望陶甄。", "香凝燕寢森蘭玉，會見貂冠總附蟬。"]'),
('d2a4791e-0353-459b-8f11-81f0a972a31b','葉少藴生朝三首  其二','張元幹','宋','宋诗','song-poetry','','[]','綠髮翺翔翰苑春，昇平三輔已朱輪。',64,'全唐诗/poet.song.102000.json','["綠髮翺翔翰苑春，昇平三輔已朱輪。", "詩成山谷句中眼，名應石林天上人。", "耆舊政須廊廟具，蕃宣聊寄股肱臣。", "生朝剩欲爲公壽，醉裏蘋花度曲新。"]'),
('70eba873-f61c-4246-8b8c-16efac09693c','葉少藴生朝三首  其三','張元幹','宋','宋诗','song-poetry','','[]','元戎玉帳凜霜威，談笑何妨羽扇揮。',64,'全唐诗/poet.song.102000.json','["元戎玉帳凜霜威，談笑何妨羽扇揮。", "平日丹心馳象闕，長年綵服奉慈闈。", "誰無五馬人生貴，獨有三奇命世稀。", "志在麟經成事業，頗聞天子詔公歸。"]'),
('e55885ca-3c5e-4198-b4e6-908965974a60','題企疏堂','張元幹','宋','宋诗','song-poetry','','[]','出處當師漢大夫，立朝常擬賦歸歟。',64,'全唐诗/poet.song.102000.json','["出處當師漢大夫，立朝常擬賦歸歟。", "賜金端爲供行樂，燕客猶疑是送車。", "欲識吳門重解組，要符潭府向移書。", "聞知剩有閑風月，宅相須留待小疏。"]'),
('60f4d04e-fef9-4d22-a0a1-1dbef67a4b5f','左舉善人物高妙才具敏特要當爲世用而乃携孥撫孤以不二價從事丹壺中其胸次詎可窺耶一日出示諸公篇軸邀老夫同賦義不可辭','張元幹','宋','宋诗','song-poetry','','[]','小隱丹壺時憑欄，它年興在跨黄班。',64,'全唐诗/poet.song.102000.json','["小隱丹壺時憑欄，它年興在跨黄班。", "不妨遊戲橘中樂，政爾經營湖上山。", "誰識胸懷容萬頃，聊將身世寓三間。", "故人有子猶流落，我輩逢渠轉厚顔。"]'),
('8209bf05-ae9f-4474-a4cf-7c653098611f','病中示彭德器','張元幹','宋','宋诗','song-poetry','','[]','老病無堪正坐貧，交遊相見賴情親。',64,'全唐诗/poet.song.102000.json','["老病無堪正坐貧，交遊相見賴情親。", "從渠造物小兒戲，不礙維摩老子神。", "三顧九遷成底事，一區二頃合由人。", "君侯論議高千古，略假毫端問大鈞。"]'),
('57bbcad8-50fc-45c0-9a61-7d4253c78656','挽李丈然明','張元幹','宋','宋诗','song-poetry','','[]','眼看流輩上青雲，拂袖歸來晝掩門。',64,'全唐诗/poet.song.102000.json','["眼看流輩上青雲，拂袖歸來晝掩門。", "心計豈容生事拙，時名長與故山存。", "不妨開徑栽花卉，政復藏書遺子孫。", "八十光陰無可恨，聊歌楚些爲招魂。"]'),
('771ff696-1fb0-4de7-9962-60b292dfb43a','再次前韻即事','張元幹','宋','宋诗','song-poetry','','[]','太一遊行遍九宮，世間無地可寬容。',64,'全唐诗/poet.song.102000.json','["太一遊行遍九宮，世間無地可寬容。", "坤維莫傍劍門閣，衡嶽何依天柱峯。", "睨柱儻能回趙璧，思鱸安用過吳松。", "羣羊競語遽如計，欲息兵戈氣甚濃。"]'),
('56d89ec9-ce75-4510-9bbe-8fd527e5d1c3','再用韻奉留聰父','張元幹','宋','宋诗','song-poetry','','[]','長饑方朔笑侏儒，歲晚還驚大小餘。',64,'全唐诗/poet.song.102000.json','["長饑方朔笑侏儒，歲晚還驚大小餘。", "客裏論文聊把酒，閑來會面勝通書。", "薄寒欺醉悲清夜，孤月流光悵碧虛。", "何苦相逢又相別，不如供米寓僧居。"]'),
('9edf2d26-ab78-40a4-9b6b-d4b44ff4e10b','辛酉別楊聰父','張元幹','宋','宋诗','song-poetry','','[]','春風著意送將歸，爲賦清江落日低。',64,'全唐诗/poet.song.102000.json','["春風著意送將歸，爲賦清江落日低。", "惜別更留烹玉鱠，寓居長記對青猊。", "家山彼此歸心速，歧路東西客夢迷。", "重把一樽成悵望，鶯啼綠暗草凄凄。"]'),
('0ffd7465-3d3c-4a8f-8e4a-565f0ffeafdb','次韻陳德用明府贈別之什','張元幹','宋','宋诗','song-poetry','','[]','人欺季子弊貂裘，誰信班生萬里侯。',64,'全唐诗/poet.song.102000.json','["人欺季子弊貂裘，誰信班生萬里侯。", "小隱故山今去好，中原遺恨幾時休。", "春爭殘臘寒梅早，雨澀晴冬宿麥憂。", "老眼相看炯無語，濁醪何日更澆愁。"]'),
('e9f15577-a47a-42ea-a4ca-5183b85296c4','希道使君弭節合沙館奉太夫人遊鼓山乃蒙封示所和夢錫贈行佳句輒次嚴韻少敘別懷','張元幹','宋','宋诗','song-poetry','','[]','淮海元龍公輩流，何勞老手鎮方州。',64,'全唐诗/poet.song.102000.json','["淮海元龍公輩流，何勞老手鎮方州。", "雍容行色自登覽，邂逅故人仍倡酬。", "眼界早驚雲子熟，官期能爲荔枝留。", "臨分莫話中原事，想見家山只夢遊。"]'),
('6c9c4a13-3d98-4f53-9af1-1e31c54876d6','希道使君入山再有佳句見及復次元韻因簡老禪','張元幹','宋','宋诗','song-poetry','','[]','古澗寒泉可枕流，從渠庚伏在炎州。',64,'全唐诗/poet.song.102000.json','["古澗寒泉可枕流，從渠庚伏在炎州。", "杖藜端欲事幽討，杯酒未容相勸酬。", "坐上縱無居士客，山間聊爲老禪留。", "臨滄亭外忘歸路，他日逢君望舊遊。"]'),
('d65aa2d0-360e-4065-9bdc-8f572cdd3cb2','龍眠墨梅','張元幹','宋','宋诗','song-poetry','','[]','江南一枝春，歲久暗香滅。',24,'全唐诗/poet.song.102000.json','["江南一枝春，歲久暗香滅。", "怪得深夜寒，荒村映殘雪。"]'),
('64865271-cf81-4349-abfa-6ff9408ccaa5','歲寒三友圖','張元幹','宋','宋诗','song-poetry','','[]','蒼官森古鬣，此君挺剛節。',24,'全唐诗/poet.song.102000.json','["蒼官森古鬣，此君挺剛節。", "中有調鼎姿，獨立傲霜雪。"]'),
('be1bd5aa-b2ca-4ff4-a4ba-25a5f482ff4f','墨菊','張元幹','宋','宋诗','song-poetry','','[]','老眼驚花暗，斜枝落紙愁。',24,'全唐诗/poet.song.102000.json','["老眼驚花暗，斜枝落紙愁。", "晚來聞冷雨，幻出一籬秋。"]'),
('486cb2db-1917-46ed-afa6-bdbfd7d62c18','次韻王性之題篠叢枯木','張元幹','宋','宋诗','song-poetry','','[]','犖确有岱華勢，輪囷無斤斧痕。',28,'全唐诗/poet.song.102000.json','["犖确有岱華勢，輪囷無斤斧痕。", "我來翻君古錦，老眼洗盡眵昏。"]'),
('f3f5bb94-b98e-45bd-a103-b7227da67d40','上平江陳侍郎十絕  其一','張元幹','宋','宋诗','song-poetry','','[]','了堂先生古遺直，貶剝私史專尊堯。',32,'全唐诗/poet.song.102000.json','["了堂先生古遺直，貶剝私史專尊堯。", "二蔡懷姦首排擊，始終大節不同朝。"]'),
('1a285740-79ab-417c-9393-4551e9513419','上平江陳侍郎十絕  其二','張元幹','宋','宋诗','song-poetry','','[]','灼見禍機寧有死，剖心立敵肯忘言。',32,'全唐诗/poet.song.102000.json','["灼見禍機寧有死，剖心立敵肯忘言。", "向來逆料無遺恨，徹底孤忠抱至寃。"]'),
('f11c791e-a91d-4f7f-9c82-15c5098a3241','上平江陳侍郎十絕  其三','張元幹','宋','宋诗','song-poetry','','[]','前賢一節皆名世，此道終身公獨行。',32,'全唐诗/poet.song.102000.json','["前賢一節皆名世，此道終身公獨行。", "每見遺編須掩泣，晚生期不負先生。"]'),
('2117a75e-59b4-49dc-ac94-4466a3532935','上平江陳侍郎十絕  其四','張元幹','宋','宋诗','song-poetry','','[]','南荒百謫愈不屈，便道忽聞天遣來。',32,'全唐诗/poet.song.102000.json','["南荒百謫愈不屈，便道忽聞天遣來。", "峨帽焚香姑拱立，果無片楮可成災。"]'),
('3aacb36f-5126-4178-a994-90a246f0fa6d','上平江陳侍郎十絕  其五','張元幹','宋','宋诗','song-poetry','','[]','酒酣怒髮上衝冠，四十年前廬阜南。',32,'全唐诗/poet.song.102000.json','["酒酣怒髮上衝冠，四十年前廬阜南。", "杖履周旋痛開警，爲言小子頗嘗參。"]'),
('31790853-da1f-436f-8016-7249ee419aa5','上平江陳侍郎十絕  其六','張元幹','宋','宋诗','song-poetry','','[]','英靈精爽平生話，尚記先生苜蓿槃。',32,'全唐诗/poet.song.102000.json','["英靈精爽平生話，尚記先生苜蓿槃。", "仙去星辰終不滅，至今夢想骨毛寒。"]'),
('b1760193-c4a3-44ce-b130-2af15b86ff1a','上平江陳侍郎十絕  其七','張元幹','宋','宋诗','song-poetry','','[]','功名啐啄與時同，譬似青天白日中。',32,'全唐诗/poet.song.102000.json','["功名啐啄與時同，譬似青天白日中。", "不覺片雲隨雨雹，適從何處運神通。"]'),
('6b4a7ea0-ed59-4df3-8051-9afbca465d1d','上平江陳侍郎十絕  其八','張元幹','宋','宋诗','song-poetry','','[]','常佩了堂一則語，睢陽舉似劉潞州。',32,'全唐诗/poet.song.102000.json','["常佩了堂一則語，睢陽舉似劉潞州。", "大期不復見丙午，二老信然成古丘。"]'),
('3f174a09-85bc-4ab6-aa2a-bbeaae0b60bd','上平江陳侍郎十絕  其九','張元幹','宋','宋诗','song-poetry','','[]','先生許可能尊祖，詞采今存幹蠱身。',32,'全唐诗/poet.song.102000.json','["先生許可能尊祖，詞采今存幹蠱身。", "碑版燦然垂世譽，要知忠肅有門人。"]'),
('3cf1cf98-1239-47f5-8743-27525adcd182','上平江陳侍郎十絕  其一○','張元幹','宋','宋诗','song-poetry','','[]','傷心頃拜公床下，一氣飄零餘幾人。',32,'全唐诗/poet.song.102000.json','["傷心頃拜公床下，一氣飄零餘幾人。", "七十衰翁誰信及，話言端欲廣書紳。"]'),
('bf68f831-6fbf-4413-a683-272512f15baf','甲戌正月十四日書所見來日驚蟄節','張元幹','宋','宋诗','song-poetry','','[]','老去何堪節物催，放燈中夜忽奔雷。',32,'全唐诗/poet.song.102000.json','["老去何堪節物催，放燈中夜忽奔雷。", "一聲大震龍蛇起，蚯蚓蝦蟆也出來。"]'),
('30c5de21-e73c-433b-9db2-9277204d3427','走筆次廷藻韻二絕  其一','張元幹','宋','宋诗','song-poetry','','[]','風雨聲中過半春，泥深郊水阻遊人。',32,'全唐诗/poet.song.102000.json','["風雨聲中過半春，泥深郊水阻遊人。", "老夫不出渾閑事，但覺年來白髮新。"]'),
('a5ae7909-9825-4670-a7d1-7ff1b179326c','走筆次廷藻韻二絕  其二','張元幹','宋','宋诗','song-poetry','','[]','小蘇一物絕風流，竹杖芒鞋愛討幽。',32,'全唐诗/poet.song.102000.json','["小蘇一物絕風流，竹杖芒鞋愛討幽。", "招隱歸來吐佳句，何時一笑共重遊。"]'),
('ab1a1504-233d-48c8-98aa-c00cb4476ac9','高尚居士  其一','張元幹','宋','宋诗','song-poetry','','[]','卜室高垣桑柘邊，空中來往盡飛仙。',32,'全唐诗/poet.song.102000.json','["卜室高垣桑柘邊，空中來往盡飛仙。", "似聞一舉三千里，更待成功上九天。"]'),
('15811509-4ef1-40a7-a090-e6305cb8d0b6','高尚居士  其二','張元幹','宋','宋诗','song-poetry','','[]','往在澶淵過我家，自憐凡骨走天涯。',32,'全唐诗/poet.song.102000.json','["往在澶淵過我家，自憐凡骨走天涯。", "丹青始識先生面，點化何時一粒砂。"]'),
('578bda52-378a-470f-94de-17723506ffb4','祖穎漕使希道使君以絕句相酬答聊成二章解嘲併發一笑  其一','張元幹','宋','宋诗','song-poetry','','[]','從渠冷蕊籬邊少，未放浮蛆甕面空。',32,'全唐诗/poet.song.102000.json','["從渠冷蕊籬邊少，未放浮蛆甕面空。", "高燭幾時催夜飲，隔簾度曲也英雄。"]'),
('6e0ad63d-0697-4367-bf02-77abf1218b89','祖穎漕使希道使君以絕句相酬答聊成二章解嘲併發一笑  其二','張元幹','宋','宋诗','song-poetry','','[]','薰爐玉煖雲生岫，曉鑑鸞窺翠掃空。',32,'全唐诗/poet.song.102000.json','["薰爐玉煖雲生岫，曉鑑鸞窺翠掃空。", "未許尊前聽金縷，兩公新句漫爭雄。"]'),
