('5a2973ff-ebdc-4f25-af9c-1079af37c76b','跋米元暉瀑布橫軸','張元幹','宋','宋诗','song-poetry','','[]','老懶天教脫世紛，山川到眼失塵昏。',32,'全唐诗/poet.song.102000.json','["老懶天教脫世紛，山川到眼失塵昏。", "絕憐千仞鳴飛瀑，一灑風中八表雲。"]'),
('a1d46e7a-6332-4068-a998-869aa6cade85','跋蘇養直絕句後','張元幹','宋','宋诗','song-poetry','','[]','後湖醉卧已仙去，但有言句留人間。',32,'全唐诗/poet.song.102000.json','["後湖醉卧已仙去，但有言句留人間。", "文采風流照千古，羅浮誰復遺金丹。"]'),
('89bf1bec-2cc6-435a-b881-14667f791836','跋江天暮雨圖','張元幹','宋','宋诗','song-poetry','','[]','千山忽暗雨來時，天末濃雲送落暉。',32,'全唐诗/poet.song.102000.json','["千山忽暗雨來時，天末濃雲送落暉。", "老眼平生飽風浪，猶憐別浦釣船歸。"]'),
('ac52bcad-e5f5-45f3-8d6a-2608ba631ff9','跋江貫道絕筆古松','張元幹','宋','宋诗','song-poetry','','[]','石根盤屈老蒼官，絕筆殷勤記歲寒。',32,'全唐诗/poet.song.102000.json','["石根盤屈老蒼官，絕筆殷勤記歲寒。", "萬里風雲欲飛化，君家留得壁間看。"]'),
('5d5ac0d2-5cce-4da6-b75d-9472314725c2','雍熙堂','張元幹','宋','宋诗','song-poetry','','[]','鼎彝勳業推元老，文采風流及後昆。',32,'全唐诗/poet.song.102000.json','["鼎彝勳業推元老，文采風流及後昆。", "家世從來耐官職，百年猶見典刑存。"]'),
('fe4a5487-c1de-4696-995a-41e40c969cf5','遊廬山','張元幹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','古木寒藤挽我住，身非靖節誰能留。',32,'全唐诗/poet.song.102000.json','["古木寒藤挽我住，身非靖節誰能留。", "多慚不及鸞溪水，長向山前山後流。"]'),
('7c963af8-ca4e-415b-a3a2-5cda1594b85e','詠二疏','張元幹','宋','宋诗','song-poetry','','[]','兩傅常存好老心，漢廷元自少知音。',32,'全唐诗/poet.song.102000.json','["兩傅常存好老心，漢廷元自少知音。", "歸來日日相娛樂，賴有君王舊賜金。"]'),
('e297f7ec-bbb2-4f02-97ea-f92d4e5f4c04','奉酬陳端中明府長韻','張元幹','宋','宋诗','song-poetry','','[]','往在識公日，我與兒曹俱。',240,'全唐诗/poet.song.102000.json','["往在識公日，我與兒曹俱。", "八齡初問字，雙鉤略摹朱。", "知爲太學生，夙仰君子儒。", "契闊三十載，邂逅天一隅。", "追數半鬼錄，宰上空美楰。", "所存復陸沉，隙中驚過駒。", "長者類太丘，祖風如魏謩。", "兵火已無屋，蓬蒿仍不鋤。", "善藏武城刀，息駕王喬鳧。", "功名有要路，矢石思捐軀。", "常揮鐵如意，欲碎玉唾壺。", "書生無浪語，天驕今既誅。", "下如鴟夷子，扁舟歸五湖。", "安用金谷園，墜樓煩綠珠。", "相國起刀筆，將軍拔屠沽。", "但封寢丘地，莫料秦王鬚。", "隱居九畹蘭，活計千木奴。", "客至徑設醴，詩來或操觚。", "遊戲百家衣，劇談五雜俎。", "涉世雖歷落，安命良支梧。"]'),
('0f50ac82-a520-4994-958b-cf5667d29ebf','送前東陽于明府由鄂渚歸故林','張元幹','宋','宋诗','song-poetry','','[]','結東征車換黑貂，灞西風雨正瀟瀟。',64,'全唐诗/poet.song.102000.json','["結東征車換黑貂，灞西風雨正瀟瀟。", "茂陵久病書千卷，彭澤初歸酒一瓢。", "帆背夕陽湓水闊，棹經滄海甑山遥。", "殷勤爲謝南溪客，白首螢窗未見招。"]'),
('e11c7ce3-e6cd-455c-ab02-887bf7170879','瑶真館','張元幹','宋','宋诗','song-poetry','','[]','廣陵祠裏尋常見，又向山陽樓外開。',32,'全唐诗/poet.song.102000.json','["廣陵祠裏尋常見，又向山陽樓外開。", "須信月明風露下，飛仙玉節有時來。"]'),
('f997d6e6-b70b-4f76-861e-a98052050d26','奉祠後作','張闡','宋','宋诗','song-poetry','','[]','八請犯天顔，今朝出漢關。',24,'全唐诗/poet.song.102000.json','["八請犯天顔，今朝出漢關。", "渾如倦飛鳥，日暮傍巢還。"]'),
('952340c3-8828-4cb4-92da-7e8482f78543','句','張闡','宋','宋诗','song-poetry','','[]','玄鯽隨鈎誠養親。',8,'全唐诗/poet.song.102000.json','["玄鯽隨鈎誠養親。"]'),
('44d9865b-e2a6-439f-95ec-ccee4736e8e8','芝華亭','龔明之','宋','宋诗','song-poetry','','[]','誰道休祥繫上穹，民心元自與天通。',32,'全唐诗/poet.song.102000.json','["誰道休祥繫上穹，民心元自與天通。", "政平訟理爲真瑞，何必金芝產梵宮。"]'),
('5e78c526-59eb-488b-8f25-3dfd5adc60c6','期頤堂  其一','龔明之','宋','宋诗','song-poetry','','[]','投老歸來萬事休，北窗一枕足清幽。',32,'全唐诗/poet.song.102000.json','["投老歸來萬事休，北窗一枕足清幽。", "雖然不得行胸臆，幸喜身無千歲憂。"]'),
('abc0eca5-8c57-4397-b56a-f6a17ad49dc2','期頤堂  其二','龔明之','宋','宋诗','song-poetry','','[]','少年已自樂杯觴，種秫安排老醉鄉。',32,'全唐诗/poet.song.102000.json','["少年已自樂杯觴，種秫安排老醉鄉。", "試問幾回供酒事，真成三萬六千場。"]'),
('991184e8-033c-4641-b805-ca22465be221','期頤堂  其三','龔明之','宋','宋诗','song-poetry','','[]','百事如今與世違，十花一木謾兒嬉。',32,'全唐诗/poet.song.102000.json','["百事如今與世違，十花一木謾兒嬉。", "莫欺兀兀癡頑老，曾睹昇平元祐時。"]'),
('e4bd060e-8dc5-4064-be5d-f5472b6c21eb','期頤堂  其四','龔明之','宋','宋诗','song-poetry','','[]','不服丹砂不茹芝，老來四體未全衰。',32,'全唐诗/poet.song.102000.json','["不服丹砂不茹芝，老來四體未全衰。", "有人問我期頤法，一味胸中愛坦夷。"]'),
('bebd4013-9b79-4b9c-8ed5-f0dfa28c053f','使金和趙良嗣','馬擴','宋','宋诗','song-poetry','','[]','未見燕銘勒故山，耳聞殊議骨毛寒。',32,'全唐诗/poet.song.102000.json','["未見燕銘勒故山，耳聞殊議骨毛寒。", "願君共事烹身語，易取皇家萬世安。"]'),
('fa17d074-dc26-4f99-8de5-565e6b105962','句','馬擴','宋','宋诗','song-poetry','','[]','未敢此時非趙括，已愁他日類田豐。',16,'全唐诗/poet.song.102000.json','["未敢此時非趙括，已愁他日類田豐。"]'),
('4054a1c9-be20-405c-8a89-975d4e15569b','道中聞九里香花','王以寧','宋','宋诗','song-poetry','','[]','不見江梅三百日，聲斷紫簫愁夢長。',32,'全唐诗/poet.song.102000.json','["不見江梅三百日，聲斷紫簫愁夢長。", "何許綠裙紅帔客，御風來獻返魂香。"]'),
('8521be3f-1c92-4dc8-b30e-0eca7146db1b','句  其一','王以寧','宋','宋诗','song-poetry','','[]','浩歌排兩脚，蒙里橫天涯。',12,'全唐诗/poet.song.102000.json','["浩歌排兩脚，蒙里橫天涯。"]'),
('779158ed-9669-43b0-825f-65ee56ca5f03','句  其二','王以寧','宋','宋诗','song-poetry','','[]','人情十里白頭浪，世事幾番黄葉風。',16,'全唐诗/poet.song.102000.json','["人情十里白頭浪，世事幾番黄葉風。"]'),
('d73cc875-36c2-421e-8b26-b853aa452b6f','題萃清閣','李處勵','宋','宋诗','song-poetry','','[]','南柯一夢還，不待黄粱熟。',132,'全唐诗/poet.song.102000.json','["南柯一夢還，不待黄粱熟。", "脫身解印綬，矯迹回林麓。", "珂聲繞危磴，旆影照飛瀑。", "殷殷倚巖峰，艷艷穿籬菊。", "佛宮古藏勝，釋子出迎肅。", "軒盈架碧崖，鐘磬響虛谷。", "好鳥獻晴語，幽蘭吐寒馥。", "少焉耻奔競，老矣厭覊束。", "游宦非養高，勇歸乃知足。", "嘯裏藏至音，琴中隱真曲。", "注目久無言，呼童取醴醁。"]'),
('ec6187cc-2673-4e7e-ae44-505246d4f77d','遊洞霄','李彙','宋','宋诗','song-poetry','','[]','至真方域古今傳，琳館興從漢武年。',160,'全唐诗/poet.song.102000.json','["至真方域古今傳，琳館興從漢武年。", "石作雙門何突兀，山爲九鎖自迴環。", "仙人隱跡留中路，處士靈壇閟遠巔。", "甘潔三泉齊湧地，崢嶸一柱獨擎天。", "群峯繚繞更相挹，五洞縈迂暗接連。", "當日高崖曾虎伏，于今深穴有龍眠。", "茂林葱鬰曾鳴鳳，邃宇清虛每聚仙。", "地貯金丹藏箬下，芝翻白鼠走巖前。", "宮隨劫火雖灰矣，境異塵寰尚儼然。", "稍待昇平名遂後，便來居此結良緣。"]'),
('5278cc7f-2e47-4277-b462-f907ccdcb934','駐馬坡','葉輝','宋','宋诗','song-poetry','','[]','將軍氣勢溢江河，躍馬曾來駐此坡。',32,'全唐诗/poet.song.102000.json','["將軍氣勢溢江河，躍馬曾來駐此坡。", "坡下石頭城最險，屯兵正自不消多。"]'),
('7e4a362c-049d-490f-a0fe-f970841590f7','秦淮次北谷羅疊韻','葉輝','宋','宋诗','song-poetry','','[]','人言王氣在鄣州，嬴政因來鑿此流。',32,'全唐诗/poet.song.102000.json','["人言王氣在鄣州，嬴政因來鑿此流。", "地脈何曾真斷得，幾多天子御宸樓。"]'),
('d2d7c098-8dae-435b-8b68-68a7b44a327e','白鷺亭次羅公愚韻','葉輝','宋','宋诗','song-poetry','','[]','白鷺洲邊敞此亭，淮山江水瞰蘆汀。',32,'全唐诗/poet.song.102000.json','["白鷺洲邊敞此亭，淮山江水瞰蘆汀。", "鷺飛點點星顔色，那似公山鶴有靈。"]'),
('1e3ba2f4-fb6f-4d56-aebc-ca927ffac776','詠清凉寺竹','葉輝','宋','宋诗','song-poetry','','[]','茂林修竹綠侵雲，清到心君賴有君。',32,'全唐诗/poet.song.102000.json','["茂林修竹綠侵雲，清到心君賴有君。", "李主當年飽凉後，民間苦熱幾曾聞。"]'),
('2c6bb601-4dbb-4ab1-82ae-f48bd1efc27d','歸崑山省親別太學同舍  其一','郭章','宋','宋诗','song-poetry','','[]','菽水年來屬未涯，羞騎款段出京華。',64,'全唐诗/poet.song.102000.json','["菽水年來屬未涯，羞騎款段出京華。", "漲塵面旋風頭緊，綺照支離日脚斜。", "掠過短莎驚脫兔，踏翻紅葉鬧歸鴉。", "不堪回首孤雲外，望斷淮山始是家。"]'),
('ba82fee1-3cac-4ac5-95d5-e233333bfc7e','歸崑山省親別太學同舍  其二','郭章','宋','宋诗','song-poetry','','[]','也知隨俗調歸策，却憶當年重出關。',64,'全唐诗/poet.song.102000.json','["也知隨俗調歸策，却憶當年重出關。", "豈是長居戶限上，可能無意馬蹄間。", "中原百甓知誰運，今日分陰敢自閒。", "倘有寸功裨社稷，歸來恰好試衣斑。"]'),
('be76139f-e1df-4b0d-8a5c-8b41f17e8a93','夕秀軒','郭章','宋','宋诗','song-poetry','','[]','柳暗西津橋步斜，長川練練若縈蛇。',32,'全唐诗/poet.song.102000.json','["柳暗西津橋步斜，長川練練若縈蛇。", "晚來不爲東風惡，與子留連待月華。"]'),
('bc80d5ef-c27a-448f-9472-7c05cc8a9ca9','躡雲亭','羅孝芬','宋','宋诗','song-poetry','','[]','出山不愧草堂靈，亂後看山山更青。',64,'全唐诗/poet.song.102000.json','["出山不愧草堂靈，亂後看山山更青。", "餘燼豈容遺大厦，躡雲端爲護危亭。", "參差春燕依華浦，斷續霜猿繞翠屏。", "物色趣君歸早晚，已看蘭玉照階庭。"]'),
('c15ea7eb-7811-4dc2-bfa9-9cc7bdc631a9','行路難','張轂','宋','宋诗','song-poetry','','[]','湘東行人長歎息，十年離家歸未得。',63,'全唐诗/poet.song.102000.json','["湘東行人長歎息，十年離家歸未得。", "敝裘羸馬苦難行，僮僕盡饑少筋力。", "君不見床頭黄金盡，壯士無顔色。", "龍蟠泥中未有雲，不能生彼昇天翼。"]'),
('61f39702-2465-4556-976e-686077eafaef','挽薛艮齋二首  其一','徐嘉言','宋','宋诗','song-poetry','','[]','卓犖才名四十秋，屢攄良策動宸旒。',64,'全唐诗/poet.song.102000.json','["卓犖才名四十秋，屢攄良策動宸旒。", "傾河議論誰能敵，唾手功勳未肯休。", "方快九霄摶鸑鷟，俄驚長坂蹶驊騮。", "天公應叱六丁下，著述文章盡捲收。"]'),
('9d7f9a41-406a-4b33-a7db-9f7da76a1f1d','挽薛艮齋二首  其二','徐嘉言','宋','宋诗','song-poetry','','[]','宦遊將適鄭公鄉，衆說膺門氣味長。',64,'全唐诗/poet.song.102000.json','["宦遊將適鄭公鄉，衆說膺門氣味長。", "欲效然明略陳語，那知叔向罷登堂。", "毗壇不試新分竹，霅水空瞻舊茇棠。", "天不憖遺何太早，忍看埋玉向高岡。"]'),
('ac00d45a-93b6-4251-a208-22c91179b153','題金粟寺庵和通判軍府周壽韻','徐嘉言','宋','宋诗','song-poetry','','[]','招提敞山巖，新庵隱巖麓。',72,'全唐诗/poet.song.102000.json','["招提敞山巖，新庵隱巖麓。", "石沼引清流，風漪皺文縠。", "晴暉滿虛室，一水含自足。", "心明身宴閑，境寂誰尋逐。", "寒林带月行，夜榻和雲宿。", "若欲問西來，一齋飽自足。"]'),
('6706281a-b83c-4af8-9c9f-dea0a0a78522','題涪陵郡','宋翰','宋','宋诗','song-poetry','','[]','錦繡洲猶在，熊羆夢已無。',48,'全唐诗/poet.song.102000.json','["錦繡洲猶在，熊羆夢已無。", "文風齊兩蜀，仙跡接三都。", "白石從天設，青崖見地圖。", "荔枝妃子圃，不復曩時輸。"]'),
('5d3e2b5a-327d-47d7-ba2a-2539eb5be850','句','宋翰','宋','宋诗','song-poetry','','[]','襟分楚澤三千里，曲奏湘妃五十絃。',16,'全唐诗/poet.song.102000.json','["襟分楚澤三千里，曲奏湘妃五十絃。"]'),
('7420c54c-6f5f-4b5c-93d5-bed6925d9214','和史經  其一','孫邦','宋','宋诗','song-poetry','','[]','淵明遇佳趣，欲辯每忘言。',120,'全唐诗/poet.song.102000.json','["淵明遇佳趣，欲辯每忘言。", "道安對勝士，高論矜彌天。", "斯人已往不可得，悠悠俗駕徒爭先。", "夢尸夢穢了不悟，甯論擲足與裸顛。", "雖知香臭在得喪，一朝十獲歲九遷。", "誰能休沐過僧語，聊問我林仍我泉。", "賢哉令尹得此趣，頗厭世味如葷羶。", "學人荐取妙香句，莫學大珠空飯眠。"]'),
('73e9dcf9-6a63-471b-ad04-d1558468de49','和史經  其二','孫邦','宋','宋诗','song-poetry','','[]','宅側造豬欄，正坐貪穢免。',228,'全唐诗/poet.song.103000.json','["宅側造豬欄，正坐貪穢免。", "巷中堆馬糞，而以清貴顯。", "二事大不侔，其眼乃能辨。", "吾徒與衲子，相去夫何遠。", "祇恐無鼻孔，當知係所踐。", "勿謂一瓣香，便解生一善。", "居心苟不凈，探洗謾盧扁。", "要令登此堂，摩詰失其□。", "深入不二門，諸臭雪見睍。", "湛然方寸間，衆妙來煙篆。", "香銷本無事，風靜雲回卷。", "當年杜陵老，所造宜不淺。", "夜宿贊公房，習氣元未殄。", "沉憂覺清夢，豈念世路蹇。", "豬欄馬糞輩，皆預公卿選。", "泥塗布渠巷，欲往傷吾跣。", "所以聞妙香，慨歎獨輾轉。", "此香爲誰來，知落處者鮮。", "何如被蒙頭，熟寐一覺遣。"]'),
('4770eab4-35f2-4892-be21-2df852bc0ed6','綠筠軒','孫邦','宋','宋诗','song-poetry','','[]','年來宦拙喜躋攀，門枕溪流四面山。',32,'全唐诗/poet.song.103000.json','["年來宦拙喜躋攀，門枕溪流四面山。", "時過隣僧話浮世，一軒長對此君閑。"]'),
('791ce680-66ae-4afc-ace9-7b31d9bdf1c6','唐氏林亭','孫邦','宋','宋诗','song-poetry','','[]','華屋沈沈野外居，茂林清蔭繞門閭。',64,'全唐诗/poet.song.103000.json','["華屋沈沈野外居，茂林清蔭繞門閭。", "移花植果心無事，抱子弄孫歡有餘。", "閑過西疇觀刈穫，懶尋南郭命巾車。", "問君爲圃嗟予晚，便擬歸休學二疏。"]'),
('c904b0d3-87b4-4502-8e8b-e540dcaefd04','白蓮堂  其一','孫邦','宋','宋诗','song-poetry','','[]','大智西歸不肯回，只今蓮社喜重開。',32,'全唐诗/poet.song.103000.json','["大智西歸不肯回，只今蓮社喜重開。", "會中獨有遺民在，十五年間兩度來。"]'),
('970f8a8a-9984-43b5-bd7a-45f2306069a7','白蓮堂  其二','孫邦','宋','宋诗','song-poetry','','[]','心地白蓮俱有種，要須功德水方開。',32,'全唐诗/poet.song.103000.json','["心地白蓮俱有種，要須功德水方開。", "因師一語千花現，人各始知來處來。"]'),
('49f604a5-bd1c-409e-a8fb-f0915800c8e5','呂城謁祖廟','孫邦','宋','宋诗','song-poetry','','[]','吾祖持兵鎮此都，投身九死定全吳。',64,'全唐诗/poet.song.103000.json','["吾祖持兵鎮此都，投身九死定全吳。", "一朝流矢中眸子，千載忠魂列霸圖。", "墓木但遺楓合抱，廟庭還有像完軀。", "英雄未必輸張許，青史功名定有無。"]'),
('085be23a-9ddf-4b67-a45c-a6447dbb6886','滄浪亭','胡珵','宋','宋诗','song-poetry','','[]','昔聞滄浪亭，未濯滄浪水。',204,'全唐诗/poet.song.103000.json','["昔聞滄浪亭，未濯滄浪水。", "先賢眇遺跡，壯觀一何侈。", "飛橋跨木末，巨浸折胡壘。", "糟床行萬甕，繚牆周數里。", "廢興固在天，庶用觀物理。", "緬懷嘉祐世，周道平如砥。", "相君賢相君，子美東南美。", "如何一網盡，禍豈在故紙。", "青蠅變白黑，作俑茲焉始。", "所存醉翁文，垂耀信百世。", "無忘角弓詠，嘉樹猶仰止。", "同來二三子，感歎咸坐起。", "縹瓷釂新汲，毀譽均一洗。", "忽逢醒狂翁，一別垂二紀。", "雋哉老益壯，論事方切齒。", "我欲裂絳幔，推著明光裏。", "安得上天風，吹落君王耳。"]'),
('56151e70-f782-4845-a28a-397a4796fd3b','遊秀峰寺','胡珵','宋','宋诗','song-poetry','','[]','攝身下蓬萊，放浪雲水迹。',192,'全唐诗/poet.song.103000.json','["攝身下蓬萊，放浪雲水迹。", "非無簡書畏，心賞寄泉石。", "亭亭雲間塔，勝地聞自昔。", "梯空上青冥，如鳥著兩翼。", "化城出天半，寶甃坦如席。", "環山劃中斷，裂地開震澤。", "峨峨東西峰，觀闕倚空碧。", "千尋採香遥，劍卧漣漪直。", "當年館娃宮，六月避暑夕。", "琴臺延薰風，萬女曳阿錫。", "牛耳爭齊盟，烏喙已荐食。", "百家甬東村，託足歸無宅。", "焉知陵谷變，大厦響千舄。", "矧茲風塵際，樓殿踴山脊。", "安隱大火中，顯允像教力。", "興予浩劫嘆，萬法本空寂。"]'),
('778e4797-5772-4de5-82f2-71d87260c496','楓橋','胡珵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','朝辭海涌千人石，暮宿楓橋半夜鐘。',32,'全唐诗/poet.song.103000.json','["朝辭海涌千人石，暮宿楓橋半夜鐘。", "明日館娃宮裏去，洞庭呼起一帆風。"]'),
('e5d0fada-d859-4c2c-8b23-410f3be41e89','題天慶觀畫龍','胡珵','宋','宋诗','song-poetry','','[]','道人龍中來，醉與神物會。',120,'全唐诗/poet.song.103000.json','["道人龍中來，醉與神物會。", "寫茲蜿蜒質，日月爲冥晦。", "崩翻江海姿，素壁起濤瀨。", "呼吸見雌雄，抉石疑可碎。", "肅森殿陰古，衆真儼飛旆。", "注觀恐騰躍，夜半失像繪。", "飛光著明珠，靈秘一何怪。", "爛爛照甍棟，那得久在外。", "偷兒伺酣睡，不怕嬰鱗害。", "願言慎所托，未用期一快。"]'),
('3b88eec3-2311-499f-be0b-31064701a5b1','題智寶院','胡珵','宋','宋诗','song-poetry','','[]','六代煙塵息，千年象教尊。',24,'全唐诗/poet.song.103000.json','["六代煙塵息，千年象教尊。", "衣冠悲故里，聚落見荒村。"]'),
('acecb10f-658b-4429-856a-eba4fdaaa8b5','題定山梵放軒','胡珵','宋','宋诗','song-poetry','','[]','道人避世氛，山腰著祇園。',120,'全唐诗/poet.song.103000.json','["道人避世氛，山腰著祇園。", "千夫斸青冥，豁達窗戶搴。", "鬼神間施設，儼護龍象筵。", "法鼓空中鳴，龍卧層崖巔。", "幽靈駭今昔，異事樵夫傳。", "眷茲水雲侶，精賞託妙緣。", "努力辦己事，追駕佛祖肩。", "憑高發鐘磬，梵音落諸天。", "况時解禪縛，迢遥倚層軒。", "放意萬物外，目送孤鴻翩。"]'),
('dea9371b-f111-477f-80aa-5684156b0179','有客','林季仲','宋','宋诗','song-poetry','','[]','有客有客，託於空谷。',160,'全唐诗/poet.song.103000.json','["有客有客，託於空谷。", "問何以樂，樂彼幽獨。", "矯矯其松，藋藋其竹。", "微風過之，泠然成曲。", "歲曰莫止，霰雪交揮。", "誰與晤語，懷我人斯。", "我之懷矣，褰裳從之。", "泥淖伊阻，中心悵而。", "豈無他人，以翱以翔。", "意氣所親，不能弭忘。", "遥遥遺緒，久矣弗敭。", "之子之秀，吾宗之光。", "我有薄酒，子試歠兮。", "雪霽江明，共此月兮。", "企焉新詩，到蟄窟兮。", "老子鬅鬙，正愁絕兮。"]'),
('58ee8c89-3ca8-46f6-87cb-d78f013bd28f','觀徐孺子畫像','林季仲','宋','宋诗','song-poetry','','[]','伯淮卧彭城，遶屋生蓬茨。',108,'全唐诗/poet.song.103000.json','["伯淮卧彭城，遶屋生蓬茨。", "天子呼不起，思見巖壑姿。", "俾工圖其形，銜命日夜馳。", "落筆竟不得，韜面以疾辭。", "豫章有孺子，同時隱江湄。", "栖栖非我事，結廬對風漪。", "時人亦罕識，阿堵誰寫之。", "我聞郭有道，曾遣輕騎追。", "疑此言語生，即是茅畫師。"]'),
('721c5be9-ff7a-45de-80df-a5bfee587ba2','送真歇禪師','林季仲','宋','宋诗','song-poetry','','[]','我與真歇師，同年五十八。',288,'全唐诗/poet.song.103000.json','["我與真歇師，同年五十八。", "對之意頹然，百事付華髮。", "買舟繫籬傍，一日來告別。", "挽之不肯留，徑山演法切。", "佛法果何如，請師爲指訣。", "俯首無一言，苦欲相泯滅。", "余漫述所聞，此法本無缺。", "山河連大地，鳥獸暨魚鼈。", "微至一蠛蠓，中含大千闊。", "試即此身求，萬象皆森列。", "聲色臭味等，六根能剖决。", "阿誰使之然，未可計巧拙。", "盍亦返故鄉，子細自披抉。", "當有無價珍，終身用不徹。", "胡爲浪馳走，千里訪名剎。", "環立廣坐下，覷人摇輔頰。", "譬如坐海底，巨浸從頭沒。", "反問岸上人，覓水濟我渴。", "師聞抵掌笑，却道我饒舌。", "徑山堂未開，居士法先說。", "儒生玩韋編，貝葉師所閱。", "兩家相詬病，久矣互侵伐。", "孰如吾二人，一見意軒豁。", "縱談這箇事，迴出言詞末。"]'),
('9c6baba9-538f-4f5b-bcd7-f4de04c48566','秋熱次高仲貽韻  其一','林季仲','宋','宋诗','song-poetry','','[]','乘時火初流，執熱病未脫。',294,'全唐诗/poet.song.103000.json','["乘時火初流，執熱病未脫。", "踏冰思少蘇，坐甑哀苟活。", "雲意斷渰渰，雨聲閟{洱舌}{洱舌}。", "安用天官爲，不悟秋序奪。", "巫尪暴何辜，夸父僵且渴。", "熂山將焚燒，翻海欲灑潑。", "蛟龍遁寂寞，蠅蚋恣喧聒。", "瘴鳶時墮水，涸魚暫濡沫。", "斯焉禾不登，往矣穗奚掇。", "衆心禱不昧，羣望走莫遏。", "殷勤聞雷行，閃閃驚電抹。", "嘉澍疑盆翻，脫葉逾帚捋。", "汲井憶羸瓶，承霤爭羅鉢。", "新凉來不斷，濁水去如割。", "未論沴氣銷，陡覺煩襟豁。", "遂回望電眼，免蹙憂稼頞。", "一飽茲可營，百慮何勞㔇。", "明公軫慈仁，此道歸包括。", "世事有反覆，愁腸屢迴斡。", "栖栖同里甿，閔閔憂旱魃。", "賦詩輸悃悰，盈軸辦嗟咄。", "句圓珠走盤，意定弦在筈。", "千仞徒仰高，一葦敢杭闊。", "韜疵知含洪，策蹇終臲卼。"]'),
('9f665787-e5ac-4d82-875f-10af89c4d4a3','秋熱次高仲貽韻  其二','林季仲','宋','宋诗','song-poetry','','[]','坐我甑釜中，逾月不得脫。',291,'全唐诗/poet.song.103000.json','["坐我甑釜中，逾月不得脫。", "勞生亦何聊，喘喘覓少活。", "駕言往空谷，卧聽驚瀨{洱舌}。", "遭逢褦襶子，此事又中奪。", "天公不我憐，定爲化鄧渴。", "一夜翻河漢，散作珠璣潑。", "檐垂素練直，柏枕鳴聒聒。", "更饒窗戶間，蕭瑟濺飛沫。", "老火謝餘暉，削跡去如掇。", "乃知造化心，潛通本無遏。", "繁暑移清凉，變化在一抹。", "田父有喜言，儂得壟穗捋。", "却憶灌溉時，搰搰抱甕鉢。", "王者仁如天，寸物惡傷割。", "獨愛夏日長，器度何不豁。", "向隅泣一夫，滿堂蹙其頞。", "餘凉止殿閣，蕪垢直可㔇。", "我願均此施，遠邇歸囊括。", "措意膚寸間，六合可旋斡。", "寧容凶逆儔，肆虐爲旱魃。", "掣電備麾旟，鞭雷供叱咄。", "號令挾風行，聲飛齊萬筈。", "腥羶悉蕩攘，再見天地闊。", "孰與長畏人，朝夕懷臲卼。"]'),
('6e8da940-c978-4b45-8b09-5ab176440df1','秋熱次高仲貽韻  其三','林季仲','宋','宋诗','song-poetry','','[]','癡暑如癡人，吝權不肯脫。',291,'全唐诗/poet.song.103000.json','["癡暑如癡人，吝權不肯脫。", "凉風戒七月，尚貪朝夕活。", "雲雷動地來，一夜雨聲{洱舌}。", "老火無晶光，奔迸氣褫奪。", "我思疏仲翁，千載猶饑渴。", "父子腰金黄，照眼光潑潑。", "車馬趨其門，市井等讙聒。", "從容相與言，身名如聚沫。", "功成不還鄉，患至將誰掇。", "相隨出關去，浩然不可遏。", "挽飲東都門，頹顔酒微抹。", "迎迓走兒童，爭取霜髯捋。", "歌呼接日夜，彈筑雜擊鉢。", "時時問餘金，趣賣供釃割。", "落落丈人行，器度自軒豁。", "子孫汝何知，徒蹙求田頞。", "邇來宦途險，憑誰爲鏟㔇。", "冥行罥荆棘，進退俱有括。", "胡不觀四時，寒暑遞推斡。", "强聒不知幾，斥逐齊旱魃。", "得失何怪事，書空漫咄咄。", "要須慎其初，毋輕弦去筈。", "我本一散翁，涉世多迂闊。", "何如二大夫，安枕無臲卼。"]'),
('ef809425-989c-4be2-9efd-6e230c6050f0','謝李端明惠李翰林集','林季仲','宋','宋诗','song-poetry','','[]','江漢滔滔去不回，幾人留得詩名來。',256,'全唐诗/poet.song.103000.json','["江漢滔滔去不回，幾人留得詩名來。", "要須洗以千斛水，莫令胸臆生纖埃。", "清狂我愛李太白，亂之鷗鷺誰嫌猜。", "一生事業在杯酒，富貴於我何有哉。", "長安市上喚不醒，醉眼徐爲君王開。", "揮毫散霧金鑾殿，氣使權倖如奴儓。", "風騷獨步千載上，鞭撻揚馬咍鄒枚。", "長流夜郎得不死，定知造物須憐才。", "文采至今獨未泯，耳孫氣象何崔嵬。", "寤言世士少風骨，慨然力欲扶衰頹。", "刊傳家集流海內，廉頑立懦茲爲媒。", "分頒亦及蓬蓽士，使者踏破階前苔。", "神交不待讀終卷，騎鯨恍惚來瑶臺。", "氣酣日落酒不足，更挽天河注玉杯。", "嗚呼俗隘直可哀，吾非斯人誰與陪。", "朝遊蓬萊夕方丈，去去相隨翔九垓。"]'),
('1f03bcf7-09ec-4516-8501-4fc0e7a063f7','次韻酬黄季章','林季仲','宋','宋诗','song-poetry','','[]','長安公子意氣豪，笑我憔悴居蓬蒿。',96,'全唐诗/poet.song.103000.json','["長安公子意氣豪，笑我憔悴居蓬蒿。", "人生栖託一枝足，何用摶風九萬高。", "我今百事付流水，歸卧北窗心獨喜。", "林表春禽自在啼，絕勝豢養金籠裏。", "誰能胸臆無塵垢，木雁未論才不才。", "子陵事業亦何有，風月凄然一釣臺。"]'),
('1fddfea1-552d-4918-97d4-e036ef8891e7','天柱峰','林季仲','宋','宋诗','song-poetry','','[]','尋勝權輿自天姥，芒鞋踏遍春山雨。',96,'全唐诗/poet.song.103000.json','["尋勝權輿自天姥，芒鞋踏遍春山雨。", "要得山如磊落人，紛紛拳石何足數。", "忽逢一柱插天寒，形貌最尊疑父祖。", "羣峯往往皆兒孫，環列膝前仍俯傴。", "我憂穹昊欲撐柱，莫笑杞人心獨苦。", "伊誰有力能致之，大庇蒼生使安堵。"]'),
('cace6ef6-5ce7-4c8e-9e80-da1aa569e49c','陪館中諸人遊天竺分得香字','林季仲','宋','宋诗','song-poetry','','[]','不到八年久，重來雙鬢蒼。',48,'全唐诗/poet.song.103000.json','["不到八年久，重來雙鬢蒼。", "珠璣濺寒溜，笙磬咽風篁。", "啼鳥千林晚，飛花一路香。", "吾宗故廬在，立馬傍殘陽。"]'),
('82e3cb12-3744-4950-a073-6e8d1894d70d','中秋不見月','林季仲','宋','宋诗','song-poetry','','[]','淹淹一夜雨，脈脈萬方情。',48,'全唐诗/poet.song.103000.json','["淹淹一夜雨，脈脈萬方情。", "勿怪雲多妬，從來物惡盈。", "水渾珠自瑩，垢盡鏡還明。", "共賞此時月，無論陰與晴。"]'),
('b9f97adc-5ae0-484e-8108-d11cd1bcda95','次韻陳明錫見寄  其一','林季仲','宋','宋诗','song-poetry','','[]','一別從京洛，相逢向海邦。',48,'全唐诗/poet.song.103000.json','["一別從京洛，相逢向海邦。", "倦遊憐舌在，多病覺眉龐。", "佳處隨山屐，餘生付酒缸。", "新詩眩老眼，細讀傍寒窗。"]'),
('c4481714-e4c9-4f23-81ff-d8bbb13deacd','次韻陳明錫見寄  其二','林季仲','宋','宋诗','song-poetry','','[]','合去趨華闕，難教滯陋邦。',48,'全唐诗/poet.song.103000.json','["合去趨華闕，難教滯陋邦。", "悲鳴憐老驥，迎吠厄羣龐。", "便腹書千篋，濡頭酒一缸。", "懷君夜不寐，落葉打空窗。"]'),
('13ebd4e2-4793-4e17-b856-8450abfe2fe0','次韻陳明錫見寄  其三','林季仲','宋','宋诗','song-poetry','','[]','卑棲安故里，薄宦倦他邦。',48,'全唐诗/poet.song.103000.json','["卑棲安故里，薄宦倦他邦。", "依社願爲櫟，滌牲寧用龐。", "利名蛾赴燭，身世蟻浮缸。", "多謝江邊月，相尋到小窗。"]'),
('57718125-9d26-4c01-b298-80c81ea96c41','周希父見寄次韻','林季仲','宋','宋诗','song-poetry','','[]','松菊荒三徑，風塵走十年。',48,'全唐诗/poet.song.103000.json','["松菊荒三徑，風塵走十年。", "家山憶到骨，世路厭摩肩。", "懶計詩工拙，寧分酒聖賢。", "從他誚便腹，老去只貪眠。"]'),
('389166b0-9047-44f0-bb71-8e4215f9ddc8','次韻蕭德起見寄','林季仲','宋','宋诗','song-poetry','','[]','漫求三釜祿，浪走十年塵。',48,'全唐诗/poet.song.103000.json','["漫求三釜祿，浪走十年塵。", "白髮不饒我，虛名能中人。", "溪山閒始見，魚鳥靜相親。", "共對一庭月，誰非吾近鄰。"]'),
('ecb520f7-2c2f-4c7b-b808-1b7c31f10314','陪趙守登樓賞紅梅','林季仲','宋','宋诗','song-poetry','','[]','大潔時爭嫉，獨醒人更疑。',48,'全唐诗/poet.song.103000.json','["大潔時爭嫉，獨醒人更疑。", "漫隨春色媚，不改歲寒姿。", "霞带壽陽臉，酒融姑射肌。", "憑誰慰孤寂，新有倚樓詩。"]'),
('8fb6e8d0-3767-462e-97a9-d42a7a6af720','錢塘別諸同年','林季仲','宋','宋诗','song-poetry','','[]','晚色明沙際，春愁挂柳邊。',48,'全唐诗/poet.song.103000.json','["晚色明沙際，春愁挂柳邊。", "相逢一尊酒，難值七同年。", "聚散雁遵渚，行藏魚在淵。", "西興殘夜月，獨照渡頭船。"]'),
('50b4cc79-3154-4aaf-b0f3-042f48375133','昨夜夢陪後乘次前韻','林季仲','宋','宋诗','song-poetry','','[]','落花迷曉徑，零露點秋畦。',48,'全唐诗/poet.song.103000.json','["落花迷曉徑，零露點秋畦。", "節物驚衰鬢，登臨憶故棲。", "蒼苔痕過履，修竹濕新題。", "昨夜寒窗夢，相隨疊嶂西。"]'),
('5ada89ff-3428-4fb1-889e-86e15d9468ef','感興','林季仲','宋','宋诗','song-poetry','','[]','慶弔何時已，勞生不自閒。',48,'全唐诗/poet.song.103000.json','["慶弔何時已，勞生不自閒。", "野情難脫略，人事足機關。", "附尾初無意，同塵半强顔。", "柴門當却掃，未敢負雲山。"]'),
('4ae32703-7371-46a3-b601-e5c2c36cc97a','和人對雪','林季仲','宋','宋诗','song-poetry','','[]','匽薄一樽酒，栖遲雙鬢毛。',48,'全唐诗/poet.song.103000.json','["匽薄一樽酒，栖遲雙鬢毛。", "隨風散檐雪，卷地作秋濤。", "漢使去不返，邊人寒更勞。", "誰當如李愬，乘間縛酋豪。"]'),
('a6fa1006-7ff4-4b58-8a47-c9b2a3efd63a','贈別陳給事','林季仲','宋','宋诗','song-poetry','','[]','仕途多汩沒，歸袖獨飄颺。',48,'全唐诗/poet.song.103000.json','["仕途多汩沒，歸袖獨飄颺。", "要伴赤松子，終辭青瑣郎。", "水雲寬處好，日月靜中長。", "萬事休回首，停橈即故鄉。"]'),
('b0740af4-c815-441b-b07a-d8bd751e4ba3','陪樞密諸丈遊赤松迫於還城阻爲寶峰之集情見於詩','林季仲','宋','宋诗','song-poetry','','[]','村迥雲連屋，溪晴水繞畦。',48,'全唐诗/poet.song.103000.json','["村迥雲連屋，溪晴水繞畦。", "半生嗟薄宦，隨處愜幽棲。", "散策尋遺跡，披塵識舊題。", "夕陽催上馬，不到寶峯西。"]'),
('793f9c1d-40ad-4cd5-8033-d2ddd1f37018','中秋次韻','林季仲','宋','宋诗','song-poetry','','[]','一葉下庭木，初敲窗戶秋。',48,'全唐诗/poet.song.103000.json','["一葉下庭木，初敲窗戶秋。", "陰雲偏妬月，衰病懶登樓。", "勳業頭先白，江河淚未收。", "停橈是吾土，休夢野堂遊。"]'),
('3ac16538-4dcf-48ca-a22e-070ce771ce8e','憩瑞安北湖詩三首  其一','林季仲','宋','宋诗','song-poetry','','[]','去去春無語，融融物自驕。',48,'全唐诗/poet.song.103000.json','["去去春無語，融融物自驕。", "餉耕憐野老，隨犬過山橋。", "晚唱緣溪口，晴暉絆柳腰。", "迂儒欲何用，只合伴漁樵。"]'),
('467cbe03-1c24-45ba-bbaa-d321738d8742','憩瑞安北湖詩三首  其二','林季仲','宋','宋诗','song-poetry','','[]','逕深松翠重，風軟馬蹄驕。',48,'全唐诗/poet.song.103000.json','["逕深松翠重，風軟馬蹄驕。", "水遶誰家屋，門飛小竹橋。", "龜開平野兆，蜂引斷山腰。", "生理吾能免，趨林拾墮樵。"]'),
('f206698c-a888-409e-bbcd-93481a5f4198','憩瑞安北湖詩三首  其三','林季仲','宋','宋诗','song-poetry','','[]','吐晴林雨薄，弄水夕陽驕。',48,'全唐诗/poet.song.103000.json','["吐晴林雨薄，弄水夕陽驕。", "風定雲橫野，馬鳴人度橋。", "蘚斑封石骨，花影動溪腰。", "誰破南窗夢，空山落斷樵。"]'),
('c234b16c-f4f4-4e02-8dad-aa72c17f1155','次韻婺州蕭教授見寄','林季仲','宋','宋诗','song-poetry','','[]','不到雙溪久，渾疑一夢間。',48,'全唐诗/poet.song.103000.json','["不到雙溪久，渾疑一夢間。", "把君詩在手，見我別來山。", "薄宦故不惡，危塗難自閒。", "翩翩出林翼，飛倦合知還。"]'),
('87ebac6a-2d7c-45d6-a671-980e84862ce0','贈趙遂甫別','林季仲','宋','宋诗','song-poetry','','[]','才擅金枝秀，名標桂籍先。',48,'全唐诗/poet.song.103000.json','["才擅金枝秀，名標桂籍先。", "有如此公子，不負我同年。", "風落松間雪，沙明竹外船。", "天涯人老矣，尊酒憶凄然。"]'),
('7f2648a8-c693-4c1d-97a6-50bc88c73eaf','贈李舉之別','林季仲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','摛藻才何贍，哦松志未酬。',48,'全唐诗/poet.song.103000.json','["摛藻才何贍，哦松志未酬。", "奉祠得南嶽，戲綵向丹丘。", "賈誼方年少，馮唐已白頭。", "桃花烟浪暖，看子上瀛洲。"]'),
('335ea24e-6f3e-430d-82ce-d827bfb1c576','晚眺二首  其一','林季仲','宋','宋诗','song-poetry','','[]','秋色澹脩渚，夕光明小樓。',48,'全唐诗/poet.song.103000.json','["秋色澹脩渚，夕光明小樓。", "溪虛煙漠漠，天迥雁悠悠。", "短髮存堪數，黄花插自羞。", "青山本無事，斂黛爲誰憂。"]'),
('7d0a095c-1a5d-4003-acce-76b17800788f','晚眺二首  其二','林季仲','宋','宋诗','song-poetry','','[]','病與老相守，慵思靜自便。',48,'全唐诗/poet.song.103000.json','["病與老相守，慵思靜自便。", "故園三徑菊，歸路一蓑烟。", "高下雲連谷，縱橫水護田。", "凄凉千古事，簇簇夕檐前。"]'),
('356cba16-e1f8-465c-a556-5e7e5586eb5f','項居士挽詞','林季仲','宋','宋诗','song-poetry','','[]','孝友從初歲，溫恭見隱居。',48,'全唐诗/poet.song.103000.json','["孝友從初歲，溫恭見隱居。", "誰云不爲政，只此是知書。", "末俗惟多僞，何人得似渠。", "春江照丹旐，恨亦到龜魚。"]'),
('547ddc19-21d3-4088-ad11-5a2d3cdf8ec5','潘居士挽詞','林季仲','宋','宋诗','song-poetry','','[]','君家多隱德，自昔賦閒居。',48,'全唐诗/poet.song.103000.json','["君家多隱德，自昔賦閒居。", "不用毛錐子，甘乘下澤車。", "李衡千樹橘，范琰一園蔬。", "夫婦仍同穴，亂離誰似渠。"]'),
('97ec63b8-61ba-45a0-9f6c-b287c065472c','袁居士挽詞','林季仲','宋','宋诗','song-poetry','','[]','君看袁居士，蒼然松柏姿。',48,'全唐诗/poet.song.103000.json','["君看袁居士，蒼然松柏姿。", "生涯一樽酒，事業五言詩。", "去跨月邊鶴，空餘床下龜。", "江村相送處，尚憶杖過眉。"]'),
('1c961f97-1e1a-4d7f-9bd9-e7c57bd45fcb','挽林潜聖先生詞','林季仲','宋','宋诗','song-poetry','','[]','省己知爲政，忘言是讀書。',48,'全唐诗/poet.song.103000.json','["省己知爲政，忘言是讀書。", "世儒誰說此，學子可憐渠。", "文物思前輩，風烟翳故廬。", "倚楹獨長歎，吾道竟何如。"]'),
('28bc3057-2f38-46db-af7a-470b20348814','胡夫人挽詞','林季仲','宋','宋诗','song-poetry','','[]','自昔衣冠盛，人言胡與吳。',48,'全唐诗/poet.song.103000.json','["自昔衣冠盛，人言胡與吳。", "詩書漸漬久，婦女見聞殊。", "鳳去憐雛弱，鸞吟歎影孤。", "靈龜表賢德，卜地得慈湖。"]'),
('3ac6b48d-84c0-4491-b192-eeca48f9d8fd','柳夫人挽詞','林季仲','宋','宋诗','song-poetry','','[]','風俗日云薄，典刑終未泯。',48,'全唐诗/poet.song.103000.json','["風俗日云薄，典刑終未泯。", "請看列女傳，今有柳夫人。", "色養金章貴，褒封鈿軸新。", "凄凉板輿路，却見小梅春。"]'),
('7a3d111b-afd5-4a93-aaed-18e23c05b693','悼潘君秀才','林季仲','宋','宋诗','song-poetry','','[]','投筆辭場屋，携錢送酒家。',48,'全唐诗/poet.song.103000.json','["投筆辭場屋，携錢送酒家。", "身名俱夢幻，醒醉是生涯。", "沙晚號寒雁，林高慘暮鴉。", "嗟予方哭弟，清淚墮悲笳。"]'),
('1fd8cab5-4784-4e8f-99bf-145658016d99','沈朝議挽詞','林季仲','宋','宋诗','song-poetry','','[]','擢第繇元祐，封侯迨紹興。',48,'全唐诗/poet.song.103000.json','["擢第繇元祐，封侯迨紹興。", "曠懷初不競，薄俗漫多能。", "勳業一壺酒，交遊八尺籐。", "諸生話鄉老，揮淚溼寒燈。"]'),
('bf014bad-cf4c-4f92-9204-98015688636d','趙寶學挽詞二首  其一','林季仲','宋','宋诗','song-poetry','','[]','珠海光無盡，瑶山氣自溫。',48,'全唐诗/poet.song.103000.json','["珠海光無盡，瑶山氣自溫。", "鴻基開烈祖，餘慶襲賢孫。", "妙墨潛虬動，雄詞駭浪翻。", "九重應震悼，同性失毛原。"]'),
('73e4e5a6-2a89-4c97-b3d7-c1e811556108','趙寶學挽詞二首  其二','林季仲','宋','宋诗','song-poetry','','[]','粲粲霜蕤晚，凄凄烟渚秋。',48,'全唐诗/poet.song.103000.json','["粲粲霜蕤晚，凄凄烟渚秋。", "長隨山簡馬，同上謝公樓。", "詩句入飛鶩，歌聲落釣舟。", "那知倚欄處，直北是松楸。"]'),
('9c25af7d-c554-42a7-93a4-768685f36d03','程顯學挽詞二首  其一','林季仲','宋','宋诗','song-poetry','','[]','卓犖千人傑，飛騰四十秋。',48,'全唐诗/poet.song.103000.json','["卓犖千人傑，飛騰四十秋。", "才應有餘刃，事不見全牛。", "持節半諸道，分符知幾州。", "終遺搢紳恨，不作富民侯。"]'),
('b4c077f3-3bbc-4e66-a3d3-4ef7dd6ab4cb','程顯學挽詞二首  其二','林季仲','宋','宋诗','song-poetry','','[]','憶向沙頭別，誰知地下遊。',48,'全唐诗/poet.song.103000.json','["憶向沙頭別，誰知地下遊。", "祠堂只如舊，庭竹自生秋。", "回首山埋玉，傷心月滿樓。", "慎江日夜去，中有淚俱流。"]'),
('08cf89bd-7a3d-4772-b2f2-ffa8a6450c69','哭薛吏部  其一','林季仲','宋','宋诗','song-poetry','','[]','伯仲皆登第，人言薛與林。',48,'全唐诗/poet.song.103000.json','["伯仲皆登第，人言薛與林。", "凄凉五年事，摧折兩家心。", "漫醉春來酒，誰同別後襟。", "空餘釣磯在，落日見孤岑。"]'),
('7128a370-6efb-40d3-ace2-3da3303c4e8d','哭薛吏部  其二','林季仲','宋','宋诗','song-poetry','','[]','白鹿春城下，黄牛古壟頭。',48,'全唐诗/poet.song.103000.json','["白鹿春城下，黄牛古壟頭。", "年年喚兄弟，兩兩酹松楸。", "今日逢寒食，哀君返故丘。", "榮懷多少恨，不逐晚雲收。"]'),
('d2080304-2f5c-4ef3-82f2-250caf87f167','周希父挽詞','林季仲','宋','宋诗','song-poetry','','[]','憶昔同年友，吾鄉有六人。',48,'全唐诗/poet.song.103000.json','["憶昔同年友，吾鄉有六人。", "而今如夢寐，强半委埃塵。", "雲護霜天晚，梅含野逕春。", "回頭賦詩處，清淚墮江濱。"]'),
('8e04619f-08c6-424e-98fa-3a18260a46d7','許厚之挽詞','林季仲','宋','宋诗','song-poetry','','[]','跋馬西州路，山川淚眼傍。',48,'全唐诗/poet.song.103000.json','["跋馬西州路，山川淚眼傍。", "看君有遺範，如我見橫塘。", "寒日低瓜步，浮雲接建康。", "隔江多少恨，付與雁南翔。"]'),
('c0ec4e94-d49e-43fa-91df-81423dc41f3d','戴唐卿挽詞','林季仲','宋','宋诗','song-poetry','','[]','湖海長爲客，干戈僅脫身。',48,'全唐诗/poet.song.103000.json','["湖海長爲客，干戈僅脫身。", "來尋林下友，半與鬼爲鄰。", "馬上人何在，庭前草自春。", "平生饒意氣，寂寞委荆榛。"]'),
('d07363a2-e332-4569-a38b-913c9464a20f','次韻希父見寄二首  其一','林季仲','宋','宋诗','song-poetry','','[]','晚窗落莫雪飛花，點綴山翁兩鬢華。',64,'全唐诗/poet.song.103000.json','["晚窗落莫雪飛花，點綴山翁兩鬢華。", "好辦青銅買村酒，共撐小艇訪漁家。", "覺非便合如陶令，得趣何勞問孟嘉。", "只怕故人騰踏去，短檠誰與話天涯。"]'),
('b68aadc1-303c-4061-ba66-4a717c85d676','次韻希父見寄二首  其二','林季仲','宋','宋诗','song-poetry','','[]','臘前牆角見梅花，雪後牆頭見月華。',64,'全唐诗/poet.song.103000.json','["臘前牆角見梅花，雪後牆頭見月華。", "滿引濁醪無一事，盡收好處入吾家。", "結廬君待歸安固，抱甕儂今老永嘉。", "莫道青山便遮斷，春風浩蕩沒津涯。"]'),
('189aaed8-29f8-477e-9288-b4684f181cb6','次高季應韻','林季仲','宋','宋诗','song-poetry','','[]','杖屨相從秋水濱，便將公作社中人。',64,'全唐诗/poet.song.103000.json','["杖屨相從秋水濱，便將公作社中人。", "酒行苦要深浮白，醉去那知倒著巾。", "把手共憐江國月，回頭休憶野堂春。", "太平未見身先老，看取吳霜點鬢新。"]'),
('1634cdb7-e753-4b63-aca9-d43437881c32','次韻林楙南見寄  其一','林季仲','宋','宋诗','song-poetry','','[]','轉首今吾非故吾，問君何用惜居諸。',64,'全唐诗/poet.song.103000.json','["轉首今吾非故吾，問君何用惜居諸。", "流年已作悠悠夢，往事徒勞咄咄書。", "濁酒半壺時自酌，醉頭一月不曾梳。", "阿誰似我渾無事，睡到日高三丈餘。"]'),
('07f9c16f-2d32-4dae-9d99-f7e7e897f106','次韻林楙南見寄  其二','林季仲','宋','宋诗','song-poetry','','[]','陰陰松竹滿東山，聞說君家六月寒。',64,'全唐诗/poet.song.103000.json','["陰陰松竹滿東山，聞說君家六月寒。", "若得封胡同里巷，底須屈宋作衙官。", "酒中有趣誰能識，琴上無弦我亦彈。", "試問廬江何彥德，貂蟬孰似鹿皮冠。"]'),
('d28dae64-b75d-46c4-8128-5429d964eae1','移竹次林英伯韻四首  其一','林季仲','宋','宋诗','song-poetry','','[]','蒼苔斲破斧痕新，移傍頹檐慰病身。',64,'全唐诗/poet.song.103000.json','["蒼苔斲破斧痕新，移傍頹檐慰病身。", "見我渾如舊相識，此君端是箇中人。", "孤高自比西山潔，澹泊寧甘南巷貧。", "夢斷啼鴉窗轉月，憐渠猶把影相親。"]'),
('abd343ec-18f8-463f-a5e6-9ac9b4465988','移竹次林英伯韻四首  其二','林季仲','宋','宋诗','song-poetry','','[]','不向窗前著色新，老夫無處可安身。',64,'全唐诗/poet.song.103000.json','["不向窗前著色新，老夫無處可安身。", "寒梢已拔千尋劍，空腹堪容數百人。", "染淚浪傳湘水恨，結根終伴杜陵貧。", "回頭萬事皆衰歇，歲晚相從爾獨親。"]'),
('ec69c568-fe36-4bf0-8705-8c78c82dce59','移竹次林英伯韻四首  其三','林季仲','宋','宋诗','song-poetry','','[]','手種琅玕照眼新，老來深寄五湖身。',64,'全唐诗/poet.song.103000.json','["手種琅玕照眼新，老來深寄五湖身。", "連宵留得枝間月，邀我同爲物外人。", "封殖不貪千戶富，依棲可慰一生貧。", "武夫稱謂殊粗俗，却恨樊川語未親。"]'),
('23cf3349-7e79-44f0-85a9-d1cafae9775c','移竹次林英伯韻四首  其四','林季仲','宋','宋诗','song-poetry','','[]','娟娟猶带露痕新，分得江潭未化身。',64,'全唐诗/poet.song.103000.json','["娟娟猶带露痕新，分得江潭未化身。", "歲晚定知堪傲雪，生來不肯强隨人。", "心如龐老空諸有，節比原思不恨貧。", "月淡風清卧寒谷，倡予和女復誰親。"]'),
('80fdbdc7-a661-41a3-b38b-474976f7646f','婁夫人挽詞','林季仲','宋','宋诗','song-poetry','','[]','曾將句讀授兒童，記得何侯待我隆。',64,'全唐诗/poet.song.103000.json','["曾將句讀授兒童，記得何侯待我隆。", "肯闢高堂舍孫寶，定知賢室贊張忠。", "蘭陔未遂三山養，霜樹俄驚一夜風。", "湯沐追封他日事，哀榮應在淚痕中。"]'),
('6dfdb1c3-7cf7-4134-a5ec-4fb7c5a7aea9','高太傅挽詞','林季仲','宋','宋诗','song-poetry','','[]','聲利場中意獨消，端如處士翳蓬蒿。',64,'全唐诗/poet.song.103000.json','["聲利場中意獨消，端如處士翳蓬蒿。", "渡江一馬神先助，夾日五龍功更高。", "不願本朝私戚里，長稱文母訓兒曹。", "十年共說無生話，却對東風淚滿袍。"]'),
('ee3aed2e-ad2f-4e36-a67d-4a986387143f','贈劉舍人次德裕弟韻','林季仲','宋','宋诗','song-poetry','','[]','雁塔聯名記昔年，天涯一見破衰顔。',64,'全唐诗/poet.song.103000.json','["雁塔聯名記昔年，天涯一見破衰顔。", "人言巧宦何曾巧，我欲閒居未得閒。", "弱植自憐葭倚樹，雄文纔許管窺斑。", "明公舊有經綸手，今日寧當縮袖間。"]'),
('deecb5a1-fa99-4a06-8f03-8de7ab2efad3','次韻林楙南秋興見寄','林季仲','宋','宋诗','song-poetry','','[]','秋陽晃朗秋江前，秋山崷崒飛鳥邊。',64,'全唐诗/poet.song.103000.json','["秋陽晃朗秋江前，秋山崷崒飛鳥邊。", "待扶仙人九節杖，去采玉井千葉蓮。", "一丘一壑不在我，或用或舍其如天。", "故人謫官卧空谷，誰與晤語情凄然。"]'),
('c4703a83-c0f5-4b3c-a865-0bc8bb63d41a','陪郡守趙介然泛舟','林季仲','宋','宋诗','song-poetry','','[]','邦人夾岸覷龔黄，畫鷁夷猶轉曲塘。',64,'全唐诗/poet.song.103000.json','["邦人夾岸覷龔黄，畫鷁夷猶轉曲塘。", "風定波平溪練凈，沙寒石出木奴香。", "冥搜萬象詩肩聳，流盼千山醉眼長。", "此興在公真不淺，更乘霜月倚胡床。"]'),
('037a3d82-5e3e-40a3-a8e6-9413c0ad6709','趙守泛舟康侍郎有詩次韻','林季仲','宋','宋诗','song-poetry','','[]','彈壓湖山有主人，我如鴻雁亦來賓。',64,'全唐诗/poet.song.103000.json','["彈壓湖山有主人，我如鴻雁亦來賓。", "連雲島嶼參差見，過雨林塘取次新。", "霜橘似誇千戶富，雪梅欲放一枝春。", "酒醒月落愁無那，聽徹殘更斷曉闉。"]'),
('161ee589-5466-4299-99d7-27e97ed016ee','周希父賦梅次韻三首  其一','林季仲','宋','宋诗','song-poetry','','[]','村舍江南雪意遲，月邊初破兩三枝。',64,'全唐诗/poet.song.103000.json','["村舍江南雪意遲，月邊初破兩三枝。", "輸他一點先傳得，回首千花總後期。", "春事循環寧有盡，歲華晼晚漫多悲。", "君詩到眼如圖畫，寫出行人立馬時。"]'),
('56ce2440-cfc6-4194-a7be-7db41b177e94','周希父賦梅次韻三首  其二','林季仲','宋','宋诗','song-poetry','','[]','歲華物意兩俱遲，開到前村第幾枝。',64,'全唐诗/poet.song.103000.json','["歲華物意兩俱遲，開到前村第幾枝。", "抱影自憐春有信，衝寒長指雪爲期。", "音傳隴首人相憶，恨入樓頭角正悲。", "最是一年難忘處，小橋流水夕陽時。"]'),
('818bbfed-cf86-4109-9eeb-274df856c360','周希父賦梅次韻三首  其三','林季仲','宋','宋诗','song-poetry','','[]','歲寒誰復慰棲遲，籬落初橫一二枝。',64,'全唐诗/poet.song.103000.json','["歲寒誰復慰棲遲，籬落初橫一二枝。", "試問春從何處去，又憑梅報有來期。", "巡檐索笑如相識，倚竹懷新却自悲。", "花瘦惱教人共瘦，月明風定酒醒時。"]'),
('24e9aa77-db38-4341-8195-17eb014f6349','次韻康侍郎詠雪','林季仲','宋','宋诗','song-poetry','','[]','天公昨夜醉如泥，擘碎浮雲散漫飛。',64,'全唐诗/poet.song.103000.json','["天公昨夜醉如泥，擘碎浮雲散漫飛。", "謝女饒他歌柳絮，曹人堪笑比麻衣。", "平鋪寶貝知何限，豫表豐祥不待祈。", "最是松林難畫處，晚晴猶吐玉霏霏。"]'),
('7c1178fa-3717-4df9-8591-280f1de6a0ec','次韻劉敷言詠梅四首  其一','林季仲','宋','宋诗','song-poetry','','[]','梅花笑我無佳句，慚愧詩翁亦姓林。',64,'全唐诗/poet.song.103000.json','["梅花笑我無佳句，慚愧詩翁亦姓林。", "細看窗前隕秋葉，誰知雪底得春心。", "斷橋斜徑光將夕，淡月疏雲趣更深。", "何處清香惱行客，江頭跋馬試教尋。"]'),
('ac377fd1-821d-4034-8f64-6a4e331764c9','次韻劉敷言詠梅四首  其二','林季仲','宋','宋诗','song-poetry','','[]','江空木落出遥岑，何處佳人獨倚林。',64,'全唐诗/poet.song.103000.json','["江空木落出遥岑，何處佳人獨倚林。", "不負雪期如有信，偶先花事本無心。", "日低修渚雲容薄，路轉寒塘暝色深。", "莫怪山翁數回首，暗香十里更相尋。"]'),
('2f6e146a-a256-4437-8612-d51a8b6171bb','次韻劉敷言詠梅四首  其三','林季仲','宋','宋诗','song-poetry','','[]','粉痕欲破雪相禁，如妒孤英點暮林。',64,'全唐诗/poet.song.103000.json','["粉痕欲破雪相禁，如妒孤英點暮林。", "九陌未傳花底信，一枝先寄隴頭心。", "月橫瘦影池塘淺，風度微香院落深。", "插向鬢邊猶得在，未須笑我老浸尋。"]'),
('f965c12b-81fa-4371-a47e-fdaeaa14a3e8','次韻劉敷言詠梅四首  其四','林季仲','宋','宋诗','song-poetry','','[]','霜清木脫峭寒侵，驚見佳花吐遠林。',64,'全唐诗/poet.song.103000.json','["霜清木脫峭寒侵，驚見佳花吐遠林。", "冷落自憐池上影，孤高誰賞月邊心。", "簡文剪綵談何易，杜老巡檐意最深。", "寂寂溪橋斷行跡，吹香獨與我追尋。"]'),
('32ca56c1-b487-4837-aa18-a97482d24607','春日感懷','林季仲','宋','宋诗','song-poetry','','[]','憶昔青春去不來，深憑百舌喚將回。',64,'全唐诗/poet.song.103000.json','["憶昔青春去不來，深憑百舌喚將回。", "尊前便覺和風轉，鏡裏生憎白髮催。", "青破輕寒歸驛柳，香和宿雨落江梅。", "人生七十從來少，待挽長河作壽杯。"]'),
('db96a9d7-7337-4d99-89a9-c161d9f8d0eb','挽程夫人詞','林季仲','宋','宋诗','song-poetry','','[]','金章朱轂爛盈門，春入仙翁笑頰溫。',64,'全唐诗/poet.song.103000.json','["金章朱轂爛盈門，春入仙翁笑頰溫。", "曳杖時時過他客，含飴日日弄諸孫。", "風高浙水驚霜葉，月落黟山泣曉猿。", "丹旐悠揚轉寒日，尚疑簾下綵衣翻。"]'),
('f9f5db34-501e-435f-9674-ece6e3077193','贈李端明','林季仲','宋','宋诗','song-poetry','','[]','洗盡烟嵐見海山，池塘春草亦怡顔。',64,'全唐诗/poet.song.103000.json','["洗盡烟嵐見海山，池塘春草亦怡顔。", "野沈犬警清宵迥，檐轉堂陰白晝閑。", "移鎮又傳三疊鼓，告庭行促百官班。", "攀轅父老休相憶，總在爐錘橐籥間。"]'),
('70d19da6-a290-4c53-aa63-f269695e974a','三椽休斧陳開祖有詩次韻','林季仲','宋','宋诗','song-poetry','','[]','經營草舍得能難，甫及斜川八九間。',64,'全唐诗/poet.song.103000.json','["經營草舍得能難，甫及斜川八九間。", "傍砌更移牆後竹，鈎簾獨盼雨餘山。", "月投窗隙如相覓，雲過檐端却復還。", "長憶少陵規畫遠，要令寒士總歡顔。"]'),
('0f313b1e-e634-44c6-8460-bdb33a58f8ec','次韻酬劉延仲','林季仲','宋','宋诗','song-poetry','','[]','門翳蒿萊誰往還，憶君更覺鬢毛斑。',64,'全唐诗/poet.song.103000.json','["門翳蒿萊誰往還，憶君更覺鬢毛斑。", "何時共對吟邊月，相別猶憐雪後山。", "清夜忍聞庭鶴怨，餘年應伴海鷗閒。", "有人問我今何似，兀兀長如醉夢間。"]'),
('f5664ba4-6c81-477c-86f8-046432a1bb7d','次韻酬趙寶學','林季仲','宋','宋诗','song-poetry','','[]','高軒曾過我柴關，笑看莓苔滿地斑。',64,'全唐诗/poet.song.103000.json','["高軒曾過我柴關，笑看莓苔滿地斑。", "隱約誰憐許居士，風流得倚謝東山。", "詩鏘金石音尤古，筆走龍蛇意自閒。", "後日陪公那可得，飄然身在五雲間。"]'),
('07eeb102-c384-4b4b-a4d1-f4c45f51c17e','再次前韻酬趙寶學','林季仲','宋','宋诗','song-poetry','','[]','佳章一見一開顔，讀向寒窗到日斑。',64,'全唐诗/poet.song.103000.json','["佳章一見一開顔，讀向寒窗到日斑。", "筆陣知公來似雨，詩肩笑我聳如山。", "皂鵰氣欲凌千里，老驥身猶絆六閑。", "聞說漢庭思祭酒，詔書相繼促河間。"]'),
('46a00547-d9d6-4a18-8f10-c76de2abe4fc','用前韻酬高仲貽見贈','林季仲','宋','宋诗','song-poetry','','[]','杖藜谷口佇歸雲，生理蕭條一葛巾。',64,'全唐诗/poet.song.103000.json','["杖藜谷口佇歸雲，生理蕭條一葛巾。", "未敢軒眉焚芰製，更期晚節伴霜筠。", "江山約我盟猶在，風月於人意自新。", "木落寒林水清淺，小橋共看雪梅春。"]'),
('b4da58ef-8d92-46ee-b796-d1cbb19d8810','再次前韻','林季仲','宋','宋诗','song-poetry','','[]','野性由來愛水雲，强將麋鹿著冠巾。',64,'全唐诗/poet.song.103000.json','["野性由來愛水雲，强將麋鹿著冠巾。", "救時或用魯連子，談古空如司馬筠。", "胡雁驚心雙淚落，吳霜點鬢二毛新。", "腐儒無用終羞死，只合歸耕壟上春。"]'),
('3d53a80e-34f9-4a16-91e7-491a9e8c4834','樂壽閣','林季仲','宋','宋诗','song-poetry','','[]','看山玩水適吾情，此語從來誤後生。',64,'全唐诗/poet.song.103000.json','["看山玩水適吾情，此語從來誤後生。", "喚起萬端因好樂，靜觀一理本圓成。", "與人不競春長在，對物無心境自清。", "更就阿誰求樂壽，當時分付最分明。"]'),
('eff614c1-8fc2-4787-8ca1-dacc6a004349','贈虞教授別','林季仲','宋','宋诗','song-poetry','','[]','儒生底用苦知書，學到根源物物無。',64,'全唐诗/poet.song.103000.json','["儒生底用苦知書，學到根源物物無。", "曾子當年多一唯，顔淵終日只如愚。", "水流萬折心無競，月落千家境自孤。", "把手沙頭莫言別，與君元不隔江湖。"]'),
('be8215b6-493e-4c78-b83a-822b5cc3bc4e','次韻追和錢穆父內翰勰趙伯堅大卿令鑠遊潁湖呈正字寶學即伯堅子也','林季仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','潁水如聞得月多，黄金萬頃漾微波。',64,'全唐诗/poet.song.103000.json','["潁水如聞得月多，黄金萬頃漾微波。", "登臨未送平生目，賡唱空傳故老歌。", "宦意請看頭上雪，杯行且覆掌中荷。", "吾鄉亦有西湖好，舴艋相從意若何。"]'),
('4d17e1ec-9e22-42d5-9946-b0e0fe0c769d','次韻吳清叟書懷','林季仲','宋','宋诗','song-poetry','','[]','誤落樊籠二十年，蒼顔白髮意頹然。',64,'全唐诗/poet.song.103000.json','["誤落樊籠二十年，蒼顔白髮意頹然。", "解紛無用空彈鋏，揣分唯堪備執鞭。", "乘雁去來何足數，涸魚濡沫自相憐。", "扁舟東下雖云晚，及見梅花破臘前。"]'),
('93422ba7-f3da-4fff-8af2-2c1417695e78','次韻宋待制晚春書懷','林季仲','宋','宋诗','song-poetry','','[]','春事何曾解有窮，枝頭尋覓漫匆匆。',64,'全唐诗/poet.song.103000.json','["春事何曾解有窮，枝頭尋覓漫匆匆。", "去來燕認誰家戶，開落花因一夜風。", "萬古英雄殘照裏，半生勳業醉魂中。", "騷人往往多詩瘦，却怪老夫顔色紅。"]'),
('7d3f8734-c053-4d34-8768-525c2963c866','次韻沈叔權書懷','林季仲','宋','宋诗','song-poetry','','[]','忽思身世愴然驚，漫學雕龍藝未成。',64,'全唐诗/poet.song.103000.json','["忽思身世愴然驚，漫學雕龍藝未成。", "尸素空糜太倉粟，辛勤有愧老農耕。", "只須鬢上看勳業，休向人前道姓名。", "歲晚相從白岩下，一樽芳酒話深情。"]'),
('859288ab-7ad1-4d0e-a4ac-ea4bba7fa301','再次前韻書懷','林季仲','宋','宋诗','song-poetry','','[]','兩眼昏花近十年，簡編惟見字斑斑。',64,'全唐诗/poet.song.103000.json','["兩眼昏花近十年，簡編惟見字斑斑。", "養生正合師黄石，招隱寧須待小山。", "薄宦本無朱組願，高眠得伴白雲閒。", "清風却似憐孤寂，時送禽聲到枕間。"]'),
('f9ca3efd-cef7-4eca-b381-86d92e6a3a6e','魏府君挽詞','林季仲','宋','宋诗','song-poetry','','[]','霜露長悲陟岵人，見翁强健却酸辛。',64,'全唐诗/poet.song.103000.json','["霜露長悲陟岵人，見翁强健却酸辛。", "家徒四壁知無恨，掌有雙珠未是貧。", "老去米鹽渾不問，病來藥石强相親。", "歸從先壟平生志，松下應逢月色新。"]'),
('4a0e54d4-c4a1-44c6-b44c-130dc37b0da2','次韻和康丈真率之集','林季仲','宋','宋诗','song-poetry','','[]','行步敧危老病身，勝遊那敢厠荀陳。',64,'全唐诗/poet.song.103000.json','["行步敧危老病身，勝遊那敢厠荀陳。", "試思珠履三千客，何似風雩六七人。", "雪意遲疑終未决，詩筒來往莫辭頻。", "曉窗新得東君訊，已放梅梢一點春。"]'),
('561de1ab-3467-427e-b5b3-f78b5227ff0a','次韻和康侍郎遊仙巖','林季仲','宋','宋诗','song-poetry','','[]','林巒爭入馬蹄來，宿霧殘雲撥不開。',64,'全唐诗/poet.song.103000.json','["林巒爭入馬蹄來，宿霧殘雲撥不開。", "石卧松根橫碧玉，瀑懸天外轉晴雷。", "仙家長鎖青春好，老子猶堪竟日陪。", "收拾此身知有所，一間茅屋傍山隈。"]'),
('24ff5edb-3380-4e97-9a05-b8fb80acf2d3','送梁尚書移守宛陵','林季仲','宋','宋诗','song-poetry','','[]','堂堂體貌照簪纓，天與君王佐太平。',64,'全唐诗/poet.song.103000.json','["堂堂體貌照簪纓，天與君王佐太平。", "拭眼待看蕭相國，舉杯且屬謝宣城。", "花間未聽歌聲徹，笛裏先催別恨生。", "說與邦人休卧轍，過家聞欲趁清明。"]'),
('f3df7280-2833-4b21-9e9c-c5698e47e1d2','蕭朝宗旅寓有途窮之歎次韻以廣其意','林季仲','宋','宋诗','song-poetry','','[]','路入長安處處同，斷橋絕港自相通。',64,'全唐诗/poet.song.103000.json','["路入長安處處同，斷橋絕港自相通。", "地高何羨三公貴，境樂那知四壁空。", "萬象森羅皆拱北，百川曲折定趨東。", "懶從宦達如曾閔，也有芳猷到不窮。"]'),
('05348aa9-1a73-4bbc-9592-13a2af711e83','表之索詩爲別','林季仲','宋','宋诗','song-poetry','','[]','踏著禪門步步新，布衣蔬食欲終身。',64,'全唐诗/poet.song.103000.json','["踏著禪門步步新，布衣蔬食欲終身。", "解顔一笑如深契，拭眼相看尚未真。", "世事盡歸簪上雪，我生聊寄甕頭春。", "夜深坐對柯山月，應念滄江獨釣人。"]'),
('f59b94f3-4f45-4003-8587-884d33d2763c','次高承宣韻題劉知言郊居','林季仲','宋','宋诗','song-poetry','','[]','荷鋤歸伴隴頭雲，懶傍侯門更整巾。',64,'全唐诗/poet.song.103000.json','["荷鋤歸伴隴頭雲，懶傍侯門更整巾。", "卜築君能如沈約，題詩吾亦效王筠。", "湖光皛皛千山合，竹色娟娟一徑新。", "酒後笑歌應耳熱，西園驚破海棠春。"]'),
('b5b537f3-81c4-404c-9207-7a275adf19ac','陳升仲挽詞','林季仲','宋','宋诗','song-poetry','','[]','莫歎交情大署門，交情如子復何云。',64,'全唐诗/poet.song.103000.json','["莫歎交情大署門，交情如子復何云。", "友恭便是能爲學，樸訥由來自少文。", "曾解綈袍憐范叔，當留寶劍報徐君。", "雪梅時節尤相憶，長話平生到夜分。"]'),
('c43570a7-adc0-4c06-81fe-720531e8ca4f','迎華觀落成蘇侍郎賦詩次韻','林季仲','宋','宋诗','song-poetry','','[]','亂山爭挾我先登，拭眼還驚見未曾。',64,'全唐诗/poet.song.103000.json','["亂山爭挾我先登，拭眼還驚見未曾。", "不爲遊觀事斤築，可憐撐拄費薪蒸。", "竹依窗牖秋鳴玉，月墮樽罍夜飲冰。", "說與溪船莫吹笛，斷腸人在最高層。"]'),
('3696fb22-49b0-4dea-a508-b9d9a95a625f','早春有懷','林季仲','宋','宋诗','song-poetry','','[]','青春無語到天涯，百舌枝頭漫自誇。',64,'全唐诗/poet.song.103000.json','["青春無語到天涯，百舌枝頭漫自誇。", "紅破輕寒入桃萼，香和宿雨落梅花。", "風吹杖屨千山晚，水照林塘兩鬢華。", "萬事蕭條兵革裏，北飛愁見雁行斜。"]'),
('c4c85b42-3492-4234-bb70-20df3cd92a42','寄婺州周知錄','林季仲','宋','宋诗','song-poetry','','[]','不到東陽六七年，干戈身世兩依然。',64,'全唐诗/poet.song.103000.json','["不到東陽六七年，干戈身世兩依然。", "每思三慮堂中退，徑向雙溪樓上眠。", "空翠霏微浮酒斝，林烟杳靄沒漁船。", "有人問我今何似，頭禿昏昏瘴海邊。"]'),
('e5b08f5d-c22c-4203-b528-a29e36673c2d','寄劉知言','林季仲','宋','宋诗','song-poetry','','[]','年來何止二宜休，合把身名付釣舟。',64,'全唐诗/poet.song.103000.json','["年來何止二宜休，合把身名付釣舟。", "寒食又衝花下雨，晚塘漸狎棹前鷗。", "推居誰復如公瑾，種竹猶憐似子猷。", "來坐梅陰引春酒，微酸點點著枝頭。"]'),
('7d9246f1-2d3b-4250-aa8a-c276c0c220fd','次曾谹甫韻寄賀子忱','林季仲','宋','宋诗','song-poetry','','[]','狂客當年隱四明，至今孫子愛林坰。',64,'全唐诗/poet.song.103000.json','["狂客當年隱四明，至今孫子愛林坰。", "挂冠無慍亦無喜，抱膝自歌還自聽。", "時弄清琴懷賀若，何妨後乘載樵青。", "結鄰能踐前言否，春色方深絕境亭。"]'),
('885dcf08-f7db-4f43-8468-c1c40b794e06','州將設宴諸薦士','林季仲','宋','宋诗','song-poetry','','[]','化蜀文翁竟好文，坐令風物一番新。',64,'全唐诗/poet.song.103000.json','["化蜀文翁竟好文，坐令風物一番新。", "爭飛方朔三千牘，何止平原十九人。", "棫樸佇觀周室富，茅芹先傍魯宮春。", "使君勸駕無多語，莫學公孫只爲身。"]'),
('d2cd067e-023a-44a2-966e-4765b3478c00','盧守携酒過薛直老草堂次韻','林季仲','宋','宋诗','song-poetry','','[]','畫戟森森轉水湄，草堂顔色带恩私。',64,'全唐诗/poet.song.103000.json','["畫戟森森轉水湄，草堂顔色带恩私。", "亂離海上多簪紱，槃礴風前卸馬羈。", "醉帽半敧花近眼，賡歌間發墨翻池。", "諸公明日朝天去，且爲南陽借杜詩。"]'),
('3098711b-f7d8-4b52-8cc1-bc1c56ca51f1','寄題蔣封州三徑堂堂本在丹陽後避地四明再創','林季仲','宋','宋诗','song-poetry','','[]','三徑開從蔣兖州，至今孫子亦風流。',64,'全唐诗/poet.song.103000.json','["三徑開從蔣兖州，至今孫子亦風流。", "鈎簾雖對鄮山月，聞笛應悲京口秋。", "往事漫勞書咄咄，餘生只合賦休休。", "問君辦得蓑衣否，便好相隨上釣舟。"]'),
('0d050cc9-16bc-438f-88e9-b1bdd7ca880f','春日郊行','林季仲','宋','宋诗','song-poetry','','[]','困倚春風半醉醒，小橋流水欲相平。',64,'全唐诗/poet.song.103000.json','["困倚春風半醉醒，小橋流水欲相平。", "晚蹊窈窕行桃李，野老逢迎略姓名。", "浦溆遠兼江色暝，鳧鷗迥立夕陽明。", "田家作苦吾何恨，無補公家合退耕。"]'),
('95f0de59-a1aa-4b01-83d0-b8829643951a','次韻趙表之郊行','林季仲','宋','宋诗','song-poetry','','[]','看取吳霜點鬢新，利名場裏合抽身。',64,'全唐诗/poet.song.103000.json','["看取吳霜點鬢新，利名場裏合抽身。", "去從宦路謀多拙，歸伴田夫味最真。", "落木正饒窗外月，小梅猶靳臘前春。", "他時更有郊行句，遠寄臞溪獨卧人。"]'),
('ff1b1785-a90f-4762-a28c-6987d1a751fa','次韻梁守登富覽亭  其一','林季仲','宋','宋诗','song-poetry','','[]','朝來爽氣自橫空，躡屐寧須學謝公。',64,'全唐诗/poet.song.103000.json','["朝來爽氣自橫空，躡屐寧須學謝公。", "似此江山何處有，合分風月與人同。", "消磨萬古潮聲裏，摇兀千林酒浪中。", "欲和陽春無好語，尊前莫笑囁嚅翁。"]'),
('5f7806b2-874e-4910-9dc6-bf1a4ec23e1f','次韻梁守登富覽亭  其二','林季仲','宋','宋诗','song-poetry','','[]','絳人老矣休問年，萬事灰心寧復然。',64,'全唐诗/poet.song.103000.json','["絳人老矣休問年，萬事灰心寧復然。", "有客雅知林下趣，憐渠獨得酒中天。", "摩空雁影沈波底，照眼梅花破臘前。", "雪意方濃君且住，行歌同挂杖頭錢。"]'),
('b10e7de9-571c-4133-b56e-fbc3577b3c6c','又用前韻二首  其一','林季仲','宋','宋诗','song-poetry','','[]','雕甍華棟照晴空，更憶檐前十八公。',64,'全唐诗/poet.song.103000.json','["雕甍華棟照晴空，更憶檐前十八公。", "四望川流何富有，一時歌詠許誰同。", "海吞萬壑蒼烟外，地湧雙峯白浪中。", "洞接仙都春色早，桃花認得鶴溪翁。"]'),
('80facb57-8393-4be2-b851-e224d737616c','又用前韻二首  其二','林季仲','宋','宋诗','song-poetry','','[]','遺迹榛蕪四十年，使君跋馬獨依然。',64,'全唐诗/poet.song.103000.json','["遺迹榛蕪四十年，使君跋馬獨依然。", "要將舊觀還騷客，幻出新亭倚半天。", "井邑參差圖障裏，烟霞明滅酒尊前。", "我今不是貧居士，買斷江山莫計錢。"]'),
('a9b78227-67ce-448f-90e7-a3e0c5417e07','寄題趙丞相獨往亭詩','林季仲','宋','宋诗','song-poetry','','[]','海內英豪還有誰，寧容丘壑著皋夔。',64,'全唐诗/poet.song.103000.json','["海內英豪還有誰，寧容丘壑著皋夔。", "欲知今日中興業，已定黄岡獨往時。", "謝傅本無朱組願，留侯應念赤松期。", "更須整頓乾坤了，我亦芒鞋隨所之。"]'),
('3a08975b-ede6-4623-a3c4-1ebcd84d096d','趙彥挽詞','林季仲','宋','宋诗','song-poetry','','[]','鐵面聲名滿九州，爾來孫子亦風流。',64,'全唐诗/poet.song.103000.json','["鐵面聲名滿九州，爾來孫子亦風流。", "怡雲自比陶弘景，下澤誰如馬少游。", "醉袖舞低千嶂月，鈎綸翻動五湖秋。", "可憐舊日飛觴處，波影空摇百尺樓。"]'),
('45ce9597-e9ea-47b8-9ebd-fa19a686071d','侯公謹挽詞','林季仲','宋','宋诗','song-poetry','','[]','富貴功名等弁髦，何如聲迹翳蓬蒿。',64,'全唐诗/poet.song.103000.json','["富貴功名等弁髦，何如聲迹翳蓬蒿。", "倦遊正被微官縛，辭祿方知處士高。", "華萼向來榮父行，芝蘭重見秀兒曹。", "寄言護國山頭月，莫照山猿夜夜號。"]'),
('75a1486c-6608-48fe-bd20-1ef54c23bfb2','林楙南挽詞','林季仲','宋','宋诗','song-poetry','','[]','新詩寄我五年前，讀向寒窗倍黯然。',64,'全唐诗/poet.song.103000.json','["新詩寄我五年前，讀向寒窗倍黯然。", "自古伊優多得志，如君疏直竟誰憐。", "去凶何愧如行父，深詆那知中咸宣。", "遊世若爲能遠過，試收清淚問蒼天。"]'),
('2b16e280-b3d9-4254-831d-af0ab34f19ce','薛康朝挽詞','林季仲','宋','宋诗','song-poetry','','[]','意氣平生百不伸，一麾晚出守宜春。',64,'全唐诗/poet.song.103000.json','["意氣平生百不伸，一麾晚出守宜春。", "功名到此當言命，才術如公豈後人。", "庭集鵷雛知有種，盤堆苜蓿未全貧。", "江寒木落悲無那，詩寄蓬窗墨尚新。"]'),
('84d43fc9-15ef-4b71-ac38-bcd3b4c1cb9b','九日諸人集於資福閣次高季應韻三首  其一','林季仲','宋','宋诗','song-poetry','','[]','秋入江山晚更妍，登高臨遠意凄然。',64,'全唐诗/poet.song.103000.json','["秋入江山晚更妍，登高臨遠意凄然。", "且浮綠蟻眼前樂，底用虛名身後傳。", "舊隱未教幽鶴怨，清溪終伴白鷗眠。", "老來舉措多羞澁，强插黄花趁少年。"]'),
('d678986a-4386-4c5e-8b96-e68a37cb3247','九日諸人集於資福閣次高季應韻三首  其二','林季仲','宋','宋诗','song-poetry','','[]','隔竹通暉月自妍，樽前寶炬不須然。',64,'全唐诗/poet.song.103000.json','["隔竹通暉月自妍，樽前寶炬不須然。", "毫飛閣上千林溼，句落雲間萬井傳。", "佳節敢辭通夕醉，宿酲還傍小窗眠。", "鬢邊黄菊應相笑，白髮較多似去年。"]'),
('7fbf3be2-e40b-4466-b3d0-020871bbafdc','九日諸人集於資福閣次高季應韻三首  其三','林季仲','宋','宋诗','song-poetry','','[]','戲馬臺前草自妍，英雄何在竟茫然。',64,'全唐诗/poet.song.103000.json','["戲馬臺前草自妍，英雄何在竟茫然。", "江河猶带重陽恨，父老空將舊事傳。", "去雁來鴻波浩蕩，夕陽流水樹芊眠。", "休休世味從來惡，細嚼霜英慰暮年。"]'),
('b586b0d9-1627-48d4-9593-6f341216d8a0','和高少保九日','林季仲','宋','宋诗','song-poetry','','[]','誰將淡墨掃秋山，乞與衰翁獨倚欄。',64,'全唐诗/poet.song.103000.json','["誰將淡墨掃秋山，乞與衰翁獨倚欄。", "白髮試思何處去，黄花今有幾人觀。", "老來自覺情懷惡，客裏長嗟會面難。", "卷盡浮雲放明月，與公同倒百杯盤。"]'),
('2309748b-6404-4555-a6e7-1c6468f23723','次韻張子猷賦凱旋之什','林季仲','宋','宋诗','song-poetry','','[]','十萬貔貅擁鼓鞞，雲間聽得一聲齊。',64,'全唐诗/poet.song.103000.json','["十萬貔貅擁鼓鞞，雲間聽得一聲齊。", "祥開虎帳妖氛落，威疊鯨江怒浪低。", "曉日彩旌沙外轉，春風歸馬柳邊嘶。", "幕中自有燕公筆，合把奇功勒建溪。"]'),
('34dc2d21-3225-43bc-a706-8d1c17e2a1e4','題薛獻可新居次高仲貽韻','林季仲','宋','宋诗','song-poetry','','[]','高居占得野塘橫，竹逕桃蹊取次成。',64,'全唐诗/poet.song.103000.json','["高居占得野塘橫，竹逕桃蹊取次成。", "宿靄半兼朱戶溼，好山長傍晚窗明。", "風吹酒面春情渺，月落詩腸夜味清。", "今日主人歸定否，試聽枝上子規聲。"]'),
('dd4f3801-e769-4b70-8e00-cb7463cde601','送思深赴泉州錄參','林季仲','宋','宋诗','song-poetry','','[]','南郭先生卧病餘，瘦如騏驥服鹽車。',64,'全唐诗/poet.song.103000.json','["南郭先生卧病餘，瘦如騏驥服鹽車。", "厭嘗漆葉青黏散，旋理司空城旦書。", "長陌欲登秋色薄，一樽相對鬢毛疏。", "晉江波與溫江接，消息頻傳雙鯉魚。"]'),
('7a9095e9-d830-42f8-a9ed-b13ac5cd3d94','和梁守餞諸貢士','林季仲','宋','宋诗','song-poetry','','[]','右文逢聖代，首善自神京。',96,'全唐诗/poet.song.103000.json','["右文逢聖代，首善自神京。", "延及吳中士，咸稱洛下英。", "我邦雖僻陋，此學號專精。", "耆舊風流在，山川氣象新。", "元侯來作牧，後進頼提衡。", "有美僖公頌，誰高蜀守名。", "能書偕計吏，燕豆列賓榮。", "萬里雲霄路，摶風看去程。"]'),
('b4120239-2c9b-4e4b-bbf0-9321a87e00c2','張叔靖詠螢次韻','林季仲','宋','宋诗','song-poetry','','[]','榛莽荒秋雨，郊坰接暮陰。',120,'全唐诗/poet.song.103000.json','["榛莽荒秋雨，郊坰接暮陰。", "挾明如自喜，穿隙互相尋。", "晝伏終羞日，宵征欲亂參。", "林驚光不定，葉脫勢俱沈。", "代燭時臨卷，隨風屢拂琴。", "青熒行爝火，的皪漾沙金。", "巧自緣簾幙，翻令念藁砧。", "徘徊憐扇影，婉孌傍衣衿。", "窗曙星河落，江寒霜露深。", "危蹝悵何往，腐質諒難任。"]'),
('8dcda960-8a11-4a04-a2d6-498b05981c67','不見胡仲隸題蘇溪僧壁','林季仲','宋','宋诗','song-poetry','','[]','念別三年久，相望一舍間。',24,'全唐诗/poet.song.103000.json','["念別三年久，相望一舍間。", "無人寄消息，風雨暗前山。"]'),
('791c9be2-d768-4d5c-9176-8710ffe8fb70','宿天台石橋  其一','林季仲','宋','宋诗','song-poetry','','[]','卧聽泉聲似雨聲，直愁泥滑馬難行。',32,'全唐诗/poet.song.103000.json','["卧聽泉聲似雨聲，直愁泥滑馬難行。", "世間疑事多如許，千百年來誰與明。"]'),
('aa15bc93-a03e-4f33-bf21-6659080a6b7f','宿天台石橋  其二','林季仲','宋','宋诗','song-poetry','','[]','今人議論只從多，簣土那能障大河。',32,'全唐诗/poet.song.103000.json','["今人議論只從多，簣土那能障大河。", "我有室廬亦方廣，歸途不向石橋過。"]'),
('5aed638a-dbf8-49d9-abe6-94dcb31ecac8','釣臺','林季仲','宋','宋诗','song-poetry','','[]','脫身歸去亦何求，剛被聲名落釣鈎。',32,'全唐诗/poet.song.103000.json','["脫身歸去亦何求，剛被聲名落釣鈎。", "買得扁舟在祠下，從公覓取舊羊裘。"]'),
('08865ce1-7df1-44c7-98f5-79bddb046175','宿雁蕩能仁寺','林季仲','宋','宋诗','song-poetry','','[]','萬壑千岩簇馬蹄，羞將塵鬢照清溪。',32,'全唐诗/poet.song.103000.json','["萬壑千岩簇馬蹄，羞將塵鬢照清溪。", "晚雲带雨東風急，無數飛花過竹西。"]'),
('cc4f7f1d-c682-4dc1-aa49-48c046222acc','墨梅','林季仲','宋','宋诗','song-poetry','','[]','一枝炯炯照人寒，絕似溪橋立馬看。',32,'全唐诗/poet.song.103000.json','["一枝炯炯照人寒，絕似溪橋立馬看。", "祇恐春風解相怨，漏他消息入毫端。"]'),
('545508a9-79fb-467c-917a-917c6d849b7a','次韻十叔父書懷','林季仲','宋','宋诗','song-poetry','','[]','咸陽市上欲思歸，人到於今笑李斯。',32,'全唐诗/poet.song.103000.json','["咸陽市上欲思歸，人到於今笑李斯。", "老去何如我癡叔，了無一事獨支頤。"]'),
('3f4f7665-f6f7-49ee-9a3e-69a2717cfc12','郊行感懷  其一','林季仲','宋','宋诗','song-poetry','','[]','路轉溪迴草木香，有人荷笠山之陽。',32,'全唐诗/poet.song.103000.json','["路轉溪迴草木香，有人荷笠山之陽。", "定知我是金華守，笑道牧民如牧羊。"]'),
('dd098362-152d-4f57-97a2-ba855f01dd5a','郊行感懷  其二','林季仲','宋','宋诗','song-poetry','','[]','羽仗霓旌去不還，空餘菊水照人寒。',32,'全唐诗/poet.song.103000.json','["羽仗霓旌去不還，空餘菊水照人寒。", "至今山下無枯草，便是田家九轉丹。"]'),
('6ac93024-edd3-4961-ac3a-eef13ba41b9f','郊行感懷  其三','林季仲','宋','宋诗','song-poetry','','[]','竹光野色凈祠堂，古木千章儼在傍。',32,'全唐诗/poet.song.103000.json','["竹光野色凈祠堂，古木千章儼在傍。", "矯矯先生竟何往，癡兒猶認石爲羊。"]'),
('1e51c36c-c0a0-4495-afb0-c3d21374f571','郊行感懷  其四','林季仲','宋','宋诗','song-poetry','','[]','一夫容易縛淮陰，辟穀留侯念已深。',32,'全唐诗/poet.song.103000.json','["一夫容易縛淮陰，辟穀留侯念已深。", "去伴赤松聊爾爾，後人真向海山尋。"]'),
('dcb1226e-358b-43ac-b6bb-05763621b87a','題外兄毛國器壁','林季仲','宋','宋诗','song-poetry','','[]','尊酒相逢海一涯，娟娟妙月照人衣。',32,'全唐诗/poet.song.103000.json','["尊酒相逢海一涯，娟娟妙月照人衣。", "重來時節君須記，流水桃花魚正肥。"]'),
('6afdada1-76dd-4b77-a0e1-366e820a4db4','題廣照院壁','林季仲','宋','宋诗','song-poetry','','[]','晚溪飛出小橋斜，流水縈迂带落花。',32,'全唐诗/poet.song.103000.json','["晚溪飛出小橋斜，流水縈迂带落花。", "生怕人來問時事，杖藜聊復過僧家。"]'),
('94c9ac26-31d1-48fe-8110-dc3263a2f839','罷金華留別雙青','林季仲','宋','宋诗','song-poetry','','[]','手植雙青十八年，牆頭一見一凄然。',32,'全唐诗/poet.song.103000.json','["手植雙青十八年，牆頭一見一凄然。", "飽嘗霜露休相憶，我欲歸耕瘴海邊。"]'),
('2e22426a-75ef-4afd-ac5c-b5a7cb553882','蕭德起諸人約遊西湖小疾不赴','林季仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','倚杖臞然一病夫，羨君聯騎出西湖。',32,'全唐诗/poet.song.103000.json','["倚杖臞然一病夫，羨君聯騎出西湖。", "若逢佳處能相憶，寄與新詩作畫圖。"]'),
('1206179a-dcf2-427d-b223-df5e9c3a0966','遊智者寺','林季仲','宋','宋诗','song-poetry','','[]','一逕縈迂上翠微，亂紅無數撲人衣。',32,'全唐诗/poet.song.103000.json','["一逕縈迂上翠微，亂紅無數撲人衣。", "匆匆來往成何事，不似山禽自在飛。"]'),
('65543458-1463-4aca-a0b6-364961b25c80','過荆山寺','林季仲','宋','宋诗','song-poetry','','[]','叢條曾欲截來轅，應訝行人數往還。',32,'全唐诗/poet.song.103000.json','["叢條曾欲截來轅，應訝行人數往還。", "歸老故園猶得在，滿斟杯酒謝荆山。"]'),
('3bcda552-95fb-447a-88d7-da7b9851000b','趙殿撰賞紅梅次韻','林季仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖獨未賦紅梅，留待知音細細開。',32,'全唐诗/poet.song.103000.json','["西湖獨未賦紅梅，留待知音細細開。", "好把新詩補遺逸，不才空與作雲來。"]'),
('088f7d84-96f0-400d-b60c-81dc118dbe70','秉燭照紅梅再次前韻即席','林季仲','宋','宋诗','song-poetry','','[]','玉妃初醉下瑶臺，紫霧深深撥不開。',32,'全唐诗/poet.song.103000.json','["玉妃初醉下瑶臺，紫霧深深撥不開。", "却恐錯穿桃杏徑，高燒銀燭照歸來。"]'),
('72278c19-a93c-4b04-83d5-351a06508b7c','厭於行役感梅賦詩','林季仲','宋','宋诗','song-poetry','','[]','歸袖曾攀牆外子，征鞍又拂雪中花。',32,'全唐诗/poet.song.103000.json','["歸袖曾攀牆外子，征鞍又拂雪中花。", "往來應被江梅笑，笑我經年不在家。"]'),
('86e1c923-8e3a-4d15-a305-0144ad1fd04b','次韻和康侍郎雪後小雨二首  其一','林季仲','宋','宋诗','song-poetry','','[]','殘霙初伴梅梢月，小雨仍禁柳底春。',32,'全唐诗/poet.song.103000.json','["殘霙初伴梅梢月，小雨仍禁柳底春。", "莫厭酒摇金盞浪，更聽歌繞畫梁塵。"]'),
('34d425f6-bb7e-48e9-a8e4-d44ce96347cb','次韻和康侍郎雪後小雨二首  其二','林季仲','宋','宋诗','song-poetry','','[]','白頭羞見尊前燭，頳頰深憑甕裏春。',32,'全唐诗/poet.song.103000.json','["白頭羞見尊前燭，頳頰深憑甕裏春。", "不分落梅紛似雪，更兼疏雨細如塵。"]'),
('47563929-76ae-43e6-9555-8f1e0e922156','登張知省溪樓  其一','林季仲','宋','宋诗','song-poetry','','[]','木落霜清橘柚香，榜歌迢遞起滄浪。',32,'全唐诗/poet.song.103000.json','["木落霜清橘柚香，榜歌迢遞起滄浪。", "來鴻去鶩紛無數，怕上西樓望夕陽。"]'),
('a6fff5e6-6cc9-4a6d-a204-1f5b0373fe70','登張知省溪樓  其二','林季仲','宋','宋诗','song-poetry','','[]','雁橫霜渚水痕收，檐外微雲去復留。',32,'全唐诗/poet.song.103000.json','["雁橫霜渚水痕收，檐外微雲去復留。", "多謝西風解人意，盡驅爽氣入溪樓。"]'),
('9beb934f-dd1f-49ab-8992-19dc756c31e2','登望湖樓','林季仲','宋','宋诗','song-poetry','','[]','胡塵漠漠暗中州，無力持顛漫自憂。',32,'全唐诗/poet.song.103000.json','["胡塵漠漠暗中州，無力持顛漫自憂。", "花鳥相逢非昔日，不堪重上望湖樓。"]'),
('c312b6a7-3e1f-4864-9c15-db6300c3f7da','次韻苗彥先題薛獻可新居四首  其一','林季仲','宋','宋诗','song-poetry','','[]','仙隱深深竹徑中，杖藜還許我相從。',32,'全唐诗/poet.song.103000.json','["仙隱深深竹徑中，杖藜還許我相從。", "君能惜取清陰在，斤斧須令赦籜龍。"]'),
('88eae7c4-89ec-4e5b-978e-ecd437a58b58','次韻苗彥先題薛獻可新居四首  其二','林季仲','宋','宋诗','song-poetry','','[]','方塘環植綠楊新，朱戶重重欲閉春。',32,'全唐诗/poet.song.103000.json','["方塘環植綠楊新，朱戶重重欲閉春。", "若許茅茨傍清泚，敢教鵝鴨惱比鄰。"]'),
('abef6d2a-508f-4441-9895-e9e0325dd719','次韻苗彥先題薛獻可新居四首  其三','林季仲','宋','宋诗','song-poetry','','[]','西山拏得落檐前，飛翠侵簾夕更妍。',32,'全唐诗/poet.song.103000.json','["西山拏得落檐前，飛翠侵簾夕更妍。", "心遠地偏如靖節，江湖處處是斜川。"]'),
('95e95ef9-b418-4e61-8aff-c7844b30ccd0','次韻苗彥先題薛獻可新居四首  其四','林季仲','宋','宋诗','song-poetry','','[]','軒檻青紅壓水濱，小橋斜出樹橫陳。',32,'全唐诗/poet.song.103000.json','["軒檻青紅壓水濱，小橋斜出樹橫陳。", "功名豫計殊非計，且與龜魚作主人。"]'),
('4c1b32cb-0fe6-48e5-9980-9c01d1f9abf0','袁居士來自桐廬索詩贈二絕句  其一','林季仲','宋','宋诗','song-poetry','','[]','霜髯垂臆杖過眉，得得桐廬江上來。',32,'全唐诗/poet.song.103000.json','["霜髯垂臆杖過眉，得得桐廬江上來。", "對我休談釣臺好，姓名方挂北山移。"]'),
('dec83c1b-17ce-4987-a962-4473c4f1eaf0','袁居士來自桐廬索詩贈二絕句  其二','林季仲','宋','宋诗','song-poetry','','[]','木落空山霜露寒，却驅羸馬傍長安。',32,'全唐诗/poet.song.103000.json','["木落空山霜露寒，却驅羸馬傍長安。", "君看仕路風波惡，孰與嚴陵七里灘。"]'),
('c7f19d0f-13d2-47e7-a6ac-bb233edcbbea','過東陽諸人餞別獨劉叔明不至','林季仲','宋','宋诗','song-poetry','','[]','松竹森森灝氣生，一簾疏雨故人情。',32,'全唐诗/poet.song.103000.json','["松竹森森灝氣生，一簾疏雨故人情。", "扁舟還載離愁去，不見西城劉叔明。"]'),
('89af31ff-878c-4c6a-8886-db8c7beef9a2','遊大龍湫宿壽昌竹軒','林季仲','宋','宋诗','song-poetry','','[]','晚驅羸馬下層丘，路轉寒塘憶舊遊。',32,'全唐诗/poet.song.103000.json','["晚驅羸馬下層丘，路轉寒塘憶舊遊。", "半夜雨聲碎庭竹，更疑飛沫濺龍湫。"]'),
('4dbaa397-7774-4a11-9f53-41e3dfd62169','題護國院竹光軒','林季仲','宋','宋诗','song-poetry','','[]','茶罷移床就竹眠，泠然風起和流泉。',32,'全唐诗/poet.song.103000.json','["茶罷移床就竹眠，泠然風起和流泉。", "山禽未絕東歸客，時送清音到枕邊。"]'),
('ba5f094b-4795-4638-a249-cd1338601613','罷官金華手植秋香而去通判賦詩勉强次韻','林季仲','宋','宋诗','song-poetry','','[]','孤根憶向雪中移，早被春風次第知。',32,'全唐诗/poet.song.103000.json','["孤根憶向雪中移，早被春風次第知。", "奪汝岩栖近城郭，多應相怨不相思。"]'),
('da084fac-94d3-465c-bf5a-1d8eed317717','重九前一日宿靈岩','林季仲','宋','宋诗','song-poetry','','[]','馬上衰頹只自嗟，驚心那復見黄花。',32,'全唐诗/poet.song.103000.json','["馬上衰頹只自嗟，驚心那復見黄花。", "花如相問終羞澁，底甚重陽不在家。"]'),
('b2cf2538-a19a-4862-bbd7-e73a40bf4df6','送張侍郎歸省','林季仲','宋','宋诗','song-poetry','','[]','時時去弄老萊衣，也似何蕃歲一歸。',32,'全唐诗/poet.song.103000.json','["時時去弄老萊衣，也似何蕃歲一歸。", "相送江頭無一語，寸心遥與白雲飛。"]'),
('053fd85e-e342-4a5d-95b3-c90eb87b089b','失題','林季仲','宋','宋诗','song-poetry','','[]','平生丘壑自相於，幽意悠然入畫圖。',32,'全唐诗/poet.song.103000.json','["平生丘壑自相於，幽意悠然入畫圖。", "好向溪邊石磯上，羊裘披我作狂奴。"]'),
('2ec6536d-ddf8-47a5-8f65-261c37617bf6','題康侍郎所居二首  其一','林季仲','宋','宋诗','song-poetry','','[]','閒居正怕門庭雜，學道仍嫌歧路多。',32,'全唐诗/poet.song.103000.json','["閒居正怕門庭雜，學道仍嫌歧路多。", "仲蔚當時開一逕，問渠初意果如何。"]'),
('dfb33b43-fc69-449f-b35a-284a744a1821','題康侍郎所居二首  其二','林季仲','宋','宋诗','song-poetry','','[]','莫道水清偏得月，須知水濁亦全天。',32,'全唐诗/poet.song.103000.json','["莫道水清偏得月，須知水濁亦全天。", "請看風定波平後，一顆靈珠依舊圓。"]'),
('8ce43438-5895-4c2b-adab-b2e2341087bc','富季申賦梅次韻四首  其一','林季仲','宋','宋诗','song-poetry','','[]','容易煩公問訊梅，昨宵還有幾花開。',32,'全唐诗/poet.song.103000.json','["容易煩公問訊梅，昨宵還有幾花開。", "窗寒月落知相憶，細細吹香過竹來。"]'),
('ba19db24-d91a-43b0-9fb2-a0549910f7c4','富季申賦梅次韻四首  其二','林季仲','宋','宋诗','song-poetry','','[]','雪意商量欲放梅，破寒先遣一條開。',32,'全唐诗/poet.song.103000.json','["雪意商量欲放梅，破寒先遣一條開。", "去年花下人何在，策我蹇驢歸去來。"]'),
('1a7412ae-6a27-4961-b614-b2c3bc6a4b06','富季申賦梅次韻四首  其三','林季仲','宋','宋诗','song-poetry','','[]','誰將消息報江梅，一點先從雪裏開。',32,'全唐诗/poet.song.103000.json','["誰將消息報江梅，一點先從雪裏開。", "怪見逢迎有深意，我家曾與寫真來。"]'),
('dd9ec1d5-aa0e-41b9-a28e-d7d905c68704','富季申賦梅次韻四首  其四','林季仲','宋','宋诗','song-poetry','','[]','未知何處是真梅，雪擁溪橋撥不開。',32,'全唐诗/poet.song.103000.json','["未知何處是真梅，雪擁溪橋撥不開。", "莫訝行人數回首，西風十里送香來。"]'),
('eb519774-1ddf-433e-9584-aaeba02fc835','訪梅值雪示覺慈昇老','林季仲','宋','宋诗','song-poetry','','[]','林巒出沒晚雲低，旋放寒梅照淺溪。',32,'全唐诗/poet.song.103000.json','["林巒出沒晚雲低，旋放寒梅照淺溪。", "雪意殷勤解留客，不教歸馬識東西。"]'),
('15acdafa-0039-4301-be22-e48bfd5db600','和康侍郎喜雪二首  其一','林季仲','宋','宋诗','song-poetry','','[]','六出隨軒逞厥祥，天人應感得能忙。',32,'全唐诗/poet.song.103000.json','["六出隨軒逞厥祥，天人應感得能忙。", "使君未到然香處，先有心香叩上蒼。"]'),
('6c558225-cecf-4563-8c5d-43acb9e12a0f','和康侍郎喜雪二首  其二','林季仲','宋','宋诗','song-poetry','','[]','不掃林間一逕開，夜深留伴月皚皚。',32,'全唐诗/poet.song.103000.json','["不掃林間一逕開，夜深留伴月皚皚。", "問誰踏我瓊瑶碎，新有詩筒破曉來。"]'),
('f132cd76-4105-48e8-a6dd-fdff5b815b51','宿中竺碧梧軒','林季仲','宋','宋诗','song-poetry','','[]','夢破初驚枕簟秋，懶思身世獨搔頭。',32,'全唐诗/poet.song.103000.json','["夢破初驚枕簟秋，懶思身世獨搔頭。", "山禽强欲知人事，葉底移時語未休。"]'),
('0ee6e40f-3c52-45cc-9fd0-e0e95c7caae8','宿錢塘江詩','林季仲','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','大江推月上層霄，夜色分人此最饒。',32,'全唐诗/poet.song.103000.json','["大江推月上層霄，夜色分人此最饒。", "鄉國未成千里夢，海門又捲五更潮。"]'),
('5a88597b-ba78-4fea-a211-db15238b2b14','失子','林季仲','宋','宋诗','song-poetry','','[]','檐鵲哺雛時自喜，壟牛舐犢互相噓。',32,'全唐诗/poet.song.103000.json','["檐鵲哺雛時自喜，壟牛舐犢互相噓。", "老妻覷我無他語，歡笑何年得似渠。"]'),
('be399620-d118-4493-9012-989c406f6871','句  其一','林季仲','宋','宋诗','song-poetry','','[]','北山未忍輕相別，更許行人雪後看。',16,'全唐诗/poet.song.103000.json','["北山未忍輕相別，更許行人雪後看。"]'),
('deab4cf6-7e81-4ac5-bb1f-e9625ca02530','句  其二','林季仲','宋','宋诗','song-poetry','','[]','寒聲落鴻雁，秋意著梧桐。',12,'全唐诗/poet.song.103000.json','["寒聲落鴻雁，秋意著梧桐。"]'),
('9ccceea9-3f95-4691-8735-928280ee3285','句','楊晨','宋','宋诗','song-poetry','','[]','結網㜷教女，操舟罷詬男。',12,'全唐诗/poet.song.103000.json','["結網㜷教女，操舟罷詬男。"]'),
('9458f0a0-971a-4b61-9ec5-451d541f532a','題分宜上松晚香堂','沈莊可','宋','宋诗','song-poetry','','[]','魏公判相州，始作晝錦堂。',216,'全唐诗/poet.song.103000.json','["魏公判相州，始作晝錦堂。", "老圃秋色淡，自愛晚節香。", "怡齋懷紫綬，得誥歸故鄉。", "葺圃承祖志，構堂先廬傍。", "命名仰前哲，闊步追遺芳。", "人生隨分定，鵬鷃自殊翔。", "富貴任適志，餘暇聊徜徉。", "譬彼蘭與菊，托根花卉場。", "榮枯有遲速，代謝從暄凉。", "百年倏過半，鬚髮各已蒼。", "多情感會別，聚散安可常。", "非惟隔今古，況復閱興亡。", "何以消我憂，一醉萬慮忘。", "季子久顛沛，買臣早疏狂。", "纍纍暮年印，得失寧相償。", "何如光霽時，呼客同舉觴。", "靜中猿鳥樂，閑處日月長。", "願堅歲寒操，有如傲霜黄。"]'),
('abdd8752-ba0e-4616-ad9e-9d9526351cf7','秀野園','沈莊可','宋','宋诗','song-poetry','','[]','西京五畝園，花木秀而野。',48,'全唐诗/poet.song.103000.json','["西京五畝園，花木秀而野。", "坡仙作此詩，盛事記司馬。", "深夜獨樂堂，氣象極閑雅。", "晚芳相元祐，勳名動夷夏。"]'),
('56e487c1-940c-4749-b022-d5b49ca5a997','古上方','邵彪','宋','宋诗','song-poetry','','[]','凌雲細路險可遵，稍從飛錫攀嶙峋。',64,'全唐诗/poet.song.103000.json','["凌雲細路險可遵，稍從飛錫攀嶙峋。", "烏巢崔嵬寄林莽，蟻穴細碎嚴君臣。", "震開樓閣一彈指，俯覽世界千微塵。", "人間劫火變滅盡，此地獨與湖山新。"]'),
('6c6cd61b-9771-4398-8113-8219f62e6e6b','丹陽懷古','邵彪','宋','宋诗','song-poetry','','[]','故里詩人去，湖山最寂寥。',48,'全唐诗/poet.song.103000.json','["故里詩人去，湖山最寂寥。", "草深張祜宅，花暗許渾橋。", "鳳髓何時續，蓬萍觸處飄。", "鴻冥杳難及，霜鬢兩蕭蕭。"]'),
('94ac2df7-15a5-45a7-a096-d355855826e3','賦丹陽縣治滄浪臺','邵彪','宋','宋诗','song-poetry','','[]','秦鑿斷巘崿，晉圃亡町畦。',156,'全唐诗/poet.song.103000.json','["秦鑿斷巘崿，晉圃亡町畦。", "事古迹茫昧，天高水渺瀰。", "緬懷褚季野，清坐行四時。", "倉黄擠興公，無乃醉魂迷。", "不如顔中書，藻舟賦新詩。", "蕪廢今幾年，黄鵠怨壞陂。", "令尹古循良，見利勇有爲。", "如雲擁萬鍤，矢矯出大隄。", "蛟龍鼓洪濤，鷗鷺舞寒漪。", "危臺俯回渚，長懷曠遐睎。", "乃知高世心，宜與湖山期。", "下注萬頃田，水田數斗泥。", "民樂我亦樂，舉觴淡忘歸。"]'),
('f072cb18-625d-4803-a1f6-70de1e31e06b','壓雲軒','邵彪','宋','宋诗','song-poetry','','[]','絕頂地平易，軒窗風怒號。',48,'全唐诗/poet.song.103000.json','["絕頂地平易，軒窗風怒號。", "半空垂象緯，四面湧波濤。", "洞僻封苔蘚，泉深冷骨毛。", "登臨欲忘返，城市厭煩勞。"]'),
('473b6a67-c0db-4593-b5c2-4518cdbb80f0','遊百巖','李士美','宋','宋诗','song-poetry','','[]','珍重東平入鳳城，錦箋雙羽蹙南征。',32,'全唐诗/poet.song.103000.json','["珍重東平入鳳城，錦箋雙羽蹙南征。", "馬蹄不懼攔關雪，一駕須騎萬里逞。"]'),
('fa41b13b-f31b-42af-ad91-3e7c12d97567','句','李士美','宋','宋诗','song-poetry','','[]','何須百鍊鑑，自勝五兵符。',12,'全唐诗/poet.song.103000.json','["何須百鍊鑑，自勝五兵符。"]'),
('7cad8997-8149-4ce4-9241-2b6e7775f3d4','元宵詞二首  其一','黄彥輝','宋','宋诗','song-poetry','','[]','琥珀盞中雲母鍾，琉璃光射水晶宮。',32,'全唐诗/poet.song.103000.json','["琥珀盞中雲母鍾，琉璃光射水晶宮。", "風隨蘭麝香千里，人在蓮花影萬重。"]'),
('b5c698b0-4cf9-4378-bfa1-a56bff6f690b','元宵詞二首  其二','黄彥輝','宋','宋诗','song-poetry','','[]','鰲頭移得山三島，月下傳來燈萬枝。',32,'全唐诗/poet.song.103000.json','["鰲頭移得山三島，月下傳來燈萬枝。", "香陌馬嘶紅萼錦，翠樓人倚綠楊眉。"]'),
('f12259ef-9ebf-4bb2-a6a8-151645d0596b','古寺','黄彥輝','宋','宋诗','song-poetry','','[]','古寺雲深去路賒，來分僧鉢共生涯。',64,'全唐诗/poet.song.103000.json','["古寺雲深去路賒，來分僧鉢共生涯。", "依稀池草成春夢，容易江梅老歲華。", "長鋏悲彈三尺雪，短檠寒落五更花。", "夜來風雨催歸急，爲報河陽令尹家。"]'),
('2e90cb52-6ce4-4155-96e1-9ea78d5f8aea','七星巖','葉南仲','宋','宋诗','song-poetry','','[]','斗峯遥認舊嵩臺，爲勸耕農特地來。',64,'全唐诗/poet.song.103000.json','["斗峯遥認舊嵩臺，爲勸耕農特地來。", "短李高名光翠壁，僞劉真蹟沒蒼苔。", "洞天日永風埃靜，巖竇雲收霽色開。", "好景最宜供宴賞，操觚欲賦愧非才。"]'),
('47a31d34-6a99-4a35-8ec8-cd98dcd2f4ba','山行','曹緯','宋','宋诗','song-poetry','','[]','日出過山頭，日入宿山下。',48,'全唐诗/poet.song.103000.json','["日出過山頭，日入宿山下。", "我行山亦行，隱隱似奔馬。", "朝昏山送迎，山意自傾寫。", "借問征途間，誰如此山者。"]'),
('ec5590da-2125-44bc-addd-31742b2fe795','自齊山借舟泛湖還家','曹緯','宋','宋诗','song-poetry','','[]','十里平湖漫不流，晚風吹浪打行舟。',32,'全唐诗/poet.song.103000.json','["十里平湖漫不流，晚風吹浪打行舟。", "定知歸得侵燈火，家在菰蒲最盡頭。"]'),
('72f1a761-1656-452c-af0b-a8550bf199a0','客有遺予畫梅花者淡墨暈成因命之曰梅影','曹緯','宋','宋诗','song-poetry','','[]','憶昔神遊姑射山，夢中栩栩片時還。',32,'全唐诗/poet.song.103000.json','["憶昔神遊姑射山，夢中栩栩片時還。", "冰膚不許尋常見，故隱輕雲薄霧間。"]'),
('3a9c2af1-1313-4b91-b304-089fcfb3ad01','雁','曹緯','宋','宋诗','song-poetry','','[]','雲飛水宿過炎凉，回想來時道路長。',64,'全唐诗/poet.song.103000.json','["雲飛水宿過炎凉，回想來時道路長。", "夜月照驚惟弔影，朔風吹斷不成行。", "人間無處逃矰繳，歲晚何曾飽稻粱。", "儻以能鳴免烹死，繫書猶可到衡陽。"]'),
('ead9cd29-6fdc-4c49-b57f-12e8951d50a5','清溪亭','曹緯','宋','宋诗','song-poetry','','[]','波平渺渺草萋萋，遠目非昏望欲迷。',64,'全唐诗/poet.song.103000.json','["波平渺渺草萋萋，遠目非昏望欲迷。", "敢以安閒侵白鳥，聊將衰病照清溪。", "百年無事雙蓬鬢，萬里歸心獨杖藜。", "徙倚無人見牢落，水流東去夕陽西。"]'),
('4b237186-13e4-44db-ad0e-eca7f6787df0','次韻曹好謙負春','曹緯','宋','宋诗','song-poetry','','[]','作計尋芳不屬貧，可憐風物自良辰。',64,'全唐诗/poet.song.103000.json','["作計尋芳不屬貧，可憐風物自良辰。", "飛花有意能留客，啼鳥多情解喚人。", "涉世乍驚翻手薄，論交多語白頭新。", "十年異縣傷流落，來往山州枉過春。"]'),
('26b1b9e2-c8c9-4da9-bd8c-df635ca11707','春日憶西湖簡家弟元寵','曹緯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天涯孤客意堪哀，病眼逢春只强開。',64,'全唐诗/poet.song.103000.json','["天涯孤客意堪哀，病眼逢春只强開。", "閉戶不知花老去，捲簾方覺燕歸來。", "風休潩水光如拭，雨霽箕山翠作堆。", "遥想西湖圖畫裏，幾多車馬踏青回。"]'),
('d4ea2157-e343-49a1-927c-da217c670829','句  其一','曹緯','宋','宋诗','song-poetry','','[]','水带斷槎流。',6,'全唐诗/poet.song.103000.json','["水带斷槎流。"]'),
('c445fb23-a12c-47bc-a5f6-da24553a37a2','句  其二','曹緯','宋','宋诗','song-poetry','','[]','天涯少知遇。',6,'全唐诗/poet.song.103000.json','["天涯少知遇。"]'),
('40e26133-a032-4f1e-8598-0bd2f72cc563','句  其三','曹緯','宋','宋诗','song-poetry','','[]','日依平野沒。',6,'全唐诗/poet.song.103000.json','["日依平野沒。"]'),
('7fcbdae5-6a7d-43b5-9b75-3c6dc338b442','句  其四','曹緯','宋','宋诗','song-poetry','','[]','登臨獨立時。',6,'全唐诗/poet.song.103000.json','["登臨獨立時。"]'),
('e8aa2289-7f9c-4c54-ad63-997be015bcdd','句  其五','曹緯','宋','宋诗','song-poetry','','[]','孤芳高節共亭亭。',8,'全唐诗/poet.song.103000.json','["孤芳高節共亭亭。"]'),
('ba212a95-9ab0-47c6-9e7c-8ac7af6e5225','句  其六','曹緯','宋','宋诗','song-poetry','','[]','數枝春色豈無情。',8,'全唐诗/poet.song.103000.json','["數枝春色豈無情。"]'),
('0285b533-1d71-4391-9969-f84fa25f46e4','句  其七','曹緯','宋','宋诗','song-poetry','','[]','自笑無機觸事真。',8,'全唐诗/poet.song.103000.json','["自笑無機觸事真。"]'),
('a1a3e88a-01ff-4022-9608-daa5a5a419ec','竹間見梅','曹組','宋','宋诗','song-poetry','','[]','霜雪俱憐節操奇，碧鮮紅潤兩相宜。',64,'全唐诗/poet.song.103000.json','["霜雪俱憐節操奇，碧鮮紅潤兩相宜。", "渭濱初種謾千畝，隴上寄來惟一枝。", "酸實不供饑鳳啄，暗香翻許此君知。", "佳人零落空山久，況是天寒日暮時。"]'),
('82a58f41-b6b9-4b48-a896-49f8bd909cbe','聞鳩鳴有感','曹組','宋','宋诗','song-poetry','','[]','鳴鳩一聲斑竹林，懷遠感時驚寸心。',32,'全唐诗/poet.song.103000.json','["鳴鳩一聲斑竹林，懷遠感時驚寸心。", "却憶南園春半夜，薺花如雪草初深。"]'),
('980f7f95-3729-4500-aab2-af9238596920','鴛鴦','曹組','宋','宋诗','song-poetry','','[]','蘋洲花嶼接江湖，頭白成雙得自如。',32,'全唐诗/poet.song.103000.json','["蘋洲花嶼接江湖，頭白成雙得自如。", "春院有時描一對，日長消盡繡工夫。"]'),
('37841258-ae2f-43e3-9a0a-d29746a990bc','翡翠','曹組','宋','宋诗','song-poetry','','[]','窺魚潛立小荷圓，照水飛鳴更碧鮮。',32,'全唐诗/poet.song.103000.json','["窺魚潛立小荷圓，照水飛鳴更碧鮮。", "鬬草人歸尋墜翼，綺窗歸去補花鈿。"]'),
('d0ceedec-e19d-4f77-9dc2-ab5d6ede4083','秋夜宿學','曹組','宋','宋诗','song-poetry','','[]','促織聲中破月懸，水生寒氣近湖邊。',64,'全唐诗/poet.song.103000.json','["促織聲中破月懸，水生寒氣近湖邊。", "城頭三鼓夜方半，窗下一燈人未眠。", "辛苦詩書憐此日，奮飛功業定何年。", "太平干祿無他徑，只有鄉書可薦賢。"]'),
('968cb332-81ac-41f5-8518-a24a6c003bad','寒食輦下','曹組','宋','宋诗','song-poetry','','[]','海棠時節又清明，塵斂煙收雨乍晴。',64,'全唐诗/poet.song.103000.json','["海棠時節又清明，塵斂煙收雨乍晴。", "幾處青簾沽酒市，一竿紅日賣花聲。", "綵毬時向梭門過，繡轂遥隨輦路行。", "日暮人人醉歸去，熙熙春物見昇平。"]'),
('53a46714-1509-4c93-978b-dc1c03e6a5cd','賞心亭','曹組','宋','宋诗','song-poetry','','[]','白鷺洲邊蘆葉黄，石頭城下水茫茫。',64,'全唐诗/poet.song.103000.json','["白鷺洲邊蘆葉黄，石頭城下水茫茫。", "江山不管事興廢，今古坐令人感傷。", "六代豪華空處所，千秋城闕委荒凉。", "空餘眼外無窮景，助我憑欄到夕陽。"]'),
('1d943bdf-b3b3-4491-884f-5978ac874eda','夾竹桃花','曹組','宋','宋诗','song-poetry','','[]','曉欄紅翠凈交陰，風觸芳葩笑不任。',32,'全唐诗/poet.song.103000.json','["曉欄紅翠凈交陰，風觸芳葩笑不任。", "既有柔情慕高節，即宜同抱歲寒心。"]'),
('6eb1339b-fad2-414e-a6dc-d6e9921a4cf2','夜歸曲','曹組','宋','宋诗','song-poetry','','[]','饑烏啞啞啼暮寒，回風急雪飄朱闌。',128,'全唐诗/poet.song.103000.json','["饑烏啞啞啼暮寒，回風急雪飄朱闌。", "瑣窗繡閣艷紅獸，畫幕金泥摇彩鸞。", "吳粧秀色攢眉綠，能唱襄陽大堤曲。", "酒酣橫管咽孤吟，吹裂柯亭傲霜竹。", "遠空寒雲渾不動，老狐應渡黄河凍。", "暗回微煖入江梅，何處荒榛掛幺鳳。", "歸來祇誇青連錢，貂茸擁鼻行翩翩。", "籠紗蜜炬照飛霰，十二玉樓人未眠。"]'),
('de47debf-4cf0-47bc-b142-8f3db97e9ffa','句  其一','曹組','宋','宋诗','song-poetry','','[]','茅屋蕭然野水東。',8,'全唐诗/poet.song.103000.json','["茅屋蕭然野水東。"]'),
('2da41dc5-c0d0-4602-b14a-9e52ab420017','句  其二','曹組','宋','宋诗','song-poetry','','[]','江雨带潮來。',6,'全唐诗/poet.song.103000.json','["江雨带潮來。"]'),
('c965b13b-7bbd-40c4-8ae5-a53b65abca0f','題方干舊隱','陳最','宋','宋诗','song-poetry','','[]','百里青山數曲溪，茂林脩竹此高棲。',32,'全唐诗/poet.song.103000.json','["百里青山數曲溪，茂林脩竹此高棲。", "相尋似訪壺中景，他日重來路不迷。"]'),
('4b9c3b30-50bc-469e-8af4-40162a07902c','題疏山','周之翰','宋','宋诗','song-poetry','','[]','危亭敞層巔，上與霄漢逼。',120,'全唐诗/poet.song.103000.json','["危亭敞層巔，上與霄漢逼。", "化工無藏技，遥露一寸碧。", "天風掃微雲，宛轉樹頭直。", "不須剪狂柯，自與眼界極。", "道人久何營，白足謝塵域。", "苔青石磴險，携客半支錫。", "瘦竹漏殘日，清禽破初寂。", "豈知不可留，何苦事行役。", "薄浪吹船頭，又作城中適。", "回首謝書山，他年問消息。"]'),
('7538da33-3cd2-4c9c-ba3a-692264162f8e','中秋登青原臺','鄭作肅','宋','宋诗','song-poetry','','[]','去年中秋節，鄰州正弄兵。',144,'全唐诗/poet.song.103000.json','["去年中秋節，鄰州正弄兵。", "羽檄方四馳，酒觴難一傾。", "今年當此日，往事久已平。", "不但櫜弓矢，又復見豐登。", "桂魄十分滿，暮容千里晴。", "節物向人好，江山入眼明。", "羣峰翠靄鬰，靜練秋光澄。", "霜竹裂石響，焦桐號鐘清。", "嶪嶪高臺上，飄飄欲雲凌。", "矯首宇宙寬，顧影塵滓輕。", "今夕定何夕，此身非幻身。", "謂言坐中客，不飲若爲情。"]'),
('6a5bd198-6e64-4569-8303-8783a8112f48','寄李忠定公','鄭昌齡','宋','宋诗','song-poetry','','[]','雅望三朝第一流，端如砥柱屹清秋。',64,'全唐诗/poet.song.103000.json','["雅望三朝第一流，端如砥柱屹清秋。", "愛君炯炯無他志，許國堂堂不自謀。", "夢繞蒼龍新闕角，凉生黄鶴舊樓頭。", "中興真主須真相，未雪雙鑾恥未休。"]'),
('b4dd098d-5883-43a5-b647-99f5d77a5798','挽李忠定公','鄭昌齡','宋','宋诗','song-poetry','','[]','炎圖第一相蕭公，王謝風流愧下風。',64,'全唐诗/poet.song.103000.json','["炎圖第一相蕭公，王謝風流愧下風。", "力正君臣先僞楚，不將金帛問和戎。", "輸忠自昔忘夷險，注意如今見始終。", "駐馬佳城天莫問，寒空慘淡沒孤鴻。"]'),
('c99188aa-828f-432d-99a0-87dcfb6f5545','謝秦檜','鄭昌齡','宋','宋诗','song-poetry','','[]','先生傲睨醉觴旁，不覺滂沱入醉鄉。',32,'全唐诗/poet.song.103000.json','["先生傲睨醉觴旁，不覺滂沱入醉鄉。", "來詩恐是醉中語，使我大笑譏荒唐。"]'),
('567de37a-254a-4b82-8898-2922c057652f','題說法臺','鄭昌齡','宋','宋诗','song-poetry','','[]','四十高峰繞法臺，峰峰嶙峋玉蓮開。',64,'全唐诗/poet.song.103000.json','["四十高峰繞法臺，峰峰嶙峋玉蓮開。", "嵐光擁翠猿啼遍，松蓋移陰鶴唳回。", "貝葉乍翻鐘磬暝，金沙猶伏地爐灰。", "天冠隱處多奇絕，時見彌空花雨來。"]'),
('f0a28525-23a8-4d7a-aa5f-e9c23b00bf52','題太平興國宮留雲閣','何致','宋','宋诗','song-poetry','','[]','隱約山光到戶，蕭疏竹影侵窗。',28,'全唐诗/poet.song.103000.json','["隱約山光到戶，蕭疏竹影侵窗。", "晝靜幾聲啼鳥，夜深一枕寒江。"]'),
('c3f7ebbf-99b7-4edd-b5d6-0e50e9aaba5a','題太平興國宮','張漢彥','宋','宋诗','song-poetry','','[]','神仙所居真福地，帝遣仙官下人世。',128,'全唐诗/poet.song.103000.json','["神仙所居真福地，帝遣仙官下人世。", "開元聖主夢潛通，九天使者何靈異。", "絳節霓旌射紫霄，風吹仙袂還飄飄。", "群官再拜所共睹，至今傳聞時未遥。", "眼前不見吳生筆，劫火俱焚餘敗壁。", "當時壯麗爲一空，每對荆蓁頻歎息。", "誰人再造成奇功，巍巍寶殿尤瑰雄。", "我來祈福不爲己，喜見氣象昇平中。"]'),
('629d3b54-4f26-4e82-9665-424ee4007f7a','石仙觀','張漢彥','宋','宋诗','song-poetry','','[]','蒼崖如壁立，神仙好巖居。',144,'全唐诗/poet.song.103000.json','["蒼崖如壁立，神仙好巖居。", "杖藜往佳招，還與勝境俱。", "尋幽憩真館，訪古得遺書。", "傍有千尋木，中藏蟬蛻軀。", "終然躋絕頂，眼界聊一舒。", "軍峯散雲雨，盱水带城隅。", "始知衆山小，端欲隘寰區。", "達人等大觀，笑彼形器拘。", "天寒風景暮，歸興促籃輿。", "幸茲及官閑，行色可徐徐。", "前修儻可作，微祿亦何須。", "眷言還故山，著論擬潛夫。"]'),
('2cd3c0bc-6d97-4cc3-90a9-609cdfaecbe3','爛柯山','趙師聖','宋','宋诗','song-poetry','','[]','姑蔑城南問爛柯，籃輿踏翠晚來過。',64,'全唐诗/poet.song.103000.json','["姑蔑城南問爛柯，籃輿踏翠晚來過。", "巖前雲擁杉松老，席上棋敲日月多。", "四序秋光浮澹蕩，半空鐘韻繞嵯峨。", "仙人去後餘殘局，風雨山深長薜蘿。"]'),
('2b31cdfd-78d9-41bf-b3fe-4c4b334a90c5','句','潘先生','宋','宋诗','song-poetry','','[]','大江今古怒聲怒，長爲將軍氣不平。',16,'全唐诗/poet.song.103000.json','["大江今古怒聲怒，長爲將軍氣不平。"]'),
('2998d680-2842-4c67-aeb0-a1877bf7646f','客觀余孝經傳感而有作','張九成','宋','宋诗','song-poetry','','[]','古人文瑩理，後人工作文。',144,'全唐诗/poet.song.103000.json','["古人文瑩理，後人工作文。", "文工理愈暗，紙札何紛紛。", "君看六藝學，天葩吐奇芬。", "詩書分體製，禮樂造乾坤。", "千歧更萬轍，要以一理存。", "如何臻至理，當從踐履論。", "跋涉經險阻，衝冒恤寒溫。", "孝弟作選鋒，道德嚴中軍。", "仰觀精俯察，萬象入見聞。", "不勞施斧鑿，筆下生烟雲。", "高以君堯舜，下以覺斯民。", "君如不我鄙，時來對爐熏。"]'),
('90d39552-772e-4a65-92bf-8ce802f20e7b','見柿樹有感','張九成','宋','宋诗','song-poetry','','[]','茲山余初來，掩冉柿葉青。',96,'全唐诗/poet.song.103000.json','["茲山余初來，掩冉柿葉青。", "相去未三月，柿花亦已零。", "及茲尋去路，纍纍滿空庭。", "人生豈無情，眷眷不忍行。", "嚴霜八九月，百草不復榮。", "唯君粲丹實，獨掛秋空明。", "寄語看園翁，勿使墮秋風。", "願比櫻桃春，置之大明宮。"]'),
('44b7a82e-dcdb-4b20-a0a6-05ff06a04dbe','魯直上東坡古風坡和之因次其韻  其一','張九成','宋','宋诗','song-poetry','','[]','幽蘭如君子，閒雅翰墨場。',96,'全唐诗/poet.song.103000.json','["幽蘭如君子，閒雅翰墨場。", "春風曉畦暖，斜日半窗光。", "竟夕澹相對，菲菲吐暗香。", "掩關清杖屨，簾卷度修廊。", "釵玉莖分紫，官梅花更黄。", "豈惟堪紉佩，試伴菊英嘗。", "退處深林好，休移庭戶傍。", "自同凡草茂，無事莫相傷。"]'),
('ead10e91-3012-4b87-842f-20b6a8a34c78','魯直上東坡古風坡和之因次其韻  其二','張九成','宋','宋诗','song-poetry','','[]','浮筠雲海上，時作鐘磬聲。',84,'全唐诗/poet.song.103000.json','["浮筠雲海上，時作鐘磬聲。", "政似月中桂，不比首陽苓。", "蓬萊日月長，頃刻已千齡。", "羣仙集其下，談笑得長生。", "回首看塵世，秋瓜易落蔕。", "青鸞何時來，欲作飛升計。", "衆真問平安，此詩煩送似。"]'),
('94d56ca6-0adf-4800-908a-a7ddb8068ab8','癸亥初到嶺下寄汪聖錫','張九成','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','人物苦難得，閉眼不敢看。',108,'全唐诗/poet.song.103000.json','["人物苦難得，閉眼不敢看。", "孤芳擢荒穢，秀色出榛菅。", "懷我同心友，正在天一端。", "文字妙入聖，操履到所難。", "美玉經三煆，貞松過凝寒。", "憐我竄庾嶺，色慘顔不歡。", "書來每慰薦，苦語餘辛酸。", "不上泰山頂，安知天地寬。", "相思暮烟起，片月過前灘。"]'),
('89bcd28d-5c29-48b3-83f4-5ae3beef5c5f','正月二十日出城','張九成','宋','宋诗','song-poetry','','[]','春風驅我出，騎馬到江頭。',120,'全唐诗/poet.song.103000.json','["春風驅我出，騎馬到江頭。", "出門日已暮，獨遊無獻酬。", "江山多景物，春色滿汀洲。", "隔岸花繞屋，斜陽明戍樓。", "人家漸成聚，炊烟天際浮。", "日落霧亦起，羣山定在不。", "江柳故撩人，縈帽不肯休。", "風流乃如此，一笑忘百憂。", "隨行亦有酒，無地可遲留。", "聊寫我心耳，長歌思悠悠。"]'),
('a543bfcd-f86c-4c2c-9661-46757e2731bc','二十六日復出城','張九成','宋','宋诗','song-poetry','','[]','杜門不肯出，既出不忍歸。',120,'全唐诗/poet.song.103000.json','["杜門不肯出，既出不忍歸。", "借問胡爲爾，江山棲落暉。", "濯濯漱寒玉，青青入烟霏。", "柳色明沙岸，花枝作四圍。", "玉塔天外小，漁舟雲際微。", "興遠俗情斷，心閒人事稀。", "我本江湖人，誤落市朝機。", "計拙物多忤，身臞道則肥。", "所以此勝槩，一見不我違。", "吟餘尚多思，白鳥背人飛。"]'),
('6816d2a8-44b0-498c-ae97-bca1e56ef02e','十二日出城見隔江茅舍可愛','張九成','宋','宋诗','song-poetry','','[]','茅屋臨江上，四面惟柴荆。',96,'全唐诗/poet.song.103000.json','["茅屋臨江上，四面惟柴荆。", "綠陰繞籬落，窗几一以明。", "門前灘水急，日與白鷗盟。", "不知何隱士，居此復何營。", "朝來四山碧，晚際沙鳥鳴。", "棋聲度竹靜，江深琴調清。", "終携一尊酒，造門相對傾。", "心期羲皇上，安用知姓名。"]'),
('18095193-4020-4235-9a7e-4ba5ff1442de','客至','張九成','宋','宋诗','song-poetry','','[]','客有叩門者，冠劍何巍巍。',96,'全唐诗/poet.song.103000.json','["客有叩門者，冠劍何巍巍。", "登堂各就坐，酬答好言詞。", "中席客軒眉，揚袂論是非。", "紛紛亂我耳，擾擾敗人思。", "主人默無語，仰看孤鴻飛。", "須臾進盤饌，勸客酒一巵。", "謂言西山好，爽氣入吾扉。", "客思亦沈寂，爐熏自霏霏。"]'),
('d75fc8ac-1711-45b4-baaf-59cc142f1da3','食苦筍','張九成','宋','宋诗','song-poetry','','[]','吾鄉苦筍佳，出處惟石屋。',180,'全唐诗/poet.song.103000.json','["吾鄉苦筍佳，出處惟石屋。", "玉肌膩新酥，黄衣緣深綠。", "林深恐人知，頭角互出縮。", "烟雨養春姿，此物未成熟。", "三月臘酒香，開罇慰幽獨。", "烹庖入盤俎，點醬真味足。", "未須五鼎牛，聊稱一囊粟。", "朅來庾嶺下，歲月去何速。", "經冬又七春，未分窮途哭。", "今朝好事者，惠我生一束。", "頭髠甲斕斑，味惡韻粗俗。", "兒童不慣嘗，噦噫驚媼僕。", "老妻念鄉味，放箸淚盈目。", "丈夫志有在，何事校口腹。", "呼奴更傾酒，一笑風生谷。"]'),
('4f6e1bea-5698-453a-a0cb-41843a92f69c','示兩兒','張九成','宋','宋诗','song-poetry','','[]','余性便靜素，於世寡所諧。',108,'全唐诗/poet.song.103000.json','["余性便靜素，於世寡所諧。", "惟餘黄卷裏，聊與古人偕。", "古人不可期，古心尚可窺。", "當其會意時，悠然忘渴饑。", "可憐朝市人，大與古相違。", "所得眇何有，所亡無町畦。", "嗟乎寓此生，惟善爲可爲。", "舍善亦何樂，至死有餘悲。", "晤此聊自警，亦以警吾兒。"]'),
('07b15f95-b51c-431d-8304-e774a8dec0c5','有客','張九成','宋','宋诗','song-poetry','','[]','春雨止復作，閉門無與居。',132,'全唐诗/poet.song.103000.json','["春雨止復作，閉門無與居。", "童奴告予言，有客叩吾廬。", "束带出見之，頎然一丈夫。", "手携一尊酒，辭氣何晏如。", "謂言久聞名，曾未瞻簪裾。", "天寒宜飲酒，一杯聊以娛。", "盤飧亦草草，蔬果間溪魚。", "顔色溫勝玉，言談貫如珠。", "豈期有道者，而來警我愚。", "酒酣意兩適，心閒樂有餘。", "四海元有人，君勿輕荒區。"]'),
('2ba11bb7-6247-4ab7-8c7b-64f47c871abb','讀梅聖俞詩','張九成','宋','宋诗','song-poetry','','[]','吾生前輩後，不及識諸公。',156,'全唐诗/poet.song.103000.json','["吾生前輩後，不及識諸公。", "每讀諸公集，想見其音容。", "聖俞仁廟時，歐公最相知。", "春風一杯酒，夜坐數章詩。", "雍容長者風，忠厚君子辭。", "格律從正始，句法自爐錘。", "衮衮鳴山泉，款款語親闈。", "試一涉其流，超然忘百憂。", "後輩亦有作，豈曰不冥搜。", "雕琢傷正氣，磔裂無全牛。", "堙鬰暗大理，矜夸墮輕浮。", "所以聖俞詩，把玩不能休。", "死者如可作，吾其與之遊。"]'),
('c035c3ee-03ad-444b-8bfb-950fd8826f2f','菖蒲','張九成','宋','宋诗','song-poetry','','[]','石盆養寒翠，六月如三冬。',72,'全唐诗/poet.song.103000.json','["石盆養寒翠，六月如三冬。", "勿云數寸碧，意若千丈松。", "勁節凌孤竹，虬根蟠老龍。", "傲霜滋正氣，泣露泫春容。", "座有江湖趣，眼無塵土蹤。", "終朝澹相對，澆我磊磈胸。"]'),
('3855d2f1-5f8d-4b01-ac43-70fce81273b8','三月晦到大庾','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我登超然臺，積雨久不止。',120,'全唐诗/poet.song.103000.json','["我登超然臺，積雨久不止。", "臺下柳成行，柳下滿塘水。", "環塘率喬木，照影弄清泚。", "恍如在故鄉，西湖古寺裏。", "氣象極幽深，景物盡蒼翠。", "十年勞夢想，一夕居眼底。", "獨坐不能去，頹然起深思。", "鐘鳴主人歸，燭光何燁煒。", "笑語復移時，夜久余當起。", "歸路夫何如，江聲寒玉碎。"]'),
('5f2bbd99-1fa4-4dbb-bbe1-baf43a9ccadd','勾漕送建茶','張九成','宋','宋诗','song-poetry','','[]','我謫庾嶺下，年年餉焦坑。',156,'全唐诗/poet.song.103000.json','["我謫庾嶺下，年年餉焦坑。", "味雖輕且嫩，越宿苦還生。", "分甘嘗此品，敢望建溪烹。", "勾公道義重，不與炎凉并。", "持節漕七閩，風采照百城。", "冤苦盡昭雪，草木亦欣榮。", "得新未肯嘗，包封寄柴荆。", "罪罟敢當此，自碾供百靈。", "捧杯啜其餘，雲腴徹頂清。", "爽氣生几席，清飚起檐楹。", "頓覺凡骨蛻，疑在白玉京。", "整冠朝金闕，鳴佩謁東皇。", "須臾還舊觀，坐見百慮平。"]'),
('d8e43f21-2177-4cec-9f21-2d9c10dafb65','五月十七日冒暑報謁','張九成','宋','宋诗','song-poetry','','[]','炎熱不可觸，報謁當及時。',108,'全唐诗/poet.song.103000.json','["炎熱不可觸，報謁當及時。", "登車汗如洗，黽勉將何之。", "城隅行詰屈，路轉沿江湄。", "仰看山列黛，俯瞰水淪漪。", "心寬天地大，思遠雲霧披。", "猶如塵土中，忽見元紫芝。", "暑氣眇何許，清凉今在茲。", "客子且休轡，與汝同此嬉。", "人生貴自適，奔走亦奚爲。"]'),
('898094e5-a986-4453-886a-9e29bb9eb9ca','九月七夜喜新凉','張九成','宋','宋诗','song-poetry','','[]','晚來天宇陰，便有如許凉。',108,'全唐诗/poet.song.103000.json','["晚來天宇陰，便有如許凉。", "衣襟不作苦，燈火耿寒光。", "青編如故人，入眼興未央。", "憶昔炎歊日，蒸鬰如揚湯。", "百事懶不支，何暇考短長。", "念此深自喜，拂窗凈琴張。", "老來縱眵昏，閉目自焚香。", "心清神亦正，聖賢儼在傍。", "此意勿輕語，此景吾弗忘。"]'),
('c3256e6a-b237-4d7f-8db2-acafef982edb','十一月忽見雪片居此七年未嘗見也','張九成','宋','宋诗','song-poetry','','[]','寒色遽如許，神清瘦不禁。',108,'全唐诗/poet.song.103000.json','["寒色遽如許，神清瘦不禁。", "瓦溝聲磔索，珠琲亂衣襟。", "斯須忽復變，玉片墮前林。", "風勁勢回旋，飄零蔽遥岑。", "落此炎瘴地，七年到於今。", "不見六花飛，況聞寒玉音。", "今年盈尺瑞，天以慰吾心。", "呼兒具杯盤，開樽須滿斟。", "更製白雪辭，入我綠綺琴。"]'),
('a85d7c98-e7e0-46b2-a4f2-a76d05b00342','庚午正月七夜自詠','張九成','宋','宋诗','song-poetry','','[]','余性寡所諧，平生惟自得。',132,'全唐诗/poet.song.103000.json','["余性寡所諧，平生惟自得。", "談名頸深縮，論利面作赤。", "文不貴雕蟲，詩尤惡鈎擿。", "粗豪真所畏，機巧非予匹。", "所以常閉門，千載求知識。", "黄卷有可人，爲之忘寢食。", "亦復愛山水，策杖無與適。", "看雲獨忘歸，聽泉常永日。", "內樂萬事休，中虛衆妙入。", "欲以語斯人，此事吾無力。", "道喪亦久矣，無言三歎息。"]'),
('85593426-6da8-42ee-a475-8099a4706e9a','偶題','張九成','宋','宋诗','song-poetry','','[]','道立神自昌，心閒氣常正。',84,'全唐诗/poet.song.103000.json','["道立神自昌，心閒氣常正。", "平生飽此味，不與時俗競。", "得失了不關，榮辱任無定。", "君看富貴人，表裏互馳騁。", "雍容若恬澹，笑語多陷穽。", "見此輒自喜，魂夢亦清凈。", "告我同學者，謹勿落此徑。"]'),
('48d737b8-4932-446d-8e74-e5ee49b26757','課書','張九成','宋','宋诗','song-poetry','','[]','汲汲我何事，愛此窗日光。',72,'全唐诗/poet.song.103000.json','["汲汲我何事，愛此窗日光。", "北門終日開，風透軒檻凉。", "貧病何以療，六經真古方。", "榮辱頓爾失，太山亦毫芒。", "呼兒來讀書，絃誦驚滿堂。", "仕途有捷徑，掩口笑我狂。"]'),
('7034db59-1cb6-4ad5-8fed-272b1bc6ceb7','讀書  其一','張九成','宋','宋诗','song-poetry','','[]','伊余生三吳，竄逐落荒外。',72,'全唐诗/poet.song.103000.json','["伊余生三吳，竄逐落荒外。", "大目試環顧，四海等一芥。", "誰能於其間，清濁分涇渭。", "含菽亦飽滿，食蘗有餘味。", "不羨嵇叔夜，左右持酒蟹。", "大哉黄卷中，日與聖賢對。"]'),
('ffcf7cc1-ae0f-44c2-94be-3d6b645ee71e','讀書  其二','張九成','宋','宋诗','song-poetry','','[]','橫浦非吾土，久寓亦何聊。',72,'全唐诗/poet.song.103000.json','["橫浦非吾土，久寓亦何聊。", "不學元相國，百斛貯胡椒。", "饑寒何以遣，唯以文字消。", "方其得意處，捽茹亦逍遥。", "頓忘物我情，天地本寬饒。", "告爾二三子，我歌汝其謠。"]'),
('975f666f-dacd-4b67-86c3-cd1c01bfaf00','罷祿','張九成','宋','宋诗','song-poetry','','[]','嗟余命偏奇，一生墮枯槁。',96,'全唐诗/poet.song.103000.json','["嗟余命偏奇，一生墮枯槁。", "雖無青菁飯，顔色亦自好。", "富貴點污人，修潔終可保。", "居處既悠悠，衣食亦草草。", "靜觀天寶間，脂澤逞淫姣。", "冰山赫日來，隨例須崩倒。", "所得無纖毫，所喪不到老。", "施施若無事，憂心惄如擣。"]'),
('03c2cf06-3b26-4ef2-b8ca-b0469ecf90fc','偶成','張九成','宋','宋诗','song-poetry','','[]','冒熱不安寢，整冠常夙興。',168,'全唐诗/poet.song.103000.json','["冒熱不安寢，整冠常夙興。", "清風入我懷，眷眷如有情。", "嗟彼朝市人，正與膏火爭。", "藏機入鈎鈐，肆辯紛縱橫。", "所得無幾何，所嗟無一誠。", "往來各有趣，南北自分朋。", "明德天所相，欺誣禍所嬰。", "猶如赴火蛾，纏緜尚營營。", "悟此澹無作，不與炎凉并。", "居閒苦無事，驅馬出南城。", "登山猿不避，鼓棹鷗靡驚。", "誰知瘴嵐中，談笑適此生。", "祥鳳非矯矯，高鴻本冥冥。", "請君少安坐，此詩殊可聽。"]'),
('4a6e507d-c30d-4d63-9889-f99114255301','遊塵外亭呈妙喜老師陳元器鄭叔茂沈季誠','張九成','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我本山中人，推出塵寰裏。',84,'全唐诗/poet.song.103000.json','["我本山中人，推出塵寰裏。", "鳥囚不忘飛，今日乃來此。", "長江流吾前，列岫環其趾。", "豁然萬古心，攬之不盈袂。", "同來二三友，秀句粲玉齒。", "中有奇道人，機鋒如建水。", "此境到吾徒，成一段奇事。"]'),
('240c67fc-7cbd-4eba-80ac-80f4b4f62b7e','寄端硯與樊茂實因作詩以遺之','張九成','宋','宋诗','song-poetry','','[]','端谿石硯天下奇，紫光夜半吐虹霓。',96,'全唐诗/poet.song.103000.json','["端谿石硯天下奇，紫光夜半吐虹霓。", "不同凡石追時好，要與日月爭光輝。", "韜藏久矣不敢用，惟恐翰墨污染之。", "樊子文章有餘地，汪汪萬頃誰敢窺。", "贈君此硯勿輕棄，經史妙處其發揮。", "飛流濺沫滿天下，要使咳唾皆珠璣。"]'),
('2d7de132-9598-42a8-bc0e-047689ef393b','懷汪聖錫','張九成','宋','宋诗','song-poetry','','[]','美玉藏精璞，明珠媚深淵。',252,'全唐诗/poet.song.103000.json','["美玉藏精璞，明珠媚深淵。", "天清氣或朗，光景露涓涓。", "或者輒按劍，奇才歎難全。", "之子英傑人，聲名何軒軒。", "妙齡魁四海，終始皆稱賢。", "過眼不再讀，悟心非口傳。", "文真翻手成，識超餘子先。", "森森列五嶽，浩浩朝百川。", "謂年未三十，當握造化權。", "陶甄到唐虞，修潔偕淵騫。", "誰云一戢翅，沈滯十二年。", "衆論今未諧，子心方藐然。", "磨礲盡箭鏃，刮洗成混圓。", "上造羲軒外，下極宣政前。", "討論分本末，鈎賾窮由緣。", "遥遥數千載，恍然落眼邊。", "斯文天其興，子能常躓顛。", "試看桃李花，三春何暄妍。", "未及瞬息間，飄零墮風煙。", "青青喬松枝，霜雪彌貞堅。", "子如識此理，聊卧白雲巔。"]'),
('5496251d-e020-4cf2-8f15-acd06189cd9e','送鄭仲遠','張九成','宋','宋诗','song-poetry','','[]','仲遠英俊人，落筆驚飛電。',156,'全唐诗/poet.song.103000.json','["仲遠英俊人，落筆驚飛電。", "來自神仙中，風姿冰雪盥。", "我謫天南陲，君來適相見。", "憶昔我與君，射策麒麟殿。", "君時氣橫秋，九萬摶風便。", "文辭灑星斗，議論倒江漢。", "便宜上玉堂，不爾登蓬館。", "別來二十年，青衫尚州縣。", "蘭薰麝所忌，玉潔女多怨。", "嗟我正衰遲，何階往論薦。", "豈有如此人，而得長貧賤。", "朝廷方急賢，珠璧聯清貫。", "去去行勿遲，九天春晝暖。"]'),
('60f9efb5-fe52-4024-a28e-dbe006070abe','次陳一鶚韻','張九成','宋','宋诗','song-poetry','','[]','大道若坦塗，踐履何早晚。',144,'全唐诗/poet.song.103000.json','["大道若坦塗，踐履何早晚。", "榛荆蔽不掃，日夜勞勤墾。", "聖門一以披，即日到堂閫。", "但辦不已心，此道誰云遠。", "譬如積水陂，萬頃才一建。", "胡爲不勇决，長年成連蹇。", "百事皆已餘，一心正吾本。", "人欲如火聚，急避勿繾綣。", "超然領斯會，故鄉今已返。", "嗟我困不學，終日徒衮衮。", "羨子有淵源，浚治令深穩。", "斯文付諸公，容我老息偃。"]'),
('f79e2ea4-87c0-4810-9df4-ad254dce90d5','多雨偶成','張九成','宋','宋诗','song-poetry','','[]','謫居天南陲，終年寡儔侶。',48,'全唐诗/poet.song.103000.json','["謫居天南陲，終年寡儔侶。", "四月山氣行，淋漓滿城雨。", "獨坐北窗下，蕭然無一語。", "睡起復何如，雞鳴已亭午。"]'),
('01754ee5-2b7e-4275-bd17-04909f39c74e','即事','張九成','宋','宋诗','song-poetry','','[]','梅天喜蒸潤，江國飽雨澤。',120,'全唐诗/poet.song.103000.json','["梅天喜蒸潤，江國飽雨澤。", "況我謫逐人，窮巷宜閴寂。", "今夕復何夕，門有此佳客。", "貧家亦效勤，草草具一食。", "高興良未盡，奈此短景迫。", "微言若發蒙，喜獲此三益。", "人生務明德，餘景不足惜。", "區區名利人，長年竟何得。", "使我市朝心，一掃便無迹。", "懷君如古人，每事三歎息。"]'),
('70c80d9e-419a-4122-ab41-32aa7d4f465e','十二月二十四夜賦梅花','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我來嶺下已七年，梅花日日鬬清妍。',144,'全唐诗/poet.song.103000.json','["我來嶺下已七年，梅花日日鬬清妍。", "詩才有限思無盡，空把花枝歎晚煙。", "頗怪此花嵐瘴裏，獨抱高潔何娟娟。", "苦如靈均佩蘭芷，遠如元亮當醉眠。", "真香秀色看不足，雪花冰霰相後先。", "平生明明復皦皦，一嗅霜蕊知其天。", "固安冷落甘蠻蜑，不務輕舉巢神仙。", "他年若許中原去，携汝同住西湖邊。", "更尋和靖廟何許，相與澹泊春風前。"]'),
('8d5a57a4-4eb8-4d32-a656-b8a195335340','辛未閏四月即事  其一','張九成','宋','宋诗','song-poetry','','[]','閒居喜無事，冠櫛每晨興。',120,'全唐诗/poet.song.103000.json','["閒居喜無事，冠櫛每晨興。", "今朝鳩喚夢，疑是大雨徵。", "萬事雖顛沛，此兆常可憑。", "須臾倒江湖，一掃蠻瘴腥。", "雨罷有何好，環江數峯青。", "蛟龍得時橫，長堤豁然崩。", "衰老甘寢寐，半夜聞雷聲。", "連岡萬株松，漂零一毛輕。", "雨意疑未已，浮浮晚雲蒸。", "咄哉造化兒，徒勞竟何成。"]'),
('f43d897a-ee4f-45bd-ba81-68a14fe071a4','辛未閏四月即事  其二','張九成','宋','宋诗','song-poetry','','[]','窮居不擇交，賢否那復辨。',108,'全唐诗/poet.song.103000.json','["窮居不擇交，賢否那復辨。", "似人輒已喜，況復曾半面。", "相見且寒溫，不問風雨變。", "晚來無與遊，澄江喜如練。", "携筇信步行，屈曲隨山轉。", "數日雨不止，衝波頹激箭。", "舊雨已不來，今雨誰復見。", "甕頭香滿屋，吾計今已辦。", "豈復思故鄉，無事且彊飯。"]'),
('f55e0b49-58be-447e-8a53-1c06f631aa3a','辛未閏四月即事  其三','張九成','宋','宋诗','song-poetry','','[]','相馬須相骨，探水須探源。',96,'全唐诗/poet.song.103000.json','["相馬須相骨，探水須探源。", "君如識此理，知人若神仙。", "可以千歲下，坐照萬古前。", "有時陰求人，得意初無言。", "如聞失一士，每食不下咽。", "人才何其鮮，求一於百千。", "豈獨今世歟，自古皆已然。", "我欲授此法，其誰可與傳。"]'),
('04d7b605-863e-4405-8030-ab878becceeb','辛未閏四月即事  其四','張九成','宋','宋诗','song-poetry','','[]','平時罕啟門，愛此月色佳。',72,'全唐诗/poet.song.103000.json','["平時罕啟門，愛此月色佳。", "倚杖看未厭，戍樓已鳴笳。", "須臾星斗稀，河漢亦橫斜。", "餘生知幾何，短髮今已華。", "且盡此杯酒，未用輒興嗟。", "乾坤真轉磨，羲娥互奔車。"]'),
('4ad8cc2f-8e6d-488e-aeb6-a2b1138eb500','辛未閏四月即事  其五','張九成','宋','宋诗','song-poetry','','[]','種槿已五載，入門幽逕深。',60,'全唐诗/poet.song.103000.json','["種槿已五載，入門幽逕深。", "拒霜偶然植，亦解成清陰。", "晚凉新浴罷，松風披我襟。", "終日岸巾坐，閴無人見尋。", "浩然媚幽獨，發興付瑶琴。"]'),
('4d9146a9-3a59-4b3a-8267-f7f80ebc73b4','辛未閏四月即事  其六','張九成','宋','宋诗','song-poetry','','[]','寓居城中寺，蕭然如深山。',84,'全唐诗/poet.song.103000.json','["寓居城中寺，蕭然如深山。", "終年客不到，終日門亦關。", "晨朝香火罷，去履脫危冠。", "飽讀古人書，會意有餘歡。", "客有饋荔枝，薦以碧玉盤。", "吟哦更咀嚼，未羨朱兩轓。", "鮫綃作紅皺，護此冰肌寒。"]'),
('79ded4bf-39b4-4574-a6ce-c95909722374','辛未閏四月即事  其七','張九成','宋','宋诗','song-poetry','','[]','橫浦亦何好，人烟眇荒墟。',96,'全唐诗/poet.song.103000.json','["橫浦亦何好，人烟眇荒墟。", "所以常閉門，九年唯讀書。", "余幼好奇服，玉佩而瓊琚。", "念往復推來，薰然樂有餘。", "客有不知者，笑我長勤渠。", "目昏心則瑩，道腴形自枯。", "千載陶淵明，簞瓢常晏如。", "譬彼雞繡羣，有此海鶴孤。"]'),
('bf0938a2-78b5-444d-bcca-e0e5c023faae','有感','張九成','宋','宋诗','song-poetry','','[]','日月不知久，優遊蕭寺居。',96,'全唐诗/poet.song.103000.json','["日月不知久，優遊蕭寺居。", "臘月三十日，方驚歲又除。", "如此度九年，終朝樂有餘。", "後圃剩寒菜，水南多美魚。", "飯罷亦何爲，北窗工讀書。", "興來或意倦，玉軸時卷舒。", "傍人多失笑，謂我何迂疏。", "巍然王公門，胡不曳長裾。"]'),
('73a5ad5f-82e6-4f84-93aa-a7d7dbc2cfe5','十九日雜興  其一','張九成','宋','宋诗','song-poetry','','[]','不是南方熱，愛此有永日。',96,'全唐诗/poet.song.103000.json','["不是南方熱，愛此有永日。", "人事斷經過，蕭然空一室。", "風驚窗外竹，聲如清廟瑟。", "西塘荷已花，北戶棗亦實。", "仕途非所長，進寸輒退尺。", "所以入市朝，愁苦甘首疾。", "謫來已九年，底事無憂色。", "山林興甚長，湖海情何極。"]'),
('1fe0a111-113f-44ff-8a76-3bdeb448ff25','十九日雜興  其二','張九成','宋','宋诗','song-poetry','','[]','物理情不齊，人生各有好。',120,'全唐诗/poet.song.103000.json','["物理情不齊，人生各有好。", "所好儻不獲，亦各騁奇巧。", "淺者不及門，深者入堂奧。", "名利工欺人，市朝徒膠膠。", "所得無幾何，舌焦唇亦燥。", "其間狹劣者，不售輒復躁。", "亦有操金珠，侯門致私禱。", "葡萄得凉州，所求輒復効。", "舐痔或嘗糞，車服夸新好。", "吾唯戒妻奴，酒熟宜予告。"]'),
('354f42e3-41d3-408a-93df-6ba6dbf1e33a','和施彥執懷姚進道葉先覺韻','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖十里山，春風一杯酒。',240,'全唐诗/poet.song.103000.json','["西湖十里山，春風一杯酒。", "茲興良不淺，何日落吾手。", "我讀君和詩，襟期一何厚。", "同生上下宇，共閱古今宙。", "死生何足云，餘年付美酎。", "佩印還故鄉，衣錦眩春晝。", "一時正兒嬉，千歲墮塵垢。", "所以賢達人，中懷元有守。", "試看窗日中，野馬互奔驟。", "區區竟何成，尚誇舌在口。", "宿習猶未除，新詩漫懷舊。", "環顧天地間，四海惟三友。", "兩老雖未死，二妙已先踣。", "生者豈其巧，死者亦非謬。", "君如悟斯契，萬事可懷袖。", "銅錢自如山，金印自如斗。", "只今定何間，腐骨久已朽。", "籬菊師淵明，庭草悲王胄。", "彼已升層霄，此猶鑿戶牖。", "浩歌君其聆，相看都皓首。"]'),
('1528c750-05e4-4810-b5f8-6fcc214e8f41','彥執賞予詩','張九成','宋','宋诗','song-poetry','','[]','年來百念灰，求友良未已。',120,'全唐诗/poet.song.103000.json','["年來百念灰，求友良未已。", "一昨竄逐來，萬事風過耳。", "忽得故人書，驚喜或不寐。", "人生等行客，斯會姑小憇。", "吟詩本不工，信口何足貴。", "譬彼蜩螗蟲，時時一鳴沸。", "自惟儘喑默，何以玩浮世。", "不煩更咀嚼，欲聽已漂逝。", "胡爲不解事，異好仍偏嗜。", "從來不求名，遊戲聊卒歲。"]'),
('69435861-2125-492b-ba7d-54764aed682d','擬古  其一','張九成','宋','宋诗','song-poetry','','[]','平居自相樂，忽焉成別離。',84,'全唐诗/poet.song.103000.json','["平居自相樂，忽焉成別離。", "君居天之南，我墮海之涯。", "四海豈不大，非君誰我知。", "狡兔營三窟，鷦鷯安一枝。", "勿云千里遠，相見無遲緩。", "精誠儻可通，指日日猶反。", "毋爲浪相思，我老尚能飯。"]'),
('4cc5f87f-6fc3-4a33-b28d-f708b63896a8','擬古  其二','張九成','宋','宋诗','song-poetry','','[]','夭矯山頂松，葱蒨門前柳。',60,'全唐诗/poet.song.103000.json','["夭矯山頂松，葱蒨門前柳。", "高低邈不同，日日滿窗牖。", "窮通端似之，盡入乾坤手。", "願爲深閨女，勿學商人婦。", "閨女老彌貞，商婦多失守。"]'),
('e8664552-84a1-4cc2-a3d4-65fb631a438f','擬古  其三','張九成','宋','宋诗','song-poetry','','[]','昔我竄橫浦，佳致未易陳。',84,'全唐诗/poet.song.103000.json','["昔我竄橫浦，佳致未易陳。", "偶經𥥈頭宿，谿山妙入神。", "煙波橫小艇，疑是古玄真。", "逝言或生還，孤志良一伸。", "別來已十載，念此渴生塵。", "何當携我輩，徑往莫問律。", "謹勿思高官，驚憂可悲辛。"]'),
('a99f9703-5760-4a7a-9b4b-bad3aa97f89d','擬古  其四','張九成','宋','宋诗','song-poetry','','[]','平生澹無營，生計亦草草。',48,'全唐诗/poet.song.103000.json','["平生澹無營，生計亦草草。", "吾廬儘有餘，懶問長安道。", "楚澤驚屈平，書空咤殷浩。", "願君且休矣，沈憂令人老。"]'),
('c694a994-a8a4-4141-9ed3-72c222aa4d44','擬古  其五','張九成','宋','宋诗','song-poetry','','[]','余生本無用，頹然落澗阿。',72,'全唐诗/poet.song.103000.json','["余生本無用，頹然落澗阿。", "饑食山頂薇，寒編松上蘿。", "豈敢怨明時，貧賤固其宜。", "原憲樂窮巷，屈平愁深陂。", "度量何相越，道在胡速遲。", "屈子則已矣，原子有餘輝。"]'),
('163e49cc-e0f2-4c82-9cef-0b77927a5bb4','擬古  其六','張九成','宋','宋诗','song-poetry','','[]','願隨春陽和，不隨秋草萎。',72,'全唐诗/poet.song.103000.json','["願隨春陽和，不隨秋草萎。", "光陰瞬息耳，憂悲亦何爲。", "蘭蕙生深林，時有朝露滋。", "清香隨春風，邈若有所思。", "我亦慕明德，杖藜往從之。", "林深不可見，相遇終有時。"]'),
('9fd93e07-4371-48df-9df7-591540437c16','擬古  其七','張九成','宋','宋诗','song-poetry','','[]','蕭騷老蠶婦，窈窕深閨女。',60,'全唐诗/poet.song.103000.json','["蕭騷老蠶婦，窈窕深閨女。", "閨女曳羅裳，老婦勤機杼。", "夜深燈火微，那復凄寒雨。", "辛勤貢王宮，棄擲乃如許。", "一縷不著身，含愁誰敢語。"]'),
('0b434b22-36d4-40fa-9e89-871ac00124c2','擬古  其八','張九成','宋','宋诗','song-poetry','','[]','促裝何喧喧，西笑都門道。',72,'全唐诗/poet.song.103000.json','["促裝何喧喧，西笑都門道。", "出門何所見，王孫媚春草。", "綠鬢仍朱顔，未信人間老。", "去去謹勿遲，功名苦不早。", "君看郭令公，書二十四考。", "丈夫自足珍，珠金何用寶。"]'),
('6f29391a-d147-4578-ba7d-c24d37c58aaa','擬古  其九','張九成','宋','宋诗','song-poetry','','[]','山色翠挼藍，杯中酒如玉。',60,'全唐诗/poet.song.103000.json','["山色翠挼藍，杯中酒如玉。", "飲酒彈瑶琴，漫奏流水曲。", "音微澹無味，絃緩軫不促。", "不須苦求知，古人有遺躅。", "推琴一長嘯，清風振吾屋。"]'),
('b432e487-ec33-4c15-a962-194e8991cf3e','擬古  其一○','張九成','宋','宋诗','song-poetry','','[]','喬松列萬行，知是誰人墓。',108,'全唐诗/poet.song.103000.json','["喬松列萬行，知是誰人墓。", "龜趺表山岡，石馬夾山路。", "潺潺瀑水秋，蕭蕭白楊暮。", "蒼黄愁殺人，何物能超寤。", "人命極危脆，不殊花上露。", "秦皇死則已，規與山河固。", "一朝禍事發，所掘無尺度。", "想見冥漠中，自歎平生誤。", "遺臭千萬年，至今污尺素。"]'),
('ba104bf9-20c5-434b-ac99-d9c60840b14d','擬古  其一一','張九成','宋','宋诗','song-poetry','','[]','少小有高志，思與古人親。',60,'全唐诗/poet.song.103000.json','["少小有高志，思與古人親。", "二十學文史，三十窮典墳。", "坐觀世間事，抱火厝積薪。", "此心雖炯然，不敢以告人。", "君門深九重，欲陳諒何因。"]'),
('e865eeaa-6cbf-41bd-a5d1-3365b7fc1e7f','擬古  其一二','張九成','宋','宋诗','song-poetry','','[]','已往不足念，未至復何憂。',60,'全唐诗/poet.song.103000.json','["已往不足念，未至復何憂。", "今辰天氣佳，駕言聊出遊。", "欲識斜川時，佳處只在茲。", "穆王宴瑶池，翻爲達者嗤。", "鍾子今亡矣，難與古人期。"]'),
('dc33e1c5-56a9-41dd-9492-54712aea758d','擬古  其一三','張九成','宋','宋诗','song-poetry','','[]','夜月冷如冰，朝霞燦成綺。',60,'全唐诗/poet.song.103000.json','["夜月冷如冰，朝霞燦成綺。", "借問孰爲之，大化自然爾。", "斲月爲酒壺，裁霞爲寢被。", "酣眠九天上，此意誰能解。", "要與同心人，情話當及此。"]'),
('66af88f0-8da2-4ef7-b6f4-a2b412ed7d04','贈樊茂實鐵照','張九成','宋','宋诗','song-poetry','','[]','吾篋有鐵鏡，其光常炯炯。',98,'全唐诗/poet.song.103000.json','["吾篋有鐵鏡，其光常炯炯。", "有時置堂中，千妖百怪都潜影。", "今以贈吾子，吾子其試聽。", "謹勿以照人，百鬼聞之怒生癭。", "不如照汝心，非心邪意令遠屏。", "闇室何妨日月明，闤闠方知天地靜。", "它年相見打破鏡，吾當大笑君其領。"]'),
('4cd8d513-d9c0-4e0a-8676-c99c79381402','子集弟寄江蟹','張九成','宋','宋诗','song-poetry','','[]','吾鄉十月間，海錯賤如土。',144,'全唐诗/poet.song.103000.json','["吾鄉十月間，海錯賤如土。", "尤思鹽白蟹，滿殻紅初吐。", "薦酒欻空尊，侑飯饞如虎。", "別來九年矣，食物那可睹。", "蠻煙瘴雨中，滋味更荼苦。", "池魚腥徹骨，江魚骨無數。", "每食輒嘔噦，無辭知罪罟。", "新年庚運通，此物登盤俎。", "先以供祖先，次以宴賓侶。", "其餘及妻子，咀嚼話江浦。", "骨滓不敢擲，念带煙江雨。", "手足義可量，封寄無辭屢。"]'),
('34078e3c-4715-4d07-9344-5a6f1f27a815','嘉祐寺','張九成','宋','宋诗','song-poetry','','[]','曳屣出南郭，招提在高岡。',120,'全唐诗/poet.song.103000.json','["曳屣出南郭，招提在高岡。", "誰言林樾中，乃有此寶坊。", "甘泉溢中庭，修桂蔭層廊。", "三秋此花開，清香駐高堂。", "試問紅塵中，那得六月凉。", "門外江聲急，堂中松韻長。", "古殿儼像設，佛燈龕夜光。", "不見堂中人，斗覺心悲傷。", "人生本無定，樂處是吾鄉。", "吟餘復何事，月落山蒼蒼。"]'),
('2881b9c6-8bc7-49ae-a04b-afce2a170299','讀東坡謫居三適輒次其韻 旦起理髮','張九成','宋','宋诗','song-poetry','','[]','憶昔叨從班，入朝大明宮。',120,'全唐诗/poet.song.103000.json','["憶昔叨從班，入朝大明宮。", "五更催上馬，夢裏過萬松。", "想見天竺山，九重吟清風。", "頭垢不暇梳，爬搔常靡通。", "今來幸閒放，櫛比肯匆匆。", "清晨解絛辮，千梳復重重。", "不羨列禦寇，散髮摇風鬉。", "氣舒兩目明，頓與離朱同。", "此樂豈易得，快意適相逢。", "再拜復再拜，深恩荷天公。"]'),
('64d1819e-6da3-474b-98cc-d38c0352dbc9','讀東坡謫居三適輒次其韻 午窗坐睡','張九成','宋','宋诗','song-poetry','','[]','年老目飛花，心化柳生肘。',120,'全唐诗/poet.song.103000.json','["年老目飛花，心化柳生肘。", "萬事元一夢，古今復何有。", "六月苦夜短，午晝何其久。", "頹然北窗下，竹几休兩手。", "昏昏不復知，酣適如中酒。", "睡鄉日月長，椿靈未爲壽。", "形存若蟬蛻，質槁如木朽。", "榮辱漫紛紛，正夢那復受。", "有夢尚有思，無夢真無垢。", "欲呼李太白，醉眠成二叟。"]'),
('7d781633-d7e2-4308-a44d-f2ab30458139','讀東坡謫居三適輒次其韻 夜卧濯足','張九成','宋','宋诗','song-poetry','','[]','夏日乏絺葛，冬來無衾裯。',120,'全唐诗/poet.song.103000.json','["夏日乏絺葛，冬來無衾裯。", "況復竄炎荒，令人生百憂。", "空城舞狐狸，深林鳴鵂鶹。", "此邦無足戀，聊爲薪水留。", "枯枝煮寒泉，大竈聲颼颼。", "老盆深注湯，徐以雙骹投。", "沃久意痛快，縶維今脫韝。", "須臾膏液上，兩踝暖氣浮。", "生平苦寒痹，一洗皆已瘳。", "登山不須扶，跳梁逐狙猴。"]'),
('478a7e8f-1c94-4044-af74-a2ac90ead8af','秋興  其一','張九成','宋','宋诗','song-poetry','','[]','秋意入茅屋，杖策登平原。',72,'全唐诗/poet.song.103000.json','["秋意入茅屋，杖策登平原。", "落日銜西山，一川頓明鮮。", "蕭蕭江上竹，溜溜巖下泉。", "我生本閒放，胡爲此拘拳。", "身世兩相違，於今六十年。", "勇退未爲怯，銳進豈其賢。"]'),
('d67d96b8-5e8c-46ef-848d-cfa85b1543be','秋興  其二','張九成','宋','宋诗','song-poetry','','[]','半夜驚夢回，桐葉紛索索。',96,'全唐诗/poet.song.103000.json','["半夜驚夢回，桐葉紛索索。", "杖藜視天宇，雨罷雲收脚。", "清風拂襟裾，片月墮籬落。", "嗟我遊已倦，悵此久淹泊。", "豆畦今已花，稻垅行可穫。", "翻思黄卷中，古人誰可作。", "田園愛潜歸，簞瓢識顔樂。", "譬彼鷦鷯心，平生在叢薄。"]'),
('a16c8496-2fdd-4bef-a3ff-dae35b70608d','秋興  其三','張九成','宋','宋诗','song-poetry','','[]','月落在樓角，驚烏連夜啼。',96,'全唐诗/poet.song.103000.json','["月落在樓角，驚烏連夜啼。", "門前蟬噪急，床下蛩亦悲。", "豈不念節物，清霜殞華姿。", "况我有鴒原，九年此生離。", "時亦詠歸去，緬焉久無期。", "爲善天所相，何以報吾施。", "大明生於東，皎月生於西。", "茲理儻不昧，胡爲浪嗟咨。"]'),
('c6402135-9b5a-4ed2-a962-f610e483fd73','七月十二日偶成  其一','張九成','宋','宋诗','song-poetry','','[]','今夕起鄉心，何日歸漁釣。',48,'全唐诗/poet.song.103000.json','["今夕起鄉心，何日歸漁釣。", "欲歸定何所，無言獨長嘯。", "君意復何如，老少不同調。", "此生吾自斷，天道自難料。"]'),
('7306f035-aab7-4e8e-ad7c-bb178cfec117','七月十二日偶成  其二','張九成','宋','宋诗','song-poetry','','[]','塘南蓮吐錦，塘北樹成幄。',48,'全唐诗/poet.song.103000.json','["塘南蓮吐錦，塘北樹成幄。", "夜來已秋風，朝見一葉落。", "呼酒玩餘景，行見紛索索。", "人生如寄耳，何苦不行樂。"]'),
('d6d11dfb-45af-4615-9c5d-6d30c62e79b4','秋晴','張九成','宋','宋诗','song-poetry','','[]','秋空極清快，偶值數日陰。',48,'全唐诗/poet.song.103000.json','["秋空極清快，偶值數日陰。", "造物果何意，成此三日霖。", "晚來風色轉，天邊露遥岑。", "無言若有得，古人知我心。"]'),
('da8a8393-d013-4bea-905e-7470d6cd4708','中秋','張九成','宋','宋诗','song-poetry','','[]','陰雲不見日，何處有秋天。',48,'全唐诗/poet.song.103000.json','["陰雲不見日，何處有秋天。", "今夕復何夕，青山滿檐前。", "況是中秋夜，玩月不知眠。", "杯盤同勝友，此事記年年。"]'),
('b430dd38-a518-4b76-92b4-c86a75d94aad','聞桂香','張九成','宋','宋诗','song-poetry','','[]','清晨未盥櫛，桂香遞秋風。',48,'全唐诗/poet.song.103000.json','["清晨未盥櫛，桂香遞秋風。", "不知此花意，何爲惱衰翁。", "舉頭復何有，燕雁書晴空。", "景物如此好，誰云吾道窮。"]'),
('00bf0dda-8b02-4cf7-9a68-bbf7d0930357','喜晴','張九成','宋','宋诗','song-poetry','','[]','今晨日色佳，一洗數夕陰。',48,'全唐诗/poet.song.103000.json','["今晨日色佳，一洗數夕陰。", "開門玩秋色，愛此佳山林。", "人事端可絕，俗慮莫相侵。", "綠綺奏流水，門外無知音。"]'),
('0feadcb0-5e6e-4c0f-ad28-c73834e12df5','桂','張九成','宋','宋诗','song-poetry','','[]','清香不復聞，雪英驚滿地。',48,'全唐诗/poet.song.103000.json','["清香不復聞，雪英驚滿地。", "尚餘青青葉，濃陰猶可庇。", "我欲營茅屋，示此惜花意。", "茲謀未易言，俗士寡清致。"]'),
('6e80a0f6-56ba-41ad-a595-e9bc16fcfe35','擬歸田園  其一','張九成','宋','宋诗','song-poetry','','[]','朝市良可厭，不如歸故山。',120,'全唐诗/poet.song.103000.json','["朝市良可厭，不如歸故山。", "故山山色好，別來知幾年。", "威鳳翔高岡，神龍潜深淵。", "黄鵠志千里，皓鶴戀芝田。", "吾意亦如此，志在山水間。", "千峰列溪上，修竹滿檐前。", "樵唱歸落照，僧鐘鳴曉煙。", "晚來閒覽鏡，白髮冠頹顛。", "回思人間事，百計不如閒。", "吾言奚激烈，此事非偶然。"]'),
('6c080a41-2200-4453-b298-609c81537c4b','擬歸田園  其二','張九成','宋','宋诗','song-poetry','','[]','聖賢乃準的，仁義即羈鞅。',72,'全唐诗/poet.song.103000.json','["聖賢乃準的，仁義即羈鞅。", "遨遊君子場，邪私不入想。", "時與顔閔徒，結交尚來往。", "稂莠日以消，稻粱日以長。", "荆棘頓披除，大道何其廣。", "猶恐忽戒謹，失計成鹵莽。"]'),
('5224c45b-5709-4585-9364-d554d43a8b84','擬歸田園  其三','張九成','宋','宋诗','song-poetry','','[]','所居極幽深，事簡人迹稀。',48,'全唐诗/poet.song.103000.json','["所居極幽深，事簡人迹稀。", "乘興或登山，興盡輒復歸。", "芝朮足吾糧，薜蘿富吾衣。", "一生澹無營，百事不我違。"]'),
('e885f840-574e-4e03-9e2f-85e8e01b4607','擬歸田園  其四','張九成','宋','宋诗','song-poetry','','[]','不必效沮溺，聊與世相娛。',96,'全唐诗/poet.song.103000.json','["不必效沮溺，聊與世相娛。", "荒山無鄰里，人煙在村墟。", "所以近城市，幽處卜吾居。", "門前草三徑，堂下柳五株。", "雖無羊酪羹，簞瓢亦晏如。", "在我儻知足，清貧樂有餘。", "子雲作甘泉，相如賦子虛。", "嗟我懶此學，篋中一字無。"]'),
('eb4b1fb7-84f8-4c1c-a415-bdad1e7bab45','擬歸田園  其五','張九成','宋','宋诗','song-poetry','','[]','安得我輩人，一杯敘心曲。',60,'全唐诗/poet.song.103000.json','["安得我輩人，一杯敘心曲。", "肝膽已相知，吾事一生足。", "長日何以消，忘言書一束。", "夜闌相對語，松膏勝華燭。", "衮衮不知眠，窗明天已旭。"]'),
('37dd1d57-4d84-4443-8749-260cda378e22','擬歸田園  其六','張九成','宋','宋诗','song-poetry','','[]','出門何所見，桃李漫阡陌。',72,'全唐诗/poet.song.103000.json','["出門何所見，桃李漫阡陌。", "東風自有情，萬物各有適。", "驅馳喪我真，塵垢投其隙。", "可憐漫不知，終日常役役。", "及其蓋棺時，平生無寸績。", "達人深了此，名利終無益。"]'),
('60d78f42-ee07-4f21-8e4c-671673cfdcd2','讀東坡疊嶂圖有感因次其韻','張九成','宋','宋诗','song-poetry','','[]','虬鬚英武喧天淵，當時功臣畫凌煙。',233,'全唐诗/poet.song.103000.json','["虬鬚英武喧天淵，當時功臣畫凌煙。", "漢家驍騎才三萬，北攻稽落書燕然。", "勳名鼎鼎磨星斗，百年衰落歸黄泉。", "人間萬事都如夢，不如掛冠神武尋山川。", "我昔曾登會稽頂，逍遥疑在羲皇前。", "下觀濤江卷飛雪，旁看秦望森摩天。", "祖龍定是同鮑臭，鴟夷却得携妖妍。", "悠然會意不復出，倚鋤便欲耕春田。", "君不見淵明歸去傳圖畫，伯時妙手垂千年。", "我藏東絹今拂拭，正欲寫此春江浩渺山連娟。", "更要元龍湖海士，百尺樓中相對眠。", "玉京蓬島置勿問，人間今是地行仙。", "岷江寥寥三峽遠，此心欲往知何緣。", "煩君斷取來方丈，徑入東坡疊嶂篇。"]'),
('9297bbd0-c732-49e7-8932-e1b84a2d0bc3','聞彥執熙仲有辣螺詩聊復有作','張九成','宋','宋诗','song-poetry','','[]','乾坤中空繞滄溟，千奇百怪鬬露形。',128,'全唐诗/poet.song.103000.json','["乾坤中空繞滄溟，千奇百怪鬬露形。", "鯨鯢黿鼉突相撐，蚶蜃蚌蛤角介獰。", "是中有物入眼生，羊腸蟻垤紛縱橫。", "入口小辛美且清，薦酒百盞壺更傾。", "有如汲直官漢京，諫諍雖切心本平。", "肩吾作詩翻手成，士龍筆力敵相勍。", "嗟我材短誰敢賡，欲往侑坐愁頡羹。", "句澀韻梗君莫輕，雄豪似勝蒼蠅鳴。"]'),
('d7b2684e-f93d-4d3c-872d-764d2251767e','有感','張九成','宋','宋诗','song-poetry','','[]','江天之南有一士，自稱聖世無知子。',64,'全唐诗/poet.song.103000.json','["江天之南有一士，自稱聖世無知子。", "辛勤讀書欲有爲，平生未曾用一字。", "憔悴而今白髮翁，天地之間誰復似。", "胸中却有最佳處，一息遨遊三萬里。"]'),
('3e60ad6a-72f1-4bb4-9059-b51f1ded05cd','楊榦致仕','張九成','宋','宋诗','song-poetry','','[]','黄鍾毀棄鳴瓦釜，古來才智賤如土。',128,'全唐诗/poet.song.103000.json','["黄鍾毀棄鳴瓦釜，古來才智賤如土。", "楊公浩歌聲可憐，巢居知風穴知雨。", "憐君面色瑩有光，未似相君便飲乳。", "胡爲决去不少留，別意殷勤辭更苦。", "丁寧戒我宜退藏，靜中得路何須語。", "酒酣意氣尚爾豪，拔劍高歌爲予舞。", "君今去矣且加飯，我亦從茲不出戶。", "莫嗟糟糠食牢筴，終勝繡衣登鼎俎。"]'),
('5acc1ba8-d694-42b9-a102-8f3afb90f8b5','所見','張九成','宋','宋诗','song-poetry','','[]','兩肘橫奮何翩翩，中欲高舉外則然。',64,'全唐诗/poet.song.103000.json','["兩肘橫奮何翩翩，中欲高舉外則然。", "相見胸次開闤闠，一談名利如火然。", "君知古人著意處，君且少聽休彈冠。", "人生百年如逝川，那用如此爭後先。"]'),
('03f219d3-4dde-44aa-845e-341f914c976b','六月晦送孫少劉','張九成','宋','宋诗','song-poetry','','[]','三年相處如弟兄，他時當以名節稱。',160,'全唐诗/poet.song.103000.json','["三年相處如弟兄，他時當以名節稱。", "文章爛若蜀江錦，行義清勝萬壑冰。", "龜山先生今往矣，我於吾子見典型。", "青衫半百官嶺下，衆論稱屈氣甚平。", "乃知胸中萬鈞重，此外真成一髮輕。", "道如未央神明臺，雖高自可階級登。", "卷之不殊方寸小，舒之足以蘇疲氓。", "我衰退縮如蝸螺，愛子對我懷抱清。", "平生艱苦今已老，空歎白首都無成。", "看公權奇非凡骨，努力吾道謹其行。"]'),
('e6654182-a35b-4372-8525-9339d0cde5b5','竹','張九成','宋','宋诗','song-poetry','','[]','簾外誰家竹，凉風日日生。',48,'全唐诗/poet.song.103000.json','["簾外誰家竹，凉風日日生。", "凌霜驚節老，带月出雲明。", "色映樽罍綠，聲傳鐘磬清。", "葛陂看變化，甘雨滿寰瀛。"]'),
('b637eaa0-066f-46cd-9c14-139f28f81058','遊南路菩提寺次刁文叔韻','張九成','宋','宋诗','song-poetry','','[]','高僧居物外，有戶晝常扃。',48,'全唐诗/poet.song.103000.json','["高僧居物外，有戶晝常扃。", "海闊知天大，泉甘識地靈。", "一簾春月靜，數點列山青。", "便卜歸歟計，移文休勒銘。"]'),
('f7922fbe-5b23-4a42-83ad-13770d5870c6','雙秀峰','張九成','宋','宋诗','song-poetry','','[]','且向城西去，休驚雨濺空。',48,'全唐诗/poet.song.103000.json','["且向城西去，休驚雨濺空。", "亂山明滅外，古剎有無中。", "笑指雙峰翠，迴看落日紅。", "中興喜無事，歌管莫匆匆。"]'),
('7c7635b4-a9a0-495e-81da-9f4fe37ea28d','送單普赴肇慶節推','張九成','宋','宋诗','song-poetry','','[]','歲窮情錯莫，吾子欲何之。',48,'全唐诗/poet.song.103000.json','["歲窮情錯莫，吾子欲何之。", "庾嶺梅今見，端谿石自奇。", "瘴深宜飲酒，公退好哦詩。", "莫謂無征雁，而忘酌別時。"]'),
('57a6f167-5bc9-47d9-a084-19cb35f1c5a9','過報恩','張九成','宋','宋诗','song-poetry','','[]','籃輿訪蕭寺，烟暝漲春空。',48,'全唐诗/poet.song.103000.json','["籃輿訪蕭寺，烟暝漲春空。", "遠樹樓頭綠，殘霞山外紅。", "昏鐘發林杪，人語殷橋東。", "回首都無迹，人生真夢中。"]'),
('80eba8a7-d7e0-46c6-87ef-fe288867fc07','雨','張九成','宋','宋诗','song-poetry','','[]','已止還復作，瀉檐聲更長。',48,'全唐诗/poet.song.103000.json','["已止還復作，瀉檐聲更長。", "苔錢添晚翠，梅子試新黄。", "屋裏圖書潤，庭前蘭芷香。", "倚欄閒覓句，水閣夜生凉。"]'),
('ef757c09-2229-4a4b-8f71-eb0f2ec0ffc0','三月晦城門晚景','張九成','宋','宋诗','song-poetry','','[]','雨漲春江浪，沄沄日夜奔。',48,'全唐诗/poet.song.103000.json','["雨漲春江浪，沄沄日夜奔。", "羣山落雲裏，萬壑吼巖根。", "沙際人呼渡，烟中牧入村。", "蕭然何處士，終日掩柴門。"]'),
('27bdc01b-da13-4a6d-8afa-622329f81017','題竹軒  其一','張九成','宋','宋诗','song-poetry','','[]','老僧真好事，種竹繞禪房。',48,'全唐诗/poet.song.103000.json','["老僧真好事，種竹繞禪房。", "月出窗扉靜，風來巾屨凉。", "清香泛蘭芷，幽韻咽笙簧。", "何日林間去，歸歟興未忘。"]'),
('ff4a28f0-a31b-47d7-9124-c8f6bb6e8270','題竹軒  其二','張九成','宋','宋诗','song-poetry','','[]','聽說竹軒趣，清幽盡此房。',48,'全唐诗/poet.song.103000.json','["聽說竹軒趣，清幽盡此房。", "春禽一聲杳，夏簟五更凉。", "落雪鳴寒玉，啼螿泣古簧。", "因君詩意到，欲罷不能忘。"]'),
('2156c64f-cc87-472b-9973-951801c8614f','題竹軒  其三','張九成','宋','宋诗','song-poetry','','[]','平生酷愛竹，日日到齋房。',48,'全唐诗/poet.song.103000.json','["平生酷愛竹，日日到齋房。", "高節霜松老，清陰璧月凉。", "朝來宿烟雨，夜半奏笙簧。", "隱几如有得，塵凡一笑忘。"]'),
('5501f95f-8cda-48f5-aafc-ffb86f22f211','夜雨','張九成','宋','宋诗','song-poetry','','[]','春陰正愁絕，夜雨復淋漓。',48,'全唐诗/poet.song.103000.json','["春陰正愁絕，夜雨復淋漓。", "楚客南冠日，湘纍去國時。", "千山花盡落，萬壑水東之。", "脈脈燈前意，夫君知不知。"]'),
('bbebef89-0a0e-4071-bea3-eaa921a26eed','次單推韻  其一','張九成','宋','宋诗','song-poetry','','[]','執別動經歲，年光挽莫留。',48,'全唐诗/poet.song.103000.json','["執別動經歲，年光挽莫留。", "壯心今已老，雅志自無求。", "白日將詩遣，生涯著醉酬。", "頹然烟瘴裏，一飽更何憂。"]'),
('4913eb80-9ad1-4bae-b3f6-97c7cce92d82','次單推韻  其二','張九成','宋','宋诗','song-poetry','','[]','庾嶺三江外，相過車馬勤。',48,'全唐诗/poet.song.103000.json','["庾嶺三江外，相過車馬勤。", "孤吟清廟瑟，愁思楚江雲。", "寂寞林逋宅，凄凉伍相墳。", "何時定歸去，摸索斷碑文。"]'),
('e376ebf8-0aba-486b-aa34-e1011887ced7','次單推韻  其三','張九成','宋','宋诗','song-poetry','','[]','每思鄉里秀，日日聽新除。',48,'全唐诗/poet.song.103000.json','["每思鄉里秀，日日聽新除。", "愁苦千行淚，清貧一束書。", "端谿元秀爽，梅蕊正蕭疏。", "公事多餘暇，簞瓢亦晏如。"]'),
('f349c256-352b-4f05-8394-2666594fb640','到白石寺次壁間鄭如圭韻','張九成','宋','宋诗','song-poetry','','[]','寺古僧多老，雲深水自流。',48,'全唐诗/poet.song.103000.json','["寺古僧多老，雲深水自流。", "鳥聲驚客夢，山色到江樓。", "落日千林迥，清風一逕幽。", "幽懷終未已，歸去輒回頭。"]'),
('89dd5f1d-aa7d-4131-ae81-43b02ee62c65','七月十二日出城','張九成','宋','宋诗','song-poetry','','[]','一水去縈繞，四山來周遭。',48,'全唐诗/poet.song.103000.json','["一水去縈繞，四山來周遭。", "夷猶聊適意，登降自忘勞。", "五嶺煙雲古，三江氣象豪。", "此邦真蕞爾，形勝助風騷。"]'),
('ade2474f-f319-4c99-8212-fd0fc0bad4fa','八月十四日偶成','張九成','宋','宋诗','song-poetry','','[]','物情猶惝恍，門戶更蕭然。',48,'全唐诗/poet.song.103000.json','["物情猶惝恍，門戶更蕭然。", "勿念客來往，何妨吾醉眠。", "北園肥菜甲，南浦鱠魚鮮。", "一酌餘妻子，此生休問天。"]'),
('6c5fdfad-2115-42ff-8174-bea16a28eb33','二月二十四日即事','張九成','宋','宋诗','song-poetry','','[]','春來尋勝事，此興亦何窮。',48,'全唐诗/poet.song.103000.json','["春來尋勝事，此興亦何窮。", "夜雨亂江淥，朝花褪日紅。", "雷聲驚嶺北，雲氣漲溪東。", "蓑笠衝泥去，誰知與我同。"]'),
('4ba7d738-51ec-465b-b028-007b8a2f72d5','三月十一日不出','張九成','宋','宋诗','song-poetry','','[]','老罷慵人事，柴門盡日扃。',48,'全唐诗/poet.song.103000.json','["老罷慵人事，柴門盡日扃。", "春江入幽想，夜雨漲前汀。", "何日當晴霽，西山雲眇冥。", "江頭無限好，見說柳深青。"]'),
('cf45d353-b7ca-4bb4-8460-f98a11a94afd','晚興','張九成','宋','宋诗','song-poetry','','[]','雨罷陰雲過，綠苔生滿齋。',48,'全唐诗/poet.song.103000.json','["雨罷陰雲過，綠苔生滿齋。", "清詩哦晚思，遠興動幽懷。", "自恨無與適，誰云寡所諧。", "茅檐有餘爽，點滴在空階。"]'),
('3f369403-7206-4cc5-8b58-c5c431af4896','即事','張九成','宋','宋诗','song-poetry','','[]','幽事晚山色，幽齋春雨餘。',48,'全唐诗/poet.song.103000.json','["幽事晚山色，幽齋春雨餘。", "亂紅欹澗水，浮綠漲郊墟。", "北牖迸新筍，西園生野蔬。", "槿籬繞茅屋，已分老樵漁。"]'),
('f0187607-dc94-4b7e-852b-d12db8909929','三月二十四日出城','張九成','宋','宋诗','song-poetry','','[]','數日雨不止，今晨晴已還。',48,'全唐诗/poet.song.103000.json','["數日雨不止，今晨晴已還。", "江頭看濁浪，窗外見青山。", "白鷺投前浦，輕舟漾遠灘。", "樽中有餘酒，一酌注頹顔。"]'),
('430fd6fd-0c85-496c-9acf-638457a0724c','喜晴','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今夕何清快，風光勝去年。',48,'全唐诗/poet.song.103000.json','["今夕何清快，風光勝去年。", "水南無宿靄，天末有孤烟。", "老矣休荷橐，歸歟掛錦韉。", "西湖多樂事，感慨舊山川。"]'),
('0194cce7-698e-489b-83ad-2d137d8417aa','悼王侍郎','張九成','宋','宋诗','song-poetry','','[]','氣鬰芝蘭秀，心虛水鏡明。',48,'全唐诗/poet.song.103000.json','["氣鬰芝蘭秀，心虛水鏡明。", "訏謨三代學，獻納萬人英。", "未遂平生志，空餘後世名。", "江湖添老淚，落日照銘旌。"]'),
('4983dd14-9bdb-442f-b661-4a9602623882','悼玉溪  其一','張九成','宋','宋诗','song-poetry','','[]','聞名四十載，茲地忽相逢。',48,'全唐诗/poet.song.103000.json','["聞名四十載，茲地忽相逢。", "每聽談前事，相看淚滿胸。", "干戈今偃息，詩酒曷從容。", "寂寞千秋恨，新阡植萬松。"]'),
('901a9ed2-d794-4661-ba06-017573128e88','悼玉溪  其二','張九成','宋','宋诗','song-poetry','','[]','長年聞老病，終日擁柴門。',48,'全唐诗/poet.song.103000.json','["長年聞老病，終日擁柴門。", "冷落田文飯，凄凉北海樽。", "功名看似夢，術業付諸孫。", "慷慨臨終語，精誠徹九閽。"]'),
('600e03aa-bac8-4fca-aa53-c4f7b43fdfcc','夏日即事','張九成','宋','宋诗','song-poetry','','[]','拂袖歸來好，親朋語笑真。',120,'全唐诗/poet.song.103000.json','["拂袖歸來好，親朋語笑真。", "山高多爽氣，溪迥只清淪。", "簾幕深無暑，琴樽靜照人。", "短衫吳縠細，團扇越羅新。", "翠竹書千卷，滄波釣一輪。", "身閒人自遠，心凈世無塵。", "月出千峰外，風生萬壑濱。", "庾公樓上興，曾點舞雩春。", "高論傾今古，長歌動鬼神。", "勳名吾已判，朝市任紛綸。"]'),
('3cda4804-479a-4efa-b833-2e6e0013b90b','雨晴到江上','張九成','宋','宋诗','song-poetry','','[]','今朝山色好，不似未晴時。',72,'全唐诗/poet.song.103000.json','["今朝山色好，不似未晴時。", "路轉沙汀出，橋回櫸柳移。", "羣山來衮衮，積水去披披。", "雲葉多奇態，蘋花弄晚姿。", "人家機杼急，野寺鼓鐘遲。", "欲去不得去，冥搜足此詩。"]'),
('cbfad4ab-e739-475c-944a-0383faefb2bc','山蟬','張九成','宋','宋诗','song-poetry','','[]','浴罷風來玉宇凉，山蟬吟詠送斜陽。',64,'全唐诗/poet.song.103000.json','["浴罷風來玉宇凉，山蟬吟詠送斜陽。", "長繅獨繭來還去，九折升車短更長。", "窈眇笙簫雲漢冷，凄清風露月華香。", "看君定是神仙侶，且擇高枝深處藏。"]'),
('cdced6e6-78c5-40cc-8421-d9d9725aeb6e','惠聲伯窗前孤桐','張九成','宋','宋诗','song-poetry','','[]','只期翠影在窗櫳，豈謂年餘到碧空。',64,'全唐诗/poet.song.103000.json','["只期翠影在窗櫳，豈謂年餘到碧空。", "自笑襟期惟我似，飽諳霜雪與君同。", "千巖夜月雙溪外，一曲晚天橫笛中。", "且向幽齋伴清致，會看廊廟奏薰風。"]'),
('4f30a512-8c23-4268-b183-1ab5c40abc35','聞沈元用帥南海喜而有作','張九成','宋','宋诗','song-poetry','','[]','與公相別五經年，憂患流離理固然。',64,'全唐诗/poet.song.103000.json','["與公相別五經年，憂患流離理固然。", "悵望故園江渚外，還驚橫浦瘴烟邊。", "喜聞金節專南海，行看鋒車上九天。", "顧我不才仍老矣，只思歸棹五湖船。"]'),
('52d9c2cd-78c6-4fa4-8b7f-b49b292b5fbd','寄故人施彥執','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百念都忘萬事休，一觴一詠自賡酬。',64,'全唐诗/poet.song.103000.json','["百念都忘萬事休，一觴一詠自賡酬。", "坐看庾嶺當南斷，又送橫江轉北流。", "已覺摧頹侵兩鬢，更無術畫補前旒。", "何時把醆西湖上，笑數浮生歲幾周。"]'),
('63d41a69-432f-4d41-9d2f-36a9cbe157d7','次施彥執韻','張九成','宋','宋诗','song-poetry','','[]','新詩宛見故人面，思入江山氣象雄。',64,'全唐诗/poet.song.103000.json','["新詩宛見故人面，思入江山氣象雄。", "幾歲不堪青草瘴，今朝還喜鯉魚風。", "高秋木落雁爲伴，久雨江深吾欲東。", "他日樽前如把臂，莫驚我已白頭翁。"]'),
('6b3727f4-1db7-4052-b198-38097f64a53d','見菊花呈諸名勝','張九成','宋','宋诗','song-poetry','','[]','勿謂重陽把一枝，嗟予何限古人思。',64,'全唐诗/poet.song.103000.json','["勿謂重陽把一枝，嗟予何限古人思。", "靈均自著離騷日，元亮長歌歸去時。", "未曉只疑猶泫露，開門忽見滿疏籬。", "要呼四海平生友，來醉花前金屈巵。"]'),
('e3cdf3ea-ade0-4047-850d-e05c2651b01e','再用前韻  其一','張九成','宋','宋诗','song-poetry','','[]','野澗江灣三兩枝，一時清絕破愁思。',64,'全唐诗/poet.song.103000.json','["野澗江灣三兩枝，一時清絕破愁思。", "纖纖弄蕊霜秋裏，滴滴開花葉落時。", "借問哦詩記幽夢，何如把酒對東籬。", "不然採向林逋廟，并與寒泉薦一巵。"]'),
('8c54816d-7440-4219-a5bf-22227968e498','再用前韻  其二','張九成','宋','宋诗','song-poetry','','[]','憑誰爲斲鳳凰枝，欲寄朱絃寫我思。',64,'全唐诗/poet.song.103000.json','["憑誰爲斲鳳凰枝，欲寄朱絃寫我思。", "著葉浪同烟雨裏，開花獨向晚霜時。", "羞隨燕麥爭春色，故伴喬松棲敗籬。", "喚取老嵇揮數弄，不辭滿引帳前巵。"]'),
('d8f44ed3-8c83-4dfc-a004-0eb8d9dbb37c','倅車送海棠','張九成','宋','宋诗','song-poetry','','[]','瘴雨蠻煙西復東，海棠嶺下占春風。',64,'全唐诗/poet.song.103000.json','["瘴雨蠻煙西復東，海棠嶺下占春風。", "清肌本自同梅潔，暈臉應知是酒紅。", "澹著燕脂春未透，半勻胡粉日初烘。", "此花不與凡花並，桃李休矜造化工。"]'),
('d11b5388-1f57-44b5-8014-48a93ed010e0','客有談嘉祐間事者一客瞪目不應及聞介甫新事則心目開明殊可怪也聊作詩以紀之','張九成','宋','宋诗','song-poetry','','[]','吾道何衰只愴神，六經文字變儀秦。',64,'全唐诗/poet.song.103000.json','["吾道何衰只愴神，六經文字變儀秦。", "魏侯酷喜聽新樂，中尉生來好殺人。", "海鳥錯將金奏眩，葉公元愛畫龍真。", "不逢伯樂休驤首，忽遇長沮莫問津。"]'),
('cdef1d47-523b-4bab-8e63-1e5656619fbf','次單推韻','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','七載離家夢亦驚，春來又是聽倉庚。',64,'全唐诗/poet.song.103000.json','["七載離家夢亦驚，春來又是聽倉庚。", "熟諳世味心如水，忽見吾人眼尚明。", "青鏡不堪看白髮，長鑱何處覓黄精。", "只思歸去西湖上，飽喫東坡玉糝羹。"]'),
('bdcdadce-bb9d-489f-ad42-d38df1b01960','柑花','張九成','宋','宋诗','song-poetry','','[]','羣芳落盡只青青，獨有柑花照眼明。',64,'全唐诗/poet.song.103000.json','["羣芳落盡只青青，獨有柑花照眼明。", "已許江梅來結友，未容巖桂擅清名。", "芬芬蘭麝三春底，濯濯冰霜一座傾。", "更待秋風資爽氣，垂黄籬落伴金橙。"]'),
('e74a7c3b-4b42-4ce9-9a20-99247b9e01ca','詠梅  其一','張九成','宋','宋诗','song-poetry','','[]','策馬尋梅過小橋，江邊驛路正迢迢。',64,'全唐诗/poet.song.103000.json','["策馬尋梅過小橋，江邊驛路正迢迢。", "靈均清勁餘騷雅，夷甫風姿墮寂寥。", "半吐暗驚雲插月，橫枝忽見雪封條。", "徘徊未忍輕歸去，樓上何人調玉簫。"]'),
('c95fc229-0f51-40ce-ab33-1eec1ac5f26d','詠梅  其二','張九成','宋','宋诗','song-poetry','','[]','已知節物向春榮，籬下溪邊照眼明。',64,'全唐诗/poet.song.103000.json','["已知節物向春榮，籬下溪邊照眼明。", "夜雪壓枝生冷艷，曉寒入骨耿飛英。", "長條直上姿尤媚，斜朵橫來思更清。", "疑是玉皇傳詔急，羣妃委佩赴仙京。"]'),
('fa6c6a91-ffa0-49bd-a6ef-39e14d478352','松棚','張九成','宋','宋诗','song-poetry','','[]','炎炎暑氣若爲當，旋買松枝庇草堂。',64,'全唐诗/poet.song.103000.json','["炎炎暑氣若爲當，旋買松枝庇草堂。", "一望翠陰何爽快，暫來吾室變清凉。", "直疑仙去冰壺裏，豈是生居汾水陽。", "向晚薰風香入座，爲君一再奏文王。"]'),
('cf463fd8-6d3d-49e3-a66c-aa189a32ae5b','題大庾新樓呈鄭仲遠年契','張九成','宋','宋诗','song-poetry','','[]','憶昔衡門不勝愁，忽驚甍棟半空浮。',64,'全唐诗/poet.song.103000.json','["憶昔衡門不勝愁，忽驚甍棟半空浮。", "朝披爽氣山圍坐，夜發清吟月滿樓。", "公事早休簾迥晝，圜扉常靜草連溝。", "已聞名姓傳天上，行看騎鯨隘九州。"]'),
('5e82a3fc-7902-4cef-8081-ae1999e21b3f','十二月初七日述懷','張九成','宋','宋诗','song-poetry','','[]','謫居寂寞歲將闌，几案凝塵酒盞乾。',64,'全唐诗/poet.song.103000.json','["謫居寂寞歲將闌，几案凝塵酒盞乾。", "落落雨聲檐外過，愔愔雪意座中寒。", "孤飛隻影人誰念，萬里長途心自安。", "世事悠悠君莫問，雪芽初碾試嘗看。"]'),
('775fef51-2a1f-448d-8e0c-ae107b506564','十一日詠梅','張九成','宋','宋诗','song-poetry','','[]','一年勝事又相親，數樹寒香巧鬬新。',64,'全唐诗/poet.song.103000.json','["一年勝事又相親，數樹寒香巧鬬新。", "擁鼻獨來江上晚，行吟忽見渡頭春。", "孤標不入千花伴，冷艷初無一點塵。", "翻笑淵明太多可，千秋作好菊花人。"]'),
('6ddc6225-54b4-4b0c-8325-5f82145da54f','六月十四日觀雲有作','張九成','宋','宋诗','song-poetry','','[]','深深蕭寺足幽居，寢飯行藏亦自如。',64,'全唐诗/poet.song.103000.json','["深深蕭寺足幽居，寢飯行藏亦自如。", "仰識白雲天外意，俯看青史古人書。", "摩挲方寸生無愧，周覽山川氣有餘。", "不用棹舟江海去，清風明月是吾廬。"]'),
('6b51f896-b658-4cec-a6f4-007a72c4f267','悼呂居仁舍人','張九成','宋','宋诗','song-poetry','','[]','精識高標不世才，泉臺一掩悵難回。',64,'全唐诗/poet.song.103000.json','["精識高標不世才，泉臺一掩悵難回。", "詞源斷是詩書力，句法端從踐履來。", "西掖北門聊爾耳，春風秋月亦悠哉。", "問君身後遺何物，只有窗間水一杯。"]'),
('5c919aca-4884-4f7c-8435-8858a5e27e17','某還故里過括蒼謝景思少卿示及諸公和詩次韻爲謝','張九成','宋','宋诗','song-poetry','','[]','朝隨落月東郊去，暮逐歸雲北浦還。',64,'全唐诗/poet.song.103000.json','["朝隨落月東郊去，暮逐歸雲北浦還。", "豈但勞農勤稼穡，要知爲郡足清閒。", "家傳詩句東山謝，學到精微陋巷顔。", "今日倚欄聊解带，欲看烟雨四邊山。"]'),
('3876767b-ff49-4968-82a2-a564cfa90c06','前日偕長文赴大庾飯坐中見黄菊盛開故有前作新詩既三復矣最後乃云黄菊尚未之見間有一二株白菊耳且有閒傍短籬尋嫩蕊忽驚孤蝶繞幽籬之句黄花豈得無語輒發一笑','張九成','宋','宋诗','song-poetry','','[]','曾向華筵折數枝，不知心正阿誰思。',64,'全唐诗/poet.song.103000.json','["曾向華筵折數枝，不知心正阿誰思。", "却憐弄玉吹簫伴，忘了小橋同醉時。", "和淚盈盈凄曉露，含情脈脈怨東籬。", "孫郎風味年來減，且對西風罰滿巵。"]'),
('560ae4ef-0926-4b46-b5ca-3c89aaf4c1af','夜起','張九成','宋','宋诗','song-poetry','','[]','昔日嘗驚墮俗塵，今朝始覺是閒人。',32,'全唐诗/poet.song.103000.json','["昔日嘗驚墮俗塵，今朝始覺是閒人。", "夜窗睡起無人見，萬里青天月一輪。"]'),
('fd4a52d3-4e7d-4aeb-8cb0-0b8912d46ac4','出城','張九成','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不出柴門近兩旬，江邊柳眼已窺人。',32,'全唐诗/poet.song.103000.json','["不出柴門近兩旬，江邊柳眼已窺人。", "却思歸去西湖上，剩把長條醉幾春。"]'),
('0d851c61-67c4-4df8-b09a-2aae9f79be9a','元夕','張九成','宋','宋诗','song-poetry','','[]','前年元夕宴譙門，萬朵紅燈鬧早春。',32,'全唐诗/poet.song.103000.json','["前年元夕宴譙門，萬朵紅燈鬧早春。", "誰謂今宵頓寥落，長天獨擁一冰輪。"]'),
('51d0cafc-04bc-427f-b8ae-af159cc9f3e9','午睡','張九成','宋','宋诗','song-poetry','','[]','深杏小桃暄午晝，遊絲飛絮攪長空。',32,'全唐诗/poet.song.103000.json','["深杏小桃暄午晝，遊絲飛絮攪長空。", "覺來一枕軒窗靜，燕子雙雙西又東。"]'),
('55f5f5c5-4a35-4363-913c-6ec24c25d925','丙寅正月','張九成','宋','宋诗','song-poetry','','[]','常年正月未全春，春色今年輒去人。',32,'全唐诗/poet.song.103000.json','["常年正月未全春，春色今年輒去人。", "試上小樓南北望，紅英滿地綠粼粼。"]'),
('5d8749f6-345a-4be8-8364-5b6c1164906f','嶺下桃花作澹紅色絕可愛因作絕句','張九成','宋','宋诗','song-poetry','','[]','江北桃花色頗穠，不堪凡陋也春風。',32,'全唐诗/poet.song.103000.json','["江北桃花色頗穠，不堪凡陋也春風。", "誰知嶺下新來樣，故作宮粧澹水紅。"]'),
('153f4ddc-4695-4616-8a79-f8c3a62c2048','憶北軒菊','張九成','宋','宋诗','song-poetry','','[]','長憶故園秋色好，滿籬霜菊炫宮黄。',32,'全唐诗/poet.song.103000.json','["長憶故園秋色好，滿籬霜菊炫宮黄。", "無聊却向橫江畔，笑倚西風覓暗香。"]'),
('80b3471b-60a2-4019-ac99-204dabf9b7a5','憶天竺桂','張九成','宋','宋诗','song-poetry','','[]','湖上北山天竺寺，滿山桂子月中秋。',32,'全唐诗/poet.song.103000.json','["湖上北山天竺寺，滿山桂子月中秋。", "黄英六出非凡種，肯許天香過別州。"]'),
('d058ad2d-4410-4ee5-a8bb-ad3bcd55d827','酴醾  其一','張九成','宋','宋诗','song-poetry','','[]','蜀錦年來可作衣，西園春色故芳菲。',32,'全唐诗/poet.song.103000.json','["蜀錦年來可作衣，西園春色故芳菲。", "天工成此新翻樣，翡翠機中玉唾飛。"]'),
('75a6baa7-92c8-4bef-a7ed-160c37442747','酴醾  其二','張九成','宋','宋诗','song-poetry','','[]','昨夜姮娥到萬山，更携青女散山間。',32,'全唐诗/poet.song.103000.json','["昨夜姮娥到萬山，更携青女散山間。", "天明欲去歸不得，化作此花來破顔。"]'),
('e09c6413-e1dc-4a8b-bb12-67381b0b6b37','三月五日','張九成','宋','宋诗','song-poetry','','[]','陰陰簾幕作輕寒，蔌蔌花飛已滿欄。',32,'全唐诗/poet.song.103000.json','["陰陰簾幕作輕寒，蔌蔌花飛已滿欄。", "困思不忺嘗美酒，却憐山色倚欄看。"]'),
('bb21441b-6959-42e5-a26f-6bacfb40a735','出城','張九成','宋','宋诗','song-poetry','','[]','凌晨江畔倚筇行，正見橫雲冉冉生。',32,'全唐诗/poet.song.103000.json','["凌晨江畔倚筇行，正見橫雲冉冉生。", "失却前山尋不得，雙尖微向日邊明。"]'),
('ad9a22c7-1cdd-4804-9d64-ab5983d0faf3','元宵','張九成','宋','宋诗','song-poetry','','[]','萬疊燈山輥繡毬，怕寒騎馬著駝裘。',32,'全唐诗/poet.song.103000.json','["萬疊燈山輥繡毬，怕寒騎馬著駝裘。", "要看十里紅蓮滿，須上譙門最上頭。"]'),
('b546cde0-c426-41d9-aa4e-23ffce6f8ba2','夏日即事  其一','張九成','宋','宋诗','song-poetry','','[]','寂寂柴門可設羅，唯餘柳色許相過。',32,'全唐诗/poet.song.103000.json','["寂寂柴門可設羅，唯餘柳色許相過。", "重簾半卷鳥聲樂，閒看爐烟篆髻螺。"]'),
('f2a571d4-d2dd-4951-8505-5c8bd661a9c6','夏日即事  其二','張九成','宋','宋诗','song-poetry','','[]','心瑩是非都不入，神清魂夢亦無多。',32,'全唐诗/poet.song.103000.json','["心瑩是非都不入，神清魂夢亦無多。", "年來借問生何似，梅雨寒塘颭露荷。"]'),
('f6b0b568-c9e4-4096-9d12-d7879335d122','夏日即事  其三','張九成','宋','宋诗','song-poetry','','[]','萱草榴花照眼明，冰廳水閣晚風清。',32,'全唐诗/poet.song.103000.json','["萱草榴花照眼明，冰廳水閣晚風清。", "蕭然終日無人到，簾外時聞下子聲。"]'),
('cdf16a8d-e977-4d0a-b698-c4f11051fe47','清暑','張九成','宋','宋诗','song-poetry','','[]','碧紗燈照素屏風，滿院凉生秋意濃。',32,'全唐诗/poet.song.103000.json','["碧紗燈照素屏風，滿院凉生秋意濃。", "誰信人間五六月，清寒如在玉壺中。"]'),
('7ee56a13-5baa-4ba6-9401-dec4495ac984','雨中海棠','張九成','宋','宋诗','song-poetry','','[]','玉脆紅輕不耐寒，無端風雨苦相干。',32,'全唐诗/poet.song.103000.json','["玉脆紅輕不耐寒，無端風雨苦相干。", "曉來試卷珠簾看，蔌蔌飛香滿畫欄。"]'),
('be469bd4-2f17-4345-8495-c19364423593','三月六日出城','張九成','宋','宋诗','song-poetry','','[]','春來多病懶尋山，送客今朝漫出關。',32,'全唐诗/poet.song.103000.json','["春來多病懶尋山，送客今朝漫出關。", "楊柳江頭無限思，欲携樽酒煖衰顔。"]'),
('0b4f6beb-9e7d-4a04-a0fd-5cc4846655db','喜晴','張九成','宋','宋诗','song-poetry','','[]','數日陰霖氣不舒，江流作漲吾其魚。',32,'全唐诗/poet.song.103000.json','["數日陰霖氣不舒，江流作漲吾其魚。", "晚來風起雲頭散，夜半星辰滿太虛。"]'),
('f3cf10e5-d304-4d38-b719-e87892900de1','夏日即事  其一','張九成','宋','宋诗','song-poetry','','[]','陰陰庭院靜無聲，只有黄鸝繞樹鳴。',32,'全唐诗/poet.song.103000.json','["陰陰庭院靜無聲，只有黄鸝繞樹鳴。", "午睡覺來何所見，玉爐風細碧烟橫。"]'),
('4623277c-e1f6-432c-8a04-fd3c51a62764','夏日即事  其二','張九成','宋','宋诗','song-poetry','','[]','日長廊迥思悠悠，自視真如不繫舟。',32,'全唐诗/poet.song.103000.json','["日長廊迥思悠悠，自視真如不繫舟。", "欲趁好風河漢去，玉樓銀闕剩遨遊。"]');
